/// App-level composition errors.
#[derive(Debug, Error)]
pub enum AppCompositionError {
    /// Workspace operation failed.
    #[error(transparent)]
    Workspace(#[from] WorkspaceError),
    /// Editor operation failed.
    #[error(transparent)]
    Editor(#[from] EditorError),
    /// Protocol-port operation failed.
    #[error("protocol error: {0:?}")]
    Protocol(ProtocolError),
    /// No active workspace.
    #[error("workspace is not open")]
    WorkspaceNotOpen,
    /// No active file in composition.
    #[error("active file is not selected")]
    ActiveFileMissing,
    /// Active buffer not initialized for selected file.
    #[error("active buffer is not open")]
    ActiveBufferMissing,
    /// UI command targeted a buffer other than the active application buffer.
    #[error("command targeted buffer {target:?}, but active buffer is {active:?}")]
    BufferMismatch {
        /// Targeted buffer id.
        target: BufferId,
        /// Active buffer id.
        active: Option<BufferId>,
    },
    /// UI command targeted a buffer that is not open in the app tab set.
    #[error("buffer {0:?} is not open")]
    BufferNotOpen(BufferId),
    /// Dirty-close cancellation targeted a buffer with no active dirty-close prompt.
    #[error("dirty-close prompt is not active for buffer {0:?}")]
    DirtyClosePromptMissing(BufferId),
    /// UI proposal intent targeted a proposal other than the app-owned proposal being routed.
    #[error("proposal intent targeted {target:?}, but routed proposal is {active:?}")]
    ProposalIntentMismatch {
        /// Targeted proposal id.
        target: ProposalId,
        /// App-owned proposal id available for routing.
        active: Option<ProposalId>,
    },
    /// UI proposal intent requires an app-owned proposal object for routing.
    #[error("proposal intent requires an app-owned proposal")]
    ProposalIntentMissingProposal,
    /// Proposal-mediated save did not apply.
    #[error("save proposal did not apply: {0:?}")]
    SaveProposalRejected(Box<ProposalResponse>),
    /// Phase 4 AI runtime refused or failed a metadata-only step.
    #[error("phase 4 AI runtime failed: {0}")]
    AiRuntime(String),
    /// Requested Phase 4 AI run does not exist.
    #[error("phase 4 AI run not found: {run_id}")]
    AiRunMissing {
        /// Missing run identifier.
        run_id: String,
    },
    /// Collaboration runtime or app gate rejected a request.
    #[error("collaboration request failed: {0}")]
    Collaboration(String),
    /// Remote runtime or app gate rejected a request.
    #[error("remote request failed: {0}")]
    Remote(String),
    /// Language tooling workflow failed.
    #[error("language tooling request failed: {0}")]
    LanguageTooling(String),
    /// Terminal workflow failed.
    #[error("terminal request failed: {0}")]
    Terminal(String),
    /// Debug workflow failed.
    #[error("debug request failed: {0}")]
    Debug(String),
    /// Legion workflow orchestration failed at the app authority boundary.
    #[error("legion workflow request failed: {0}")]
    LegionWorkflow(String),
    /// Search query validation failed.
    #[error("search validation failed: {0}")]
    SearchValidation(String),
}

/// Product-mode authority for app-owned AI dispatch.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum AppProductMode {
    /// Deterministic local/manual mode; AI dispatch is rejected.
    Manual,
    /// Inline assist and assisted proposal/explain dispatch are enabled.
    Assist,
    /// Delegated task mode; includes Assist-level dispatch.
    Delegate,
    /// Automation mode; includes Assist-level dispatch.
    Automate,
}

impl AppProductMode {
    fn allows_assist(self) -> bool {
        self.to_product_mode()
            .allows_runtime_surface(legion_protocol::ProductRuntimeSurface::AssistedAi)
    }

    fn allows_delegate(self) -> bool {
        self.to_product_mode()
            .allows_runtime_surface(legion_protocol::ProductRuntimeSurface::DelegatedTask)
    }

    fn allows_automate(self) -> bool {
        self.to_product_mode()
            .allows_runtime_surface(legion_protocol::ProductRuntimeSurface::Automation)
    }

    /// Convert the app authority enum into the shared protocol product mode.
    pub fn to_product_mode(self) -> legion_protocol::ProductMode {
        match self {
            Self::Manual => legion_protocol::ProductMode::Manual,
            Self::Assist => legion_protocol::ProductMode::Assist,
            Self::Delegate => legion_protocol::ProductMode::Delegates,
            Self::Automate => legion_protocol::ProductMode::Automate,
        }
    }

    /// Convert a UI dock/product mode into the app authority enum.
    pub fn from_dock_mode(mode: DockMode) -> Self {
        match mode {
            DockMode::Manual => Self::Manual,
            DockMode::Assist => Self::Assist,
            DockMode::Delegate => Self::Delegate,
            DockMode::Automate => Self::Automate,
        }
    }

    /// Convert the app authority enum into a UI dock/product mode.
    pub fn to_dock_mode(self) -> DockMode {
        match self {
            Self::Manual => DockMode::Manual,
            Self::Assist => DockMode::Assist,
            Self::Delegate => DockMode::Delegate,
            Self::Automate => DockMode::Automate,
        }
    }
}

#[cfg(test)]
mod daily_editing_save_all_internal_tests {
    use super::*;

    #[test]
    fn daily_editing_save_all_missing_metadata_records_buffer_error() {
        let mut app = AppComposition::new();
        let orphaned_buffer = BufferId(9001);
        app.active_documents.open_tabs.push(orphaned_buffer);

        let outcome = app.save_all().expect("save-all records metadata error");
        assert_eq!(outcome.status, AppSaveAllStatus::Rejected);
        assert_eq!(outcome.saved_count, 0);
        assert_eq!(outcome.rejected_count, 1);
        assert_eq!(outcome.results.len(), 1);

        let item = &outcome.results[0];
        assert_eq!(item.buffer_id, orphaned_buffer);
        assert_eq!(item.status, AppSaveAllItemStatus::MetadataMissing);
        assert!(item.outcome.is_none());
        assert!(item.final_dirty);
        let metadata = item
            .rejection_metadata
            .as_ref()
            .expect("metadata failure summary");
        assert_eq!(metadata.response_kind, "MetadataMissing");
        assert_eq!(metadata.diagnostic_codes, vec!["save_all.metadata_missing"]);
    }

    #[test]
    fn excerpt_surface_projection_carries_source_buffer_anchors() {
        let mut app = AppComposition::new();

        let buffer_a = app
            .editor
            .open_buffer(
                WorkspaceId(7),
                FileId(11),
                "src/alpha.rs",
                "alpha\nfn alpha() {}\n",
            )
            .expect("open first buffer");
        let opened_a = OpenedFileText {
            identity: FileIdentity {
                file_id: FileId(11),
                workspace_id: WorkspaceId(7),
                canonical_path: CanonicalPath("src/alpha.rs".to_string()),
                content_version: FileContentVersion(1),
                content_hash: Some("hash-alpha".to_string()),
            },
            text: "alpha\nfn alpha() {}\n".to_string(),
            fingerprint: FileFingerprint {
                algorithm: "test".to_string(),
                value: "alpha".to_string(),
            },
            file_content_version: FileContentVersion(1),
            workspace_generation: WorkspaceGeneration(1),
            modified_at: None,
            file_length: Some(21),
            is_new_file: false,
        };
        app.active_documents.bind_opened_file(&opened_a, buffer_a);

        let buffer_b = app
            .editor
            .open_buffer(
                WorkspaceId(7),
                FileId(12),
                "src/beta.rs",
                "beta\nfn beta() {}\n",
            )
            .expect("open second buffer");
        let opened_b = OpenedFileText {
            identity: FileIdentity {
                file_id: FileId(12),
                workspace_id: WorkspaceId(7),
                canonical_path: CanonicalPath("src/beta.rs".to_string()),
                content_version: FileContentVersion(1),
                content_hash: Some("hash-beta".to_string()),
            },
            text: "beta\nfn beta() {}\n".to_string(),
            fingerprint: FileFingerprint {
                algorithm: "test".to_string(),
                value: "beta".to_string(),
            },
            file_content_version: FileContentVersion(1),
            workspace_generation: WorkspaceGeneration(1),
            modified_at: None,
            file_length: Some(18),
            is_new_file: false,
        };
        app.active_documents.bind_opened_file(&opened_b, buffer_b);

        let surface =
            ProjectionBuilder::excerpt_surface_projection(&app.active_documents, &app.editor);

        assert_eq!(surface.active_excerpt_id.as_deref(), Some("buffer:2"));
        assert_eq!(surface.sections.len(), 2);

        let first = &surface.sections[0];
        assert_eq!(first.excerpt_id, "buffer:1");
        assert_eq!(first.buffer_id, Some(buffer_a));
        assert_eq!(
            first.file_path.as_ref().map(|path| path.0.as_str()),
            Some("src/alpha.rs")
        );
        assert!(!first.dirty);
        assert!(!first.lines.is_empty());
        assert_eq!(first.lines[0].visible_text, "alpha");
        assert_eq!(first.lines[0].range.start.line, 0);

        let second = &surface.sections[1];
        assert_eq!(second.excerpt_id, "buffer:2");
        assert_eq!(second.buffer_id, Some(buffer_b));
        assert_eq!(
            second.file_path.as_ref().map(|path| path.0.as_str()),
            Some("src/beta.rs")
        );
        assert!(!second.dirty);
        assert!(!second.lines.is_empty());
    }
    #[test]
    fn terminal_shell_output_parser_strips_markers_and_extracts_metadata() {
        let parsed = legion_terminal::osc::parse_terminal_shell_output(
            "\x1b]7;file://localhost/tmp/workspace\x1b\\output\x1b]133;D;7\x1b\\",
        );

        assert_eq!(parsed.visible_output, "output");
        assert_eq!(parsed.cwd.as_deref(), Some("/tmp/workspace"));
        assert_eq!(parsed.exit_code, Some(7));
    }
}

