fn language_quick_fixes_for_problems(
    problems: &[LanguageProblemProjection],
) -> Vec<LanguageQuickFixProjection> {
    problems
        .iter()
        .take(50)
        .enumerate()
        .map(|(index, problem)| {
            let code_label = problem
                .code_label
                .clone()
                .unwrap_or_else(|| "diagnostic".to_string());
            LanguageQuickFixProjection {
                action_id: language_quick_fix_action_id(index, problem),
                title: format!(
                    "Prepare code action for {}",
                    bounded_label(code_label.clone(), 64)
                ),
                kind_label: "quickfix.diagnostic".to_string(),
                problem_code_label: problem.code_label.clone(),
                problem_range: problem.range,
                severity: problem.severity,
                source_label: problem.source_label.clone(),
                proposal_id: None,
                redaction_hints: vec![RedactionHint::MetadataOnly],
                schema_version: 1,
            }
        })
        .collect()
}

fn language_quick_fix_action_id(index: usize, problem: &LanguageProblemProjection) -> String {
    let code = problem.code_label.as_deref().unwrap_or("diagnostic");
    let safe_code = sanitized_action_component(code, 64);
    let (line, character) = problem
        .range
        .map(|range| (range.start.line, range.start.character))
        .unwrap_or((0, 0));
    format!("quickfix:{safe_code}:{line}:{character}:{index}")
}

fn sanitized_action_component(value: &str, limit: usize) -> String {
    let sanitized = value
        .chars()
        .filter_map(|character| {
            if character.is_ascii_alphanumeric() || matches!(character, '.' | '_' | '-' | ':') {
                Some(character)
            } else if character.is_ascii_whitespace() {
                Some('-')
            } else {
                None
            }
        })
        .take(limit)
        .collect::<String>();
    if sanitized.is_empty() {
        "diagnostic".to_string()
    } else {
        sanitized
    }
}

fn language_breadcrumbs_for_outline(
    outline: &[LanguageOutlineSymbolProjection],
    position: TextCoordinate,
) -> Vec<LanguageBreadcrumbProjection> {
    language_scope_outline_rows(outline, position)
        .into_iter()
        .enumerate()
        .map(|(index, symbol)| LanguageBreadcrumbProjection {
            breadcrumb_id: format!("breadcrumb:{}", symbol.symbol_id),
            label: symbol.label.clone(),
            kind_label: symbol.kind_label.clone(),
            range: symbol.range,
            depth: index.min(u16::MAX as usize) as u16,
            source_label: "legion-index".to_string(),
            schema_version: 1,
        })
        .collect()
}

fn language_sticky_scopes_for_outline(
    outline: &[LanguageOutlineSymbolProjection],
    position: TextCoordinate,
) -> Vec<LanguageStickyScopeProjection> {
    let rows = language_scope_outline_rows(outline, position);
    let active_index = rows.len().saturating_sub(1);
    rows.into_iter()
        .enumerate()
        .map(|(index, symbol)| LanguageStickyScopeProjection {
            scope_id: format!("sticky:{}", symbol.symbol_id),
            label: symbol.label.clone(),
            kind_label: symbol.kind_label.clone(),
            range: symbol.range,
            depth: index.min(u16::MAX as usize) as u16,
            active: index == active_index,
            source_label: "legion-index".to_string(),
            schema_version: 1,
        })
        .collect()
}

fn language_inlay_hints_for_symbols(
    symbols: &[SymbolFileMapRecord],
) -> Vec<LanguageInlayHintProjection> {
    symbols
        .iter()
        .filter_map(|symbol| {
            let range = symbol.declaration_range?;
            Some(LanguageInlayHintProjection {
                hint_id: format!("inlay:{}:kind", symbol.symbol_id.0),
                label: format!(": {}", bounded_label(symbol.kind.clone(), 48)),
                kind_label: "symbol-kind".to_string(),
                position: range.end,
                range: Some(range),
                padding_left: true,
                padding_right: false,
                source_label: "legion-index".to_string(),
                schema_version: 1,
            })
        })
        .take(50)
        .collect()
}

fn language_code_lenses_for_symbols(
    symbols: &[SymbolFileMapRecord],
) -> Vec<LanguageCodeLensProjection> {
    symbols
        .iter()
        .take(50)
        .map(|symbol| {
            let reference_count = symbol.reference_ranges.len();
            let reference_label = if reference_count == 1 {
                "1 reference".to_string()
            } else {
                format!("{reference_count} references")
            };
            LanguageCodeLensProjection {
                lens_id: format!("codelens:{}:references", symbol.symbol_id.0),
                title: reference_label,
                command_label: "Find references".to_string(),
                kind_label: "references".to_string(),
                range: symbol.declaration_range,
                data_label: Some(format!("references={reference_count}")),
                source_label: "legion-index".to_string(),
                schema_version: 1,
            }
        })
        .collect()
}

fn language_scope_outline_rows(
    outline: &[LanguageOutlineSymbolProjection],
    position: TextCoordinate,
) -> Vec<&LanguageOutlineSymbolProjection> {
    let mut rows = outline
        .iter()
        .filter(|symbol| {
            symbol
                .range
                .is_some_and(|range| text_coordinate_at_or_before(range.start, position))
        })
        .collect::<Vec<_>>();
    rows.sort_by(|left, right| {
        outline_range_sort_key(left)
            .cmp(&outline_range_sort_key(right))
            .then_with(|| left.symbol_id.cmp(&right.symbol_id))
    });
    if rows.len() > 4 {
        rows.drain(0..rows.len() - 4);
    }
    rows
}

fn outline_range_sort_key(symbol: &LanguageOutlineSymbolProjection) -> (u32, u32, u64) {
    symbol
        .range
        .map(|range| text_coordinate_sort_key(range.start))
        .unwrap_or((u32::MAX, u32::MAX, u64::MAX))
}

fn text_coordinate_at_or_before(left: TextCoordinate, right: TextCoordinate) -> bool {
    match (left.byte_offset, right.byte_offset) {
        (Some(left_byte), Some(right_byte)) => left_byte <= right_byte,
        _ => (left.line, left.character) <= (right.line, right.character),
    }
}

fn text_coordinate_sort_key(coordinate: TextCoordinate) -> (u32, u32, u64) {
    (
        coordinate.line,
        coordinate.character,
        coordinate.byte_offset.unwrap_or(u64::MAX),
    )
}

fn text_coordinate_with_offsets(
    line: u32,
    character: u32,
    byte_offset: u64,
    utf16_offset: u64,
) -> TextCoordinate {
    TextCoordinate {
        line,
        character,
        byte_offset: Some(byte_offset),
        utf16_offset: Some(utf16_offset),
    }
}

fn text_end_coordinate(text: &str) -> TextCoordinate {
    let line = text.bytes().filter(|byte| *byte == b'\n').count() as u32;
    let character = text
        .rsplit_once('\n')
        .map_or(text.len(), |(_, tail)| tail.len()) as u32;
    TextCoordinate {
        line,
        character,
        byte_offset: Some(text.len() as u64),
        utf16_offset: Some(text.encode_utf16().count() as u64),
    }
}

fn text_coordinate_after_replacement(start: TextPosition, replacement: &str) -> TextCoordinate {
    let mut line = start.line;
    let mut column = start.column;
    for ch in replacement.chars() {
        if ch == '\n' {
            line += 1;
            column = 0;
        } else {
            column += ch.len_utf8();
        }
    }
    TextCoordinate {
        line: line as u32,
        character: column as u32,
        byte_offset: None,
        utf16_offset: None,
    }
}

fn byte_bounds_for_protocol_range(text: &str, range: ProtocolTextRange) -> Option<(usize, usize)> {
    let start = usize::try_from(range.start.byte_offset?).ok()?;
    let end = usize::try_from(range.end.byte_offset?).ok()?;
    if start > end
        || end > text.len()
        || !text.is_char_boundary(start)
        || !text.is_char_boundary(end)
    {
        return None;
    }
    Some((start, end))
}

fn selected_line_count(selected: &str) -> usize {
    if selected.is_empty() {
        0
    } else {
        selected.bytes().filter(|byte| *byte == b'\n').count() + 1
    }
}

fn identifier_byte_range_at(text: &str, requested_byte: u64) -> Option<ByteRange> {
    if text.is_empty() {
        return None;
    }

    let mut index = usize::try_from(requested_byte).unwrap_or(usize::MAX);
    index = index.min(text.len());
    while index > 0 && !text.is_char_boundary(index) {
        index -= 1;
    }
    let bytes = text.as_bytes();
    if index == bytes.len() && index > 0 {
        index -= 1;
    }
    if index < bytes.len()
        && !is_identifier_byte(bytes[index])
        && index > 0
        && is_identifier_byte(bytes[index - 1])
    {
        index -= 1;
    }
    if index >= bytes.len() || !is_identifier_byte(bytes[index]) {
        return None;
    }

    let mut start = index;
    while start > 0 && is_identifier_byte(bytes[start - 1]) {
        start -= 1;
    }
    let mut end = index + 1;
    while end < bytes.len() && is_identifier_byte(bytes[end]) {
        end += 1;
    }
    Some(ByteRange::new(start as u64, end as u64))
}

fn is_identifier_byte(byte: u8) -> bool {
    byte.is_ascii_alphanumeric() || byte == b'_'
}

struct Phase4ContextAssemblyService;

impl Phase4ContextAssemblyService {
    #[allow(clippy::too_many_arguments)]
    fn assemble_context_manifest(
        context: &ActiveSaveContext,
        run_id: &legion_protocol::AgentRunId,
        provider_route_id: &str,
        snapshot_id: legion_protocol::SnapshotId,
        buffer_version: legion_protocol::BufferVersion,
        snapshot_hash: FileFingerprint,
        byte_len: u64,
        line_count: u32,
        generated_at: TimestampMillis,
        instruction_manifest_items: Vec<legion_protocol::ContextManifestItem>,
    ) -> legion_protocol::ContextManifestProjection {
        let file_item = legion_protocol::ContextManifestItem {
            item_id: format!("phase4:{}:file", run_id.0),
            kind: legion_protocol::ContextManifestItemKind::File,
            inclusion: legion_protocol::ContextManifestInclusionState::Included,
            workspace_id: Some(context.workspace_id),
            file_id: Some(context.metadata.identity.file_id),
            buffer_id: Some(context.buffer_id),
            proposal_id: None,
            target_id: Some(context.metadata.identity.file_id.0.to_string()),
            path: Some(context.metadata.identity.canonical_path.clone()),
            ranges: Vec::new(),
            counts: context
                .metadata
                .file_length
                .map(|count| legion_protocol::ContextManifestItemCount {
                    label: "file_bytes".to_string(),
                    count: count.min(u32::MAX as u64) as u32,
                })
                .into_iter()
                .collect(),
            hashes: vec![context.metadata.fingerprint.clone()],
            privacy_scope: Some(legion_protocol::SemanticPrivacyScope::MetadataOnly),
            privacy_label: legion_protocol::ProposalPrivacyLabel::WorkspaceMetadata,
            risk_label: legion_protocol::ProposalRiskLabel::Low,
            egress: legion_protocol::ContextManifestEgressStatus::LocalOnly,
            freshness: Some(legion_protocol::ContextManifestFreshnessSummary {
                state: legion_protocol::SemanticFreshnessState::Fresh,
                freshness_key_present: true,
                snapshot_id: Some(snapshot_id),
                file_content_version: Some(context.metadata.file_content_version),
                workspace_generation: Some(context.metadata.workspace_generation),
                content_hash: Some(context.metadata.fingerprint.clone()),
                privacy_scope: Some(legion_protocol::SemanticPrivacyScope::MetadataOnly),
                observed_at: Some(generated_at),
                risk_label: legion_protocol::ProposalRiskLabel::Low,
                risk_reasons: Vec::new(),
                schema_version: 1,
            }),
            preconditions: None,
            labels: vec!["phase4.context.file_metadata".to_string()],
            redaction_hints: vec![legion_protocol::RedactionHint::MetadataOnly],
            schema_version: 1,
        };
        let buffer_item = legion_protocol::ContextManifestItem {
            item_id: format!("phase4:{}:buffer", run_id.0),
            kind: legion_protocol::ContextManifestItemKind::Buffer,
            inclusion: legion_protocol::ContextManifestInclusionState::Included,
            workspace_id: Some(context.workspace_id),
            file_id: Some(context.metadata.identity.file_id),
            buffer_id: Some(context.buffer_id),
            proposal_id: None,
            target_id: Some(context.buffer_id.0.to_string()),
            path: None,
            ranges: Vec::new(),
            counts: vec![
                legion_protocol::ContextManifestItemCount {
                    label: "snapshot_bytes".to_string(),
                    count: byte_len.min(u32::MAX as u64) as u32,
                },
                legion_protocol::ContextManifestItemCount {
                    label: "lines".to_string(),
                    count: line_count,
                },
            ],
            hashes: vec![snapshot_hash],
            privacy_scope: Some(legion_protocol::SemanticPrivacyScope::MetadataOnly),
            privacy_label: legion_protocol::ProposalPrivacyLabel::WorkspaceMetadata,
            risk_label: legion_protocol::ProposalRiskLabel::Low,
            egress: legion_protocol::ContextManifestEgressStatus::LocalOnly,
            freshness: Some(legion_protocol::ContextManifestFreshnessSummary {
                state: legion_protocol::SemanticFreshnessState::Fresh,
                freshness_key_present: true,
                snapshot_id: Some(snapshot_id),
                file_content_version: Some(context.metadata.file_content_version),
                workspace_generation: Some(context.metadata.workspace_generation),
                content_hash: None,
                privacy_scope: Some(legion_protocol::SemanticPrivacyScope::MetadataOnly),
                observed_at: Some(generated_at),
                risk_label: legion_protocol::ProposalRiskLabel::Low,
                risk_reasons: Vec::new(),
                schema_version: 1,
            }),
            preconditions: Some(legion_protocol::ContextManifestPreconditionSummary {
                file_content_version: Some(context.metadata.file_content_version),
                buffer_version: Some(buffer_version),
                snapshot_id: Some(snapshot_id),
                workspace_generation: Some(context.metadata.workspace_generation),
                expected_fingerprint: Some(context.metadata.fingerprint.clone()),
                expected_file_length: context.metadata.file_length,
                expected_modified_at: context.metadata.modified_at,
                core_preconditions_present: true,
                risk_label: legion_protocol::ProposalRiskLabel::Low,
                risk_reasons: Vec::new(),
                schema_version: 1,
            }),
            labels: vec!["phase4.context.buffer_descriptor".to_string()],
            redaction_hints: vec![legion_protocol::RedactionHint::MetadataOnly],
            schema_version: 1,
        };
        let route_item = Self::metadata_item(
            format!("phase4:{}:provider-route", run_id.0),
            legion_protocol::ContextManifestItemKind::ProviderRoute,
            context.workspace_id,
            provider_route_id,
            legion_protocol::ContextManifestEgressStatus::LocalProvider,
            vec!["phase4.provider.local_loopback".to_string()],
        );
        let agent_item = Self::metadata_item(
            format!("phase4:{}:agent-step", run_id.0),
            legion_protocol::ContextManifestItemKind::AgentStep,
            context.workspace_id,
            &run_id.0,
            legion_protocol::ContextManifestEgressStatus::LocalOnly,
            vec!["phase4.agent.proposal_only".to_string()],
        );
        let selection_item = Self::metadata_item(
            format!("phase4:{}:selection", run_id.0),
            legion_protocol::ContextManifestItemKind::UserSelection,
            context.workspace_id,
            "active-buffer",
            legion_protocol::ContextManifestEgressStatus::LocalOnly,
            vec!["phase4.selection.active_buffer".to_string()],
        );

        let permission = legion_protocol::ContextManifestPermissionSummary {
            kind: legion_protocol::ContextManifestPermissionKind::ModelProvider,
            capability: CapabilityId("ai.provider.invoke".to_string()),
            principal: Some(context.principal.clone()),
            decision_id: None,
            granted: false,
            privacy_scope: legion_protocol::SemanticPrivacyScope::MetadataOnly,
            egress: legion_protocol::ContextManifestEgressStatus::LocalProvider,
            risk_label: legion_protocol::ProposalRiskLabel::Low,
            redaction_hints: vec![legion_protocol::RedactionHint::MetadataOnly],
            schema_version: 1,
        };
        let manifest = legion_protocol::ContextManifestRecord {
            manifest_id: format!("phase4:manifest:{}", run_id.0),
            workspace_id: Some(context.workspace_id),
            proposal_id: None,
            purpose: legion_protocol::ContextManifestPurpose::ProviderRequest,
            workspace_trust_state: Some(context.trust.clone()),
            privacy_label: legion_protocol::ProposalPrivacyLabel::WorkspaceMetadata,
            risk_label: legion_protocol::ProposalRiskLabel::Low,
            egress: legion_protocol::ContextManifestEgressStatus::LocalProvider,
            items: vec![file_item, buffer_item]
                .into_iter()
                .chain(instruction_manifest_items)
                .chain(vec![selection_item, route_item, agent_item])
                .collect(),
            permissions: vec![permission],
            omitted_item_count: 0,
            stale_or_missing_metadata_risk_present: false,
            generated_at,
            redaction_hints: vec![legion_protocol::RedactionHint::MetadataOnly],
            schema_version: 1,
        };
        legion_protocol::ContextManifestProjection {
            manifest,
            selected_item_id: None,
            generated_at,
            redaction_hints: vec![legion_protocol::RedactionHint::MetadataOnly],
            schema_version: 1,
        }
    }

    fn metadata_item(
        item_id: String,
        kind: legion_protocol::ContextManifestItemKind,
        workspace_id: WorkspaceId,
        target_id: &str,
        egress: legion_protocol::ContextManifestEgressStatus,
        labels: Vec<String>,
    ) -> legion_protocol::ContextManifestItem {
        legion_protocol::ContextManifestItem {
            item_id,
            kind,
            inclusion: legion_protocol::ContextManifestInclusionState::Included,
            workspace_id: Some(workspace_id),
            file_id: None,
            buffer_id: None,
            proposal_id: None,
            target_id: Some(target_id.to_string()),
            path: None,
            ranges: Vec::new(),
            counts: Vec::new(),
            hashes: Vec::new(),
            privacy_scope: Some(legion_protocol::SemanticPrivacyScope::MetadataOnly),
            privacy_label: legion_protocol::ProposalPrivacyLabel::WorkspaceMetadata,
            risk_label: legion_protocol::ProposalRiskLabel::Low,
            egress,
            freshness: None,
            preconditions: None,
            labels,
            redaction_hints: vec![legion_protocol::RedactionHint::MetadataOnly],
            schema_version: 1,
        }
    }
}

#[derive(Debug, Clone)]
struct InstructionPrefixSource {
    source_label: String,
    scope_label: String,
    path: std::path::PathBuf,
    content: String,
}

#[derive(Debug, Clone)]
struct InstructionPrefixBundle {
    prompt_prefix: String,
    manifest_items: Vec<legion_protocol::ContextManifestItem>,
}

fn instruction_prefix_bundle(
    workspace_id: WorkspaceId,
    generated_at: TimestampMillis,
    workspace_root_path: Option<&std::path::Path>,
    home_dir: Option<&std::path::Path>,
) -> InstructionPrefixBundle {
    let mut sources = Vec::new();
    if let Some(workspace_root) = workspace_root_path {
        collect_instruction_scope_sources("workspace", workspace_root, &mut sources);
    }
    if let Some(home_dir) = home_dir {
        collect_instruction_scope_sources("user", home_dir, &mut sources);
    }
    sources.sort_by(|a, b| {
        scope_rank(&a.scope_label)
            .cmp(&scope_rank(&b.scope_label))
            .then(source_kind_rank(&a.source_label).cmp(&source_kind_rank(&b.source_label)))
            .then(a.path.cmp(&b.path))
            .then(a.source_label.cmp(&b.source_label))
    });
    sources.dedup_by(|a, b| a.path == b.path);

    let prompt_prefix = sources
        .iter()
        .map(render_instruction_source)
        .collect::<Vec<_>>()
        .join("\n\n");
    let manifest_items = sources
        .iter()
        .enumerate()
        .map(|(index, source)| {
            instruction_source_manifest_item(workspace_id, generated_at, index, source)
        })
        .collect();

    InstructionPrefixBundle {
        prompt_prefix,
        manifest_items,
    }
}

fn collect_instruction_scope_sources(
    scope_label: &str,
    root: &std::path::Path,
    sources: &mut Vec<InstructionPrefixSource>,
) {
    let agents_path = root.join("AGENTS.md");
    if let Some(source) = instruction_source_from_file(scope_label, "agents", agents_path) {
        sources.push(source);
    }
    let rules_dir = root.join(".legion/rules");
    collect_instruction_rule_sources(scope_label, &rules_dir, sources);
}

fn collect_instruction_rule_sources(
    scope_label: &str,
    rules_dir: &std::path::Path,
    sources: &mut Vec<InstructionPrefixSource>,
) {
    let Ok(entries) = std::fs::read_dir(rules_dir) else {
        return;
    };
    let mut entries = entries.filter_map(Result::ok).collect::<Vec<_>>();
    entries.sort_by_key(|entry| entry.path());
    for entry in entries {
        let path = entry.path();
        if path.is_dir() {
            collect_instruction_rule_sources(scope_label, &path, sources);
            continue;
        }
        if path.is_file()
            && let Some(source) = instruction_source_from_file(scope_label, "rules", path)
        {
            sources.push(source);
        }
    }
}

fn instruction_source_from_file(
    scope_label: &str,
    source_kind: &str,
    path: std::path::PathBuf,
) -> Option<InstructionPrefixSource> {
    let content = std::fs::read_to_string(&path).ok()?;
    Some(InstructionPrefixSource {
        source_label: format!("{scope_label}-{source_kind}"),
        scope_label: scope_label.to_string(),
        path,
        content,
    })
}

fn render_instruction_source(source: &InstructionPrefixSource) -> String {
    format!(
        "source={}\npath={}\n{}",
        source.source_label,
        source.path.display(),
        source.content
    )
}

fn instruction_source_manifest_item(
    workspace_id: WorkspaceId,
    generated_at: TimestampMillis,
    index: usize,
    source: &InstructionPrefixSource,
) -> legion_protocol::ContextManifestItem {
    let content_fingerprint = metadata_fingerprint(
        "instruction-source",
        &format!(
            "{}|{}|{}",
            source.source_label,
            source.path.display(),
            source.content
        ),
    );
    let byte_count = source.content.len().min(u32::MAX as usize) as u32;
    let line_count = source.content.lines().count().min(u32::MAX as usize) as u32;
    legion_protocol::ContextManifestItem {
        item_id: format!("phase4:instruction:{}:{}", index, content_fingerprint.value),
        kind: legion_protocol::ContextManifestItemKind::File,
        inclusion: legion_protocol::ContextManifestInclusionState::Included,
        workspace_id: Some(workspace_id),
        file_id: None,
        buffer_id: None,
        proposal_id: None,
        target_id: Some(source.path.display().to_string()),
        path: Some(CanonicalPath(source.path.display().to_string())),
        ranges: Vec::new(),
        counts: vec![
            legion_protocol::ContextManifestItemCount {
                label: "file_bytes".to_string(),
                count: byte_count,
            },
            legion_protocol::ContextManifestItemCount {
                label: "lines".to_string(),
                count: line_count,
            },
        ],
        hashes: vec![content_fingerprint.clone()],
        privacy_scope: Some(legion_protocol::SemanticPrivacyScope::MetadataOnly),
        privacy_label: legion_protocol::ProposalPrivacyLabel::WorkspaceMetadata,
        risk_label: legion_protocol::ProposalRiskLabel::Low,
        egress: legion_protocol::ContextManifestEgressStatus::LocalOnly,
        freshness: Some(legion_protocol::ContextManifestFreshnessSummary {
            state: legion_protocol::SemanticFreshnessState::Fresh,
            freshness_key_present: true,
            snapshot_id: None,
            file_content_version: None,
            workspace_generation: None,
            content_hash: Some(content_fingerprint.clone()),
            privacy_scope: Some(legion_protocol::SemanticPrivacyScope::MetadataOnly),
            observed_at: Some(generated_at),
            risk_label: legion_protocol::ProposalRiskLabel::Low,
            risk_reasons: Vec::new(),
            schema_version: 1,
        }),
        preconditions: None,
        labels: vec![
            "phase4.context.instruction_source".to_string(),
            format!("phase4.context.instruction_scope:{}", source.scope_label),
            format!("phase4.context.instruction_layer:{}", source.source_label),
            format!("phase4.context.instruction_path:{}", source.path.display()),
        ],
        redaction_hints: vec![legion_protocol::RedactionHint::MetadataOnly],
        schema_version: 1,
    }
}

fn source_kind_rank(source_label: &str) -> u8 {
    if source_label.ends_with("-agents") {
        0
    } else if source_label.ends_with("-rules") {
        1
    } else {
        2
    }
}

fn scope_rank(scope_label: &str) -> u8 {
    match scope_label {
        "workspace" => 0,
        "user" => 1,
        _ => 2,
    }
}

#[derive(Debug, Clone)]
struct DeferredSaveSuccess {
    request_id: uuid::Uuid,
    buffer_id: BufferId,
    applied: legion_project::WorkspaceSaveApplied,
}

#[derive(Debug, Clone)]
enum ProposalMutationRollback {
    None,
    TextEdit {
        workspace_id: WorkspaceId,
        file_id: FileId,
    },
    WorkspaceFile(WorkspaceMutationRollbackCheckpoint),
    Composite(Vec<ProposalMutationRollback>),
    Scoped {
        proposal: Box<WorkspaceProposal>,
        rollback: Box<ProposalMutationRollback>,
    },
}

