fn metadata_fingerprint(algorithm: &str, value: &str) -> FileFingerprint {
    FileFingerprint {
        algorithm: algorithm.to_string(),
        value: value.to_string(),
    }
}

#[cfg(feature = "ai")]
fn value_fingerprint(algorithm: &str, value: &Value) -> FileFingerprint {
    let mut hasher = DefaultHasher::new();
    value.to_string().hash(&mut hasher);
    metadata_fingerprint(algorithm, &format!("{:016x}", hasher.finish()))
}

fn trust_reference(
    reference_id: &str,
    kind: legion_protocol::AssistedAiTrustProjectionKind,
) -> legion_protocol::AssistedAiTrustProjectionReference {
    legion_protocol::AssistedAiTrustProjectionReference {
        reference_id: reference_id.to_string(),
        kind,
        projection_hash: metadata_fingerprint("projection-id", reference_id),
        schema_version: 1,
    }
}

