fn parse_search_query(
    query: &str,
) -> Result<(SearchPattern, WorkspaceSearchFilters, String, bool), String> {
    let mut mode = SearchPatternKind::Literal;
    let mut case_sensitive = true;
    let mut whole_word = false;
    let mut include_globs = Vec::<String>::new();
    let mut exclude_globs = Vec::<String>::new();
    let mut pattern_parts = Vec::<String>::new();

    for token in query.split_whitespace() {
        if let Some(pattern) = token.strip_prefix("regex:") {
            mode = SearchPatternKind::Regex;
            if !pattern.is_empty() {
                pattern_parts.push(pattern.to_string());
            }
            continue;
        }
        if let Some(pattern) = token.strip_prefix("re:") {
            mode = SearchPatternKind::Regex;
            if !pattern.is_empty() {
                pattern_parts.push(pattern.to_string());
            }
            continue;
        }
        if let Some(pattern) = token.strip_prefix("literal:") {
            mode = SearchPatternKind::Literal;
            if !pattern.is_empty() {
                pattern_parts.push(pattern.to_string());
            }
            continue;
        }
        if let Some(pattern) = token.strip_prefix("word:") {
            whole_word = true;
            if !pattern.is_empty() {
                pattern_parts.push(pattern.to_string());
            }
            continue;
        }
        if token == "word" {
            whole_word = true;
            continue;
        }
        if token == "case" {
            case_sensitive = true;
            continue;
        }
        if token == "icase" || token == "nocase" {
            case_sensitive = false;
            continue;
        }
        if let Some(pattern) = token.strip_prefix("include:") {
            if pattern.is_empty() {
                return Err("include glob is empty".to_string());
            }
            include_globs.push(pattern.to_string());
            continue;
        }
        if let Some(pattern) = token.strip_prefix("exclude:") {
            if pattern.is_empty() {
                return Err("exclude glob is empty".to_string());
            }
            exclude_globs.push(pattern.to_string());
            continue;
        }
        pattern_parts.push(token.to_string());
    }

    let pattern = pattern_parts.join(" ").trim().to_string();
    if pattern.is_empty() {
        return Err("Search query is empty".to_string());
    }

    let compiled_pattern = match mode {
        SearchPatternKind::Literal => SearchPattern::literal(&pattern, case_sensitive, whole_word)
            .map_err(|err| format!("invalid literal search: {err}"))?,
        SearchPatternKind::Regex => SearchPattern::regex(&pattern, case_sensitive, whole_word)
            .map_err(|err| format!("invalid regex search: {err}"))?,
    };

    let include = compile_search_globset(&include_globs)?;
    let exclude = compile_search_globset(&exclude_globs)?;

    Ok((
        compiled_pattern,
        WorkspaceSearchFilters { include, exclude },
        pattern,
        matches!(mode, SearchPatternKind::Literal),
    ))
}

fn compile_search_globset(patterns: &[String]) -> Result<Option<Arc<GlobSet>>, String> {
    if patterns.is_empty() {
        return Ok(None);
    }

    let mut builder = GlobSetBuilder::new();
    for pattern in patterns {
        builder.add(
            Glob::new(pattern).map_err(|err| format!("invalid search glob `{pattern}`: {err}"))?,
        );
    }
    builder
        .build()
        .map(|set| Some(Arc::new(set)))
        .map_err(|err| format!("invalid search glob set: {err}"))
}

fn normalize_search_limit(limit: usize) -> usize {
    if limit == 0 {
        SEARCH_DEFAULT_RESULT_LIMIT
    } else {
        limit.min(SEARCH_MAX_RESULT_LIMIT)
    }
}

fn search_status_for_result(
    scope: SearchScopeProjection,
    result: &SearchBuildResult,
) -> SearchStatusProjection {
    if let Some(message) = &result.validation_error {
        return SearchStatusProjection {
            kind: SearchStatusKindProjection::ValidationError,
            message: message.clone(),
        };
    }

    if result.degraded_limited {
        return SearchStatusProjection {
            kind: SearchStatusKindProjection::DegradedLimited,
            message: if result.results.is_empty() {
                "Search was limited to degraded viewport content; no visible matches".to_string()
            } else {
                format!(
                    "Search was limited to degraded viewport content; {} visible matches",
                    result.results.len()
                )
            },
        };
    }

    if result.results.is_empty() {
        SearchStatusProjection {
            kind: SearchStatusKindProjection::NoResults,
            message: "No search results".to_string(),
        }
    } else {
        let scope_label = match scope {
            SearchScopeProjection::ActiveFile => "active file",
            SearchScopeProjection::Workspace => "workspace",
        };
        SearchStatusProjection {
            kind: SearchStatusKindProjection::Completed,
            message: format!("Found {} results in {scope_label}", result.results.len()),
        }
    }
}

fn build_search_projection(
    query_id: Option<String>,
    scope: SearchScopeProjection,
    query_label: String,
    result_limit: usize,
    status: SearchStatusProjection,
    result: SearchBuildResult,
) -> SearchProjection {
    SearchProjection {
        query_id,
        scope,
        query_label,
        status,
        results: result.results,
        result_limit,
        omitted_result_count: result.omitted_result_count,
        omitted_file_count: result.omitted_file_count,
        diagnostics: result.diagnostics,
        generated_at: TimestampMillis::now(),
        schema_version: 1,
    }
}

fn structural_search_status_for_result(result: &StructuralBuildResult) -> SearchStatusProjection {
    if result.matches.is_empty() {
        SearchStatusProjection {
            kind: SearchStatusKindProjection::NoResults,
            message: "No structural search results".to_string(),
        }
    } else {
        SearchStatusProjection {
            kind: SearchStatusKindProjection::Completed,
            message: format!("Found {} structural matches", result.matches.len()),
        }
    }
}

struct StructuralSearchProjectionInput<'a> {
    query_id: Option<String>,
    scope: SearchScopeProjection,
    pattern_label: String,
    rewrite_label: Option<String>,
    result_limit: usize,
    status: SearchStatusProjection,
    result: &'a StructuralBuildResult,
    proposal_id: Option<ProposalId>,
}

fn build_structural_search_projection(
    input: StructuralSearchProjectionInput<'_>,
) -> StructuralSearchProjection {
    StructuralSearchProjection {
        query_id: input.query_id,
        scope: input.scope,
        pattern_label: input.pattern_label,
        rewrite_label: input.rewrite_label,
        status: input.status,
        matches: input.result.matches.clone(),
        result_limit: input.result_limit,
        omitted_match_count: input.result.omitted_match_count,
        omitted_file_count: input.result.omitted_file_count,
        diagnostics: input.result.diagnostics.clone(),
        proposal_id: input.proposal_id,
        generated_at: TimestampMillis::now(),
        schema_version: 1,
    }
}

fn git_projection_from_project(snapshot: ProjectGitSnapshot) -> GitProjection {
    GitProjection {
        root_label: Some(snapshot.root.0),
        branch_label: snapshot.branch_label,
        head_short: snapshot.head_short,
        remote_url: snapshot.remote_url,
        remote_default_branch: snapshot.remote_default_branch,
        changed_files: snapshot
            .changed_files
            .into_iter()
            .map(|file| GitFileProjection {
                path: file.path,
                status: file.status,
                inserted_lines: file.inserted_lines,
                deleted_lines: file.deleted_lines,
                unstaged_hunk_count: file.unstaged_hunk_count,
                staged_hunk_count: file.staged_hunk_count,
                stageable: file.stageable,
                diff_strategy: git_diff_strategy_projection(file.diff_strategy),
                fallback_reason: file.fallback_reason,
                conflict: file.conflict,
            })
            .collect(),
        hunks: snapshot
            .hunks
            .into_iter()
            .map(|hunk| GitHunkProjection {
                hunk_id: hunk.hunk_id,
                path: hunk.path,
                stage: git_hunk_stage_projection(hunk.stage),
                header: hunk.header,
                old_start: hunk.old_start,
                old_lines: hunk.old_lines,
                new_start: hunk.new_start,
                new_lines: hunk.new_lines,
                added_lines: hunk.added_lines,
                deleted_lines: hunk.deleted_lines,
                context: hunk.context,
            })
            .collect(),
        blame_lines: snapshot
            .blame_lines
            .into_iter()
            .map(|line| GitBlameLineProjection {
                path: line.path,
                line_number: line.line_number,
                commit_short: line.commit_short,
                author: line.author,
                summary: line.summary,
                line_preview: line.line_preview,
            })
            .collect(),
        commits: snapshot
            .commits
            .into_iter()
            .map(|commit| GitCommitProjection {
                hash: commit.hash,
                short_hash: commit.short_hash,
                author: commit.author,
                date: commit.date,
                summary: commit.summary,
                parent_count: commit.parent_count,
                refs: commit.refs,
            })
            .collect(),
        conflicts: snapshot
            .conflicts
            .into_iter()
            .map(|conflict| GitConflictProjection {
                path: conflict.path,
                marker_count: conflict.marker_count,
                actions: conflict.actions,
            })
            .collect(),
        worktrees: snapshot
            .worktrees
            .into_iter()
            .map(|worktree| GitWorktreeProjection {
                path: worktree.path,
                branch_label: worktree.branch_label,
                head_short: worktree.head_short,
                kind: match worktree.kind {
                    legion_project::ProjectGitWorktreeKind::Agent => {
                        GitWorktreeKindProjection::Agent
                    }
                    legion_project::ProjectGitWorktreeKind::Manual => {
                        GitWorktreeKindProjection::Manual
                    }
                },
                prunable: worktree.prunable,
            })
            .collect(),
        diagnostics: snapshot.diagnostics,
        generated_at: snapshot.generated_at,
        schema_version: snapshot.schema_version,
    }
}

fn git_diff_strategy_projection(strategy: GitDiffStrategy) -> GitDiffStrategyProjection {
    match strategy {
        GitDiffStrategy::Syntactic => GitDiffStrategyProjection::Syntactic,
        GitDiffStrategy::LineFallback => GitDiffStrategyProjection::LineFallback,
    }
}

fn git_hunk_stage_projection(stage: GitHunkStage) -> GitHunkStageProjection {
    match stage {
        GitHunkStage::Unstaged => GitHunkStageProjection::Unstaged,
        GitHunkStage::Staged => GitHunkStageProjection::Staged,
    }
}

fn git_protocol_error(code: impl Into<String>, message: impl Into<String>) -> AppCompositionError {
    AppCompositionError::Protocol(ProtocolError {
        code: code.into(),
        message: message.into(),
    })
}

fn git_inspection_protocol_error(error: GitInspectionError) -> AppCompositionError {
    git_protocol_error("git_operation_failed", error.to_string())
}

fn structural_document_for_tree_node(
    node: &FileTreeNode,
    fallback_generation: WorkspaceGeneration,
    text: String,
) -> SourceDocument {
    let metadata = node.metadata.as_ref();
    let file_content_version = metadata
        .and_then(|metadata| metadata.content_version)
        .unwrap_or(node.identity.content_version);
    let workspace_generation = metadata
        .and_then(|metadata| metadata.workspace_generation)
        .unwrap_or(fallback_generation);
    let mut document = SourceDocument::with_versions(
        node.identity.workspace_id,
        node.identity.file_id,
        node.identity.canonical_path.clone(),
        language_id_for_path(&node.identity.canonical_path),
        file_content_version,
        workspace_generation,
        None,
        SemanticPrivacyScope::Workspace,
        text,
    );
    if let Some(fingerprint) = metadata.and_then(|metadata| metadata.fingerprint.clone()) {
        document.identity.content_hash = fingerprint.clone();
        document.identity.disk_fingerprint = Some(fingerprint);
    }
    document.identity.byte_len = metadata.and_then(|metadata| metadata.size_bytes);
    document.identity.modified_at = metadata.and_then(|metadata| metadata.modified_at);
    document
}

fn collect_structural_document_result(
    query_id: &str,
    _scope: SearchScopeProjection,
    query: &StructuralSearchQuery,
    document: SourceDocument,
    limit: usize,
    result: &mut StructuralBuildResult,
) {
    let report = index_run_structural_search(&document, query);
    result.omitted_match_count = result
        .omitted_match_count
        .saturating_add(report.omitted_match_count);
    result.diagnostics.extend(
        report
            .diagnostics
            .iter()
            .map(|diagnostic| format!("{}: {}", diagnostic.code, diagnostic.message)),
    );

    let mut selected = Vec::new();
    for matched in report.matches {
        if result.matches.len() < limit {
            result.matches.push(StructuralSearchMatchProjection {
                query_id: query_id.to_string(),
                workspace_id: matched.workspace_id,
                file_id: matched.file_id,
                file_path: matched.path.clone(),
                range: matched.range,
                captures: matched
                    .captures
                    .iter()
                    .map(|capture| StructuralSearchCaptureProjection {
                        name: capture.name.clone(),
                        value: capture.value.clone(),
                        range: capture.range,
                    })
                    .collect(),
                snippet: matched.snippet.clone(),
                replacement_preview: matched.replacement_preview.clone(),
            });
            selected.push(matched);
        } else {
            result.omitted_match_count = result.omitted_match_count.saturating_add(1);
        }
    }

    if !selected.is_empty() {
        result.reports.push(StructuralDocumentReport {
            document,
            matches: selected,
        });
    }
}

fn workspace_node_is_regular_file(node: &FileTreeNode) -> bool {
    node.metadata
        .as_ref()
        .is_some_and(|metadata| matches!(metadata.kind, FileKind::File))
}

fn palette_open_query(mode: PaletteMode, query: String) -> String {
    if query.is_empty() {
        return mode
            .prefix()
            .map_or_else(String::new, |prefix| prefix.to_string());
    }
    if query.starts_with('>')
        || query.starts_with('/')
        || query.starts_with('#')
        || query.starts_with('@')
        || query.starts_with('^')
    {
        query
    } else {
        mode.prefix()
            .map_or(query.clone(), |prefix| format!("{prefix}{query}"))
    }
}

fn palette_mode_for_query(query: &str) -> Option<PaletteMode> {
    match query.chars().next() {
        Some('>') => Some(PaletteMode::Command),
        Some('/') => Some(PaletteMode::Search),
        Some('#') => Some(PaletteMode::StructuralSearch),
        Some('@') => Some(PaletteMode::Symbol),
        Some('^') => Some(PaletteMode::RecentBuffers),
        Some(_) | None => Some(PaletteMode::File),
    }
}

fn palette_query_body(mode: PaletteMode, query: &str) -> &str {
    if mode
        .prefix()
        .is_some_and(|prefix| query.starts_with(prefix))
    {
        &query[1..]
    } else {
        query
    }
}

fn palette_scope_label(scope: SearchScopeProjection) -> &'static str {
    match scope {
        SearchScopeProjection::ActiveFile => "active file",
        SearchScopeProjection::Workspace => "workspace",
    }
}

