    fn refresh_palette_results(&mut self) -> Result<(), AppCompositionError> {
        let mode = palette_mode_for_query(&self.palette.query).unwrap_or(self.palette.mode);
        let query = palette_query_body(mode, &self.palette.query);
        let results = match mode {
            PaletteMode::File => self.palette_file_results(query)?,
            PaletteMode::Symbol => self.palette_symbol_results(query)?,
            PaletteMode::RecentBuffers => self.palette_recent_buffer_results(query)?,
            PaletteMode::Command => self.palette_command_results(query),
            PaletteMode::Search => vec![self.palette_search_result(query)],
            PaletteMode::StructuralSearch => vec![self.palette_structural_search_result(query)],
        };

        self.palette.mode = mode;
        self.palette.results = results;
        self.palette.clamp_selection();
        Ok(())
    }

    fn palette_file_results(&self, query: &str) -> Result<Vec<PaletteResult>, AppCompositionError> {
        let Some(workspace_id) = self.active_documents.workspace_id() else {
            return Ok(Vec::new());
        };

        let recent_bonus = self.palette_recent_path_bonus_map();
        let mut paths = AppWorkspaceCommandPort::tree_snapshot(&self.workspace, workspace_id)?
            .into_iter()
            .filter(workspace_node_is_regular_file)
            .map(|node| node.identity.canonical_path.0)
            .collect::<Vec<_>>();
        for metadata in self.active_documents.buffer_file_metadata.values() {
            paths.push(metadata.identity.canonical_path.0.clone());
        }
        paths.sort();
        paths.dedup();

        let mut scored = paths
            .into_iter()
            .filter_map(|path| {
                palette_fuzzy_score(&path, query).map(|(score, match_indices)| {
                    let recency_bonus = recent_bonus.get(&path).copied().unwrap_or_default();
                    PaletteScoredResult {
                        score: score.saturating_add(recency_bonus),
                        result: PaletteResult {
                            id: format!("file:{path}"),
                            kind: PaletteResultKind::File,
                            title: path.clone(),
                            detail: Some(if recency_bonus > 0 {
                                "Recent workspace file".to_string()
                            } else {
                                "Workspace file".to_string()
                            }),
                            shortcut_label: Some("Enter".to_string()),
                            path: Some(path),
                            buffer_id: None,
                            position: None,
                            match_indices,
                            disabled_reason: None,
                        },
                    }
                })
            })
            .collect::<Vec<_>>();
        sort_palette_results(&mut scored);
        Ok(scored
            .into_iter()
            .take(PALETTE_RESULT_LIMIT)
            .map(|scored| scored.result)
            .collect())
    }

    fn palette_symbol_results(
        &self,
        query: &str,
    ) -> Result<Vec<PaletteResult>, AppCompositionError> {
        let Some(workspace_id) = self.active_documents.workspace_id() else {
            return Ok(Vec::new());
        };
        let active_file_id = self.active_documents.active_file_id;
        let scope_file_only = self.palette.scope == SearchScopeProjection::ActiveFile;
        let recent_bonus = self.palette_recent_path_bonus_map();

        let mut scored = self
            .language_tooling
            .symbols()
            .iter()
            .filter(|symbol| symbol.workspace_id == workspace_id)
            .filter(|symbol| !scope_file_only || Some(symbol.file_id) == active_file_id)
            .filter_map(|symbol| {
                let title = symbol
                    .display_name
                    .clone()
                    .unwrap_or_else(|| symbol.symbol_name_hash.value.clone());
                let searchable = format!("{title} {}", symbol.path.0);
                palette_fuzzy_score(&searchable, query).map(|(score, match_indices)| {
                    let recency_bonus = recent_bonus
                        .get(&symbol.path.0)
                        .copied()
                        .unwrap_or_default();
                    let position = symbol.declaration_range.map(|range| range.start);
                    PaletteScoredResult {
                        score: score.saturating_add(recency_bonus),
                        result: PaletteResult {
                            id: format!("symbol:{}", symbol.symbol_id.0),
                            kind: PaletteResultKind::Symbol,
                            title,
                            detail: Some(format!("{} · {}", symbol.kind, symbol.path.0)),
                            shortcut_label: Some("Enter".to_string()),
                            path: Some(symbol.path.0.clone()),
                            buffer_id: None,
                            position,
                            match_indices,
                            disabled_reason: None,
                        },
                    }
                })
            })
            .collect::<Vec<_>>();
        sort_palette_results(&mut scored);
        Ok(scored
            .into_iter()
            .take(PALETTE_RESULT_LIMIT)
            .map(|scored| scored.result)
            .collect())
    }

    fn palette_recent_buffer_results(
        &self,
        query: &str,
    ) -> Result<Vec<PaletteResult>, AppCompositionError> {
        let recent_bonus = self.palette_recent_path_bonus_map();
        let mut scored = self
            .active_documents
            .recent_buffer_ids()
            .iter()
            .rev()
            .filter_map(|buffer_id| {
                let metadata = self.active_documents.metadata_for_buffer(*buffer_id)?;
                let path = metadata.identity.canonical_path.0.clone();
                palette_fuzzy_score(&path, query).map(|(score, match_indices)| {
                    let recency_bonus = recent_bonus.get(&path).copied().unwrap_or_default();
                    PaletteScoredResult {
                        score: score.saturating_add(recency_bonus),
                        result: PaletteResult {
                            id: format!("recent-buffer:{}", buffer_id.0),
                            kind: PaletteResultKind::RecentBuffers,
                            title: path.clone(),
                            detail: Some("Recent open tab".to_string()),
                            shortcut_label: Some("Enter".to_string()),
                            path: Some(path),
                            buffer_id: Some(*buffer_id),
                            position: None,
                            match_indices,
                            disabled_reason: None,
                        },
                    }
                })
            })
            .collect::<Vec<_>>();
        sort_palette_results(&mut scored);
        Ok(scored
            .into_iter()
            .take(PALETTE_RESULT_LIMIT)
            .map(|scored| scored.result)
            .collect())
    }

    fn palette_recent_path_bonus_map(&self) -> HashMap<String, i32> {
        let recent_ids = self.active_documents.recent_buffer_ids();
        recent_ids
            .iter()
            .enumerate()
            .filter_map(|(index, buffer_id)| {
                self.active_documents
                    .metadata_for_buffer(*buffer_id)
                    .map(|metadata| {
                        let bonus = ((index + 1) as i32).saturating_mul(1_000);
                        (metadata.identity.canonical_path.0.clone(), bonus)
                    })
            })
            .collect()
    }

    fn palette_command_results(&self, query: &str) -> Vec<PaletteResult> {
        let active_buffer_id = self.active_documents.active_buffer_id;
        let mut scored = palette_command_specs()
            .into_iter()
            .filter_map(|spec| {
                palette_fuzzy_score(spec.title, query).map(|(score, match_indices)| {
                    let (buffer_id, disabled_reason) = match spec.id {
                        "save-active-buffer" | "close-active-tab" => (
                            active_buffer_id,
                            active_buffer_id
                                .is_none()
                                .then(|| "Open a tab first".to_string()),
                        ),
                        "reveal-active-file" => {
                            let disabled_reason = active_buffer_id
                                .and_then(|buffer_id| {
                                    self.active_documents.metadata_for_buffer(buffer_id)
                                })
                                .is_none()
                                .then(|| "Open an active file first".to_string());
                            (active_buffer_id, disabled_reason)
                        }
                        _ => (None, None),
                    };
                    PaletteScoredResult {
                        score,
                        result: PaletteResult {
                            id: format!("command:{}", spec.id),
                            kind: PaletteResultKind::Command,
                            title: spec.title.to_string(),
                            detail: Some(spec.detail.to_string()),
                            shortcut_label: spec.shortcut_label.map(str::to_string),
                            path: None,
                            buffer_id,
                            position: None,
                            match_indices,
                            disabled_reason,
                        },
                    }
                })
            })
            .collect::<Vec<_>>();
        sort_palette_results(&mut scored);
        scored
            .into_iter()
            .take(PALETTE_RESULT_LIMIT)
            .map(|scored| scored.result)
            .collect()
    }

    fn palette_search_result(&self, query: &str) -> PaletteResult {
        let trimmed = query.trim();
        let scope = palette_scope_label(self.palette.scope);
        PaletteResult {
            id: "search:run".to_string(),
            kind: PaletteResultKind::Search,
            title: if trimmed.is_empty() {
                format!("Search {scope}")
            } else {
                format!("Search {scope} for \"{trimmed}\"")
            },
            detail: Some("Run lexical search".to_string()),
            shortcut_label: Some("Enter".to_string()),
            path: None,
            buffer_id: None,
            position: None,
            match_indices: Vec::new(),
            disabled_reason: trimmed
                .is_empty()
                .then(|| "Enter a search query".to_string()),
        }
    }

    fn palette_structural_search_result(&self, query: &str) -> PaletteResult {
        let trimmed = query.trim();
        let scope = palette_scope_label(self.palette.scope);
        PaletteResult {
            id: "structural-search:run".to_string(),
            kind: PaletteResultKind::StructuralSearch,
            title: if trimmed.is_empty() {
                format!("Structural search {scope}")
            } else {
                format!("Structural search {scope} for \"{trimmed}\"")
            },
            detail: Some("Preview structural matches".to_string()),
            shortcut_label: Some("Enter".to_string()),
            path: None,
            buffer_id: None,
            position: None,
            match_indices: Vec::new(),
            disabled_reason: trimmed
                .is_empty()
                .then(|| "Enter a structural pattern".to_string()),
        }
    }

    fn palette_result_intent(&self, result: &PaletteResult) -> Option<CommandDispatchIntent> {
        match result.kind {
            PaletteResultKind::File => result
                .path
                .as_ref()
                .map(|path| CommandDispatchIntent::OpenPath { path: path.clone() }),
            PaletteResultKind::Symbol => match (result.path.as_ref(), result.position) {
                (Some(path), Some(position)) => Some(CommandDispatchIntent::OpenPathAtPosition {
                    path: path.clone(),
                    position,
                }),
                _ => None,
            },
            PaletteResultKind::RecentBuffers => result
                .buffer_id
                .map(|buffer_id| CommandDispatchIntent::SwitchTab { buffer_id }),
            PaletteResultKind::Command => {
                result
                    .id
                    .strip_prefix("command:")
                    .and_then(|command_id| match command_id {
                        "save-active-buffer" => result
                            .buffer_id
                            .map(|buffer_id| CommandDispatchIntent::Save { buffer_id }),
                        "close-active-tab" => result
                            .buffer_id
                            .map(|buffer_id| CommandDispatchIntent::CloseTab { buffer_id }),
                        "reveal-active-file" => result.buffer_id.and_then(|buffer_id| {
                            self.active_documents
                                .metadata_for_buffer(buffer_id)
                                .map(|metadata| CommandDispatchIntent::RevealInExplorer {
                                    file_id: metadata.identity.file_id,
                                })
                        }),
                        "git-commit" => {
                            let body =
                                palette_query_body(PaletteMode::Command, &self.palette.query)
                                    .trim()
                                    .to_string();
                            let message = body
                                .strip_prefix("git commit")
                                .or_else(|| body.strip_prefix("commit"))
                                .unwrap_or(&body)
                                .trim()
                                .to_string();
                            (!message.is_empty())
                                .then_some(CommandDispatchIntent::CommitGitChanges { message })
                        }
                        "git-switch-branch" => {
                            let branch =
                                palette_query_body(PaletteMode::Command, &self.palette.query)
                                    .trim()
                                    .to_string();
                            (!branch.is_empty())
                                .then_some(CommandDispatchIntent::SwitchGitBranch { branch })
                        }
                        "git-create-branch" => {
                            let branch =
                                palette_query_body(PaletteMode::Command, &self.palette.query)
                                    .trim()
                                    .to_string();
                            (!branch.is_empty())
                                .then_some(CommandDispatchIntent::CreateGitBranch { branch })
                        }
                        "git-delete-branch" => {
                            let branch =
                                palette_query_body(PaletteMode::Command, &self.palette.query)
                                    .trim()
                                    .to_string();
                            (!branch.is_empty())
                                .then_some(CommandDispatchIntent::DeleteGitBranch { branch })
                        }
                        "git-stash" => {
                            let message =
                                palette_query_body(PaletteMode::Command, &self.palette.query)
                                    .trim()
                                    .to_string();
                            Some(CommandDispatchIntent::StashGitChanges {
                                message: (!message.is_empty()).then_some(message),
                            })
                        }
                        "git-prune-worktrees" => Some(CommandDispatchIntent::PruneGitWorktrees),
                        "git-remove-worktree" => {
                            let path =
                                palette_query_body(PaletteMode::Command, &self.palette.query)
                                    .trim()
                                    .to_string();
                            (!path.is_empty())
                                .then_some(CommandDispatchIntent::RemoveGitWorktree { path })
                        }
                        _ => palette_command_intent(command_id),
                    })
            }
            PaletteResultKind::Search => {
                let query = palette_query_body(PaletteMode::Search, &self.palette.query)
                    .trim()
                    .to_string();
                (!query.is_empty()).then_some(CommandDispatchIntent::RunSearch {
                    scope: self.palette.scope,
                    query,
                    limit: 0,
                })
            }
            PaletteResultKind::StructuralSearch => {
                let pattern =
                    palette_query_body(PaletteMode::StructuralSearch, &self.palette.query)
                        .trim()
                        .to_string();
                (!pattern.is_empty()).then_some(CommandDispatchIntent::RunStructuralSearch {
                    scope: self.palette.scope,
                    pattern,
                    rewrite: None,
                    limit: 0,
                })
            }
        }
    }

    /// Route a UI dispatch intent through editor and workspace authorities.
    pub fn dispatch_ui_intent(
        &mut self,
        intent: CommandDispatchIntent,
    ) -> Result<AppCommandOutcome, AppCompositionError> {
        let event_context = self.next_event_context();
        if Self::proposal_intent_id(&intent).is_some() {
            return self.dispatch_proposal_ui_intent(intent, event_context);
        }

        let request = CommandDispatcher::route_intent(
            intent,
            AppCommandRouteContext::from_active(&self.active_documents),
            event_context.correlation_id,
        )?;

        match &request {
            AppCommandRequest::ApplyEdit { buffer_id, edit } => {
                let descriptor = self.apply_edit_to_buffer_with_correlation(
                    *buffer_id,
                    edit.clone(),
                    event_context.correlation_id,
                )?;
                self.set_cursor_after_edit(*buffer_id, edit)?;
                self.emit_transaction_event(&descriptor);
                return Ok(AppCommandOutcome::Edited(descriptor));
            }
            AppCommandRequest::ClipboardCopy { buffer_id } => {
                return Ok(AppCommandOutcome::ClipboardUpdated(
                    self.clipboard_metadata_for_selection(*buffer_id, false)?.0,
                ));
            }
            AppCommandRequest::ClipboardCut { buffer_id } => {
                let (metadata, selection) =
                    self.clipboard_metadata_for_selection(*buffer_id, true)?;
                if metadata.byte_len > 0
                    && let Some(selection) = selection
                {
                    let descriptor = self.apply_edit_to_buffer_with_correlation(
                        *buffer_id,
                        TextEdit::delete(CommandDispatcher::editor_range(selection)),
                        event_context.correlation_id,
                    )?;
                    self.collapse_selection_to_cursor(*buffer_id, selection.start)?;
                    self.emit_transaction_event(&descriptor);
                }
                return Ok(AppCommandOutcome::ClipboardUpdated(metadata));
            }
            AppCommandRequest::SelectAll { buffer_id } => {
                self.select_all_buffer(*buffer_id)?;
                return Ok(AppCommandOutcome::SelectionSet(*buffer_id));
            }
            _ => {}
        }

        let mut state = AppCommandExecutionState::from_active(&self.active_documents);
        if let Some(outcome) = CommandExecutionService::execute(
            &request,
            &mut self.editor,
            &self.workspace,
            &mut state,
        )? {
            state.apply_to_active(&mut self.active_documents);
            return Ok(outcome);
        }

        match request {
            AppCommandRequest::SetProductMode { mode } => {
                self.set_product_mode(mode);
                Ok(AppCommandOutcome::ProductModeChanged(mode))
            }
            AppCommandRequest::Save { buffer_id } => {
                self.active_documents.ensure_active_buffer(buffer_id)?;
                Ok(AppCommandOutcome::Save(self.save_active_buffer()?))
            }
            AppCommandRequest::SwitchTab { buffer_id } => {
                self.switch_tab(buffer_id)?;
                Ok(AppCommandOutcome::TabSwitched(buffer_id))
            }
            AppCommandRequest::CloseTab { buffer_id } => {
                Ok(AppCommandOutcome::TabClose(self.close_tab(buffer_id)?))
            }
            AppCommandRequest::SaveAll => Ok(AppCommandOutcome::SaveAll(self.save_all()?)),
            AppCommandRequest::SetCursor { buffer_id, cursor } => {
                self.set_buffer_cursor(buffer_id, cursor)?;
                Ok(AppCommandOutcome::CursorSet(buffer_id))
            }
            AppCommandRequest::SetSelection { buffer_id, range } => {
                self.set_buffer_selection(buffer_id, range)?;
                Ok(AppCommandOutcome::SelectionSet(buffer_id))
            }
            AppCommandRequest::SetViewportScroll { buffer_id, scroll } => {
                self.set_viewport_scroll(buffer_id, scroll)?;
                Ok(AppCommandOutcome::ViewportScrollSet(buffer_id))
            }
            AppCommandRequest::OpenPalette { mode, query, scope } => Ok(
                AppCommandOutcome::PaletteUpdated(self.open_palette(mode, query, scope)?),
            ),
            AppCommandRequest::ClosePalette => {
                Ok(AppCommandOutcome::PaletteUpdated(self.close_palette()))
            }
            AppCommandRequest::UpdatePaletteQuery { query } => Ok(
                AppCommandOutcome::PaletteUpdated(self.update_palette_query(query)?),
            ),
            AppCommandRequest::MovePaletteSelection { delta } => Ok(
                AppCommandOutcome::PaletteUpdated(self.move_palette_selection(delta)),
            ),
            AppCommandRequest::CompletePaletteSelection => Ok(AppCommandOutcome::PaletteUpdated(
                self.complete_palette_selection()?,
            )),
            AppCommandRequest::DispatchPaletteSelection => self.dispatch_palette_selection(),
            AppCommandRequest::OpenSettings => {
                Ok(AppCommandOutcome::SettingsUpdated(self.open_settings()))
            }
            AppCommandRequest::SetThemePreference { preference } => Ok(
                AppCommandOutcome::SettingsUpdated(self.set_theme_preference(preference)),
            ),
            AppCommandRequest::SetZoomPercent { zoom_percent } => Ok(
                AppCommandOutcome::SettingsUpdated(self.set_zoom_percent(zoom_percent)),
            ),
            AppCommandRequest::SetEditorFontSize { font_size_pt } => Ok(
                AppCommandOutcome::SettingsUpdated(self.set_editor_font_size(font_size_pt)),
            ),
            AppCommandRequest::SetEditorFontFamily { family } => Ok(
                AppCommandOutcome::SettingsUpdated(self.set_editor_font_family(family)),
            ),
            AppCommandRequest::SetToastVerbosity { verbosity } => Ok(
                AppCommandOutcome::SettingsUpdated(self.set_toast_verbosity(verbosity)),
            ),
            AppCommandRequest::SetLineNumbersVisible { visible } => Ok(
                AppCommandOutcome::SettingsUpdated(self.set_line_numbers_visible(visible)),
            ),
            AppCommandRequest::SetCurrentLineHighlight { enabled } => Ok(
                AppCommandOutcome::SettingsUpdated(self.set_current_line_highlight(enabled)),
            ),
            AppCommandRequest::SetStickyHeadersVisible { visible } => Ok(
                AppCommandOutcome::SettingsUpdated(self.set_sticky_headers_visible(visible)),
            ),
            AppCommandRequest::SetCodeFoldingVisible { visible } => Ok(
                AppCommandOutcome::SettingsUpdated(self.set_code_folding_visible(visible)),
            ),
            AppCommandRequest::SetMinimapVisible { visible } => Ok(
                AppCommandOutcome::SettingsUpdated(self.set_minimap_visible(visible)),
            ),
            AppCommandRequest::SetWhitespaceGuidesVisible { visible } => Ok(
                AppCommandOutcome::SettingsUpdated(self.set_whitespace_guides_visible(visible)),
            ),
            AppCommandRequest::SetIndentGuidesVisible { visible } => Ok(
                AppCommandOutcome::SettingsUpdated(self.set_indent_guides_visible(visible)),
            ),
            AppCommandRequest::SetSmoothScrollingEnabled { enabled } => Ok(
                AppCommandOutcome::SettingsUpdated(self.set_smooth_scrolling_enabled(enabled)),
            ),
            AppCommandRequest::SetLineWrappingPolicy {
                policy,
                wrap_column,
            } => Ok(AppCommandOutcome::SettingsUpdated(
                self.set_line_wrapping_policy(policy, wrap_column),
            )),
            AppCommandRequest::SetIndexedWorkspaceSearchEnabled { enabled } => {
                Ok(AppCommandOutcome::SettingsUpdated(
                    self.set_indexed_workspace_search_enabled(enabled),
                ))
            }
            AppCommandRequest::SetNextEditPredictionEnabled { enabled } => Ok(
                AppCommandOutcome::SettingsUpdated(self.set_next_edit_prediction_enabled(enabled)),
            ),
            AppCommandRequest::SetCrashReportsEnabled { enabled } => Ok(
                AppCommandOutcome::SettingsUpdated(self.set_crash_reports_enabled(enabled)),
            ),
            AppCommandRequest::ResetSettings => {
                Ok(AppCommandOutcome::SettingsUpdated(self.reset_settings()))
            }
            AppCommandRequest::RunSearch {
                query_id,
                scope,
                query,
                limit,
            } => Ok(AppCommandOutcome::SearchUpdated(
                self.run_search(query_id, scope, query, limit)?,
            )),
            AppCommandRequest::RunStructuralSearch {
                query_id,
                scope,
                pattern,
                rewrite,
                limit,
            } => Ok(AppCommandOutcome::StructuralSearchUpdated(
                self.run_structural_search(query_id, scope, pattern, rewrite, limit)?,
            )),
            AppCommandRequest::CancelSearch { query_id } => Ok(AppCommandOutcome::SearchUpdated(
                self.cancel_search(query_id),
            )),
            AppCommandRequest::RefreshGit => {
                Ok(AppCommandOutcome::GitUpdated(self.refresh_git_projection()))
            }
            AppCommandRequest::StageGitHunk { hunk_id } => Ok(AppCommandOutcome::GitUpdated(
                self.stage_or_unstage_git_hunk(&hunk_id, GitHunkStage::Unstaged)?,
            )),
            AppCommandRequest::UnstageGitHunk { hunk_id } => Ok(AppCommandOutcome::GitUpdated(
                self.stage_or_unstage_git_hunk(&hunk_id, GitHunkStage::Staged)?,
            )),
            AppCommandRequest::ResolveGitConflict { path, choice } => {
                let Some(root_path) = self.active_documents.workspace_root_path.as_deref() else {
                    return Err(AppCompositionError::WorkspaceNotOpen);
                };
                let workspace_id = self.active_documents.require_workspace_id()?;
                let repo_root = git_repository_root(Path::new(root_path))
                    .map_err(git_inspection_protocol_error)?;
                let candidate_path = repo_root.join(&path);
                let candidate_path_str = candidate_path.to_string_lossy().to_string();
                let canonical_candidate = CanonicalPath(candidate_path_str.clone());
                let buffer_id = self
                    .open_buffer_for_equivalent_path(workspace_id, &canonical_candidate)
                    .or_else(|| {
                        self.editor
                            .buffer_for_path(workspace_id, &path)
                            .or_else(|| {
                                self.editor
                                    .buffer_for_path(workspace_id, &candidate_path_str)
                            })
                    });
                let is_dirty = if let Some(buffer_id) = buffer_id {
                    self.editor.is_dirty(buffer_id).unwrap_or(true)
                } else {
                    false
                };
                if is_dirty {
                    return Err(AppCompositionError::Protocol(ProtocolError::validation(
                        format!(
                            "buffer for `{}` has unsaved changes; resolve conflict after saving or discarding edits",
                            path
                        ),
                    )));
                }
                resolve_git_conflict(Path::new(root_path), &path, choice)
                    .map_err(git_inspection_protocol_error)?;

                // Synchronize open buffer if the conflicted file is open so that
                // active_buffer_projection and subsequent edits use the resolved text.
                if let Some(buffer_id) = buffer_id {
                    let prior_active = self.active_documents.active_buffer_id;
                    if self.editor.close_buffer(buffer_id).is_ok() {
                        self.active_documents.remove_open_tab(buffer_id);
                        self.assist_inline_prediction_state
                            .clear_for_buffer(buffer_id);
                        if prior_active == Some(buffer_id) {
                            self.active_documents.activate_first_available_tab();
                        }
                        let reopened = self.open_file(&candidate_path_str).is_ok();
                        let prior = prior_active.filter(|p| *p != buffer_id);
                        if let (true, Some(prior)) = (reopened, prior) {
                            let _ = self.switch_tab(prior);
                        }
                    }
                }

                Ok(AppCommandOutcome::GitUpdated(self.refresh_git_projection()))
            }
            AppCommandRequest::CommitGitChanges { message } => {
                let Some(root_path) = self.active_documents.workspace_root_path.as_deref() else {
                    return Err(AppCompositionError::WorkspaceNotOpen);
                };
                commit_git_changes(Path::new(root_path), &message)
                    .map_err(git_inspection_protocol_error)?;
                Ok(AppCommandOutcome::GitUpdated(self.refresh_git_projection()))
            }
            AppCommandRequest::SwitchGitBranch { branch } => {
                let Some(root_path) = self.active_documents.workspace_root_path.as_deref() else {
                    return Err(AppCompositionError::WorkspaceNotOpen);
                };
                switch_git_branch(Path::new(root_path), &branch)
                    .map_err(git_inspection_protocol_error)?;
                Ok(AppCommandOutcome::GitUpdated(self.refresh_git_projection()))
            }
            AppCommandRequest::CreateGitBranch { branch } => {
                let Some(root_path) = self.active_documents.workspace_root_path.as_deref() else {
                    return Err(AppCompositionError::WorkspaceNotOpen);
                };
                create_git_branch(Path::new(root_path), &branch)
                    .map_err(git_inspection_protocol_error)?;
                Ok(AppCommandOutcome::GitUpdated(self.refresh_git_projection()))
            }
            AppCommandRequest::DeleteGitBranch { branch } => {
                let Some(root_path) = self.active_documents.workspace_root_path.as_deref() else {
                    return Err(AppCompositionError::WorkspaceNotOpen);
                };
                delete_git_branch(Path::new(root_path), &branch)
                    .map_err(git_inspection_protocol_error)?;
                Ok(AppCommandOutcome::GitUpdated(self.refresh_git_projection()))
            }
            AppCommandRequest::StashGitChanges { message } => {
                let Some(root_path) = self.active_documents.workspace_root_path.as_deref() else {
                    return Err(AppCompositionError::WorkspaceNotOpen);
                };
                stash_git_changes(Path::new(root_path), message.as_deref())
                    .map_err(git_inspection_protocol_error)?;
                Ok(AppCommandOutcome::GitUpdated(self.refresh_git_projection()))
            }
            AppCommandRequest::PushGitRemote { remote } => {
                let Some(root_path) = self.active_documents.workspace_root_path.as_deref() else {
                    return Err(AppCompositionError::WorkspaceNotOpen);
                };
                let branch = self.git_projection.branch_label.clone().ok_or_else(|| {
                    git_protocol_error(
                        "git_branch_missing",
                        "git branch label unavailable for push",
                    )
                })?;
                push_git_remote(Path::new(root_path), &remote, &branch)
                    .map_err(git_inspection_protocol_error)?;
                Ok(AppCommandOutcome::GitUpdated(self.refresh_git_projection()))
            }
            AppCommandRequest::PruneGitWorktrees => {
                let Some(root_path) = self.active_documents.workspace_root_path.as_deref() else {
                    return Err(AppCompositionError::WorkspaceNotOpen);
                };
                prune_git_worktrees(Path::new(root_path)).map_err(git_inspection_protocol_error)?;
                Ok(AppCommandOutcome::GitUpdated(self.refresh_git_projection()))
            }
            AppCommandRequest::RemoveGitWorktree { path } => {
                let Some(root_path) = self.active_documents.workspace_root_path.as_deref() else {
                    return Err(AppCompositionError::WorkspaceNotOpen);
                };
                remove_git_worktree(Path::new(root_path), Path::new(&path))
                    .map_err(git_inspection_protocol_error)?;
                Ok(AppCommandOutcome::GitUpdated(self.refresh_git_projection()))
            }
            AppCommandRequest::RequestHover {
                buffer_id,
                position,
            } => Ok(AppCommandOutcome::LanguageToolingUpdated(
                self.run_language_read(buffer_id, LanguageReadKind::Hover, position)?,
            )),
            AppCommandRequest::RequestCompletion {
                buffer_id,
                position,
            } => Ok(AppCommandOutcome::LanguageToolingUpdated(
                self.run_language_read(buffer_id, LanguageReadKind::Completion, position)?,
            )),
            AppCommandRequest::RequestAssistInlinePrediction {
                buffer_id,
                position,
            } => Ok(AppCommandOutcome::AssistInlinePredictionUpdated(
                self.request_assist_inline_prediction(
                    buffer_id,
                    position,
                    InlinePredictionTriggerKind::Explicit,
                )?,
            )),
            AppCommandRequest::AcceptAssistInlinePrediction {
                buffer_id,
                prediction_id,
            } => Ok(AppCommandOutcome::AssistInlinePredictionUpdated(
                self.accept_assist_inline_prediction(buffer_id, prediction_id)?,
            )),
            AppCommandRequest::DismissAssistInlinePrediction {
                buffer_id,
                prediction_id,
            } => Ok(AppCommandOutcome::AssistInlinePredictionUpdated(
                self.dismiss_assist_inline_prediction(buffer_id, prediction_id)?,
            )),
            AppCommandRequest::CancelAssistInlinePrediction {
                buffer_id,
                prediction_id,
            } => Ok(AppCommandOutcome::AssistInlinePredictionUpdated(
                self.cancel_assist_inline_prediction(buffer_id, prediction_id)?,
            )),
            AppCommandRequest::GoToDefinition {
                buffer_id,
                position,
            } => Ok(AppCommandOutcome::LanguageToolingUpdated(
                self.run_language_read(buffer_id, LanguageReadKind::Definition, position)?,
            )),
            AppCommandRequest::FindReferences {
                buffer_id,
                position,
            } => Ok(AppCommandOutcome::LanguageToolingUpdated(
                self.run_language_read(buffer_id, LanguageReadKind::References, position)?,
            )),
            AppCommandRequest::RefreshOutline { buffer_id } => Ok(
                AppCommandOutcome::LanguageToolingUpdated(self.run_language_read(
                    buffer_id,
                    LanguageReadKind::Outline,
                    TextCoordinate {
                        line: 0,
                        character: 0,
                        byte_offset: Some(0),
                        utf16_offset: Some(0),
                    },
                )?),
            ),
            AppCommandRequest::RequestFormattingProposal { buffer_id } => Ok(
                AppCommandOutcome::LanguageToolingUpdated(self.run_language_proposal(
                    buffer_id,
                    LanguageProposalKind::Formatting,
                    TextCoordinate {
                        line: 0,
                        character: 0,
                        byte_offset: Some(0),
                        utf16_offset: Some(0),
                    },
                    "format".to_string(),
                )?),
            ),
            AppCommandRequest::RequestRenameProposal {
                buffer_id,
                position,
                new_name,
            } => Ok(AppCommandOutcome::LanguageToolingUpdated(
                self.run_language_proposal(
                    buffer_id,
                    LanguageProposalKind::Rename,
                    position,
                    new_name,
                )?,
            )),
            AppCommandRequest::RequestOrganizeImportsProposal { buffer_id } => Ok(
                AppCommandOutcome::LanguageToolingUpdated(self.run_language_proposal(
                    buffer_id,
                    LanguageProposalKind::OrganizeImports,
                    TextCoordinate {
                        line: 0,
                        character: 0,
                        byte_offset: Some(0),
                        utf16_offset: Some(0),
                    },
                    "organize-imports".to_string(),
                )?),
            ),
            AppCommandRequest::RequestCodeActionProposal {
                buffer_id,
                action_id,
            } => Ok(AppCommandOutcome::LanguageToolingUpdated(
                self.run_language_proposal(
                    buffer_id,
                    LanguageProposalKind::CodeAction,
                    TextCoordinate {
                        line: 0,
                        character: 0,
                        byte_offset: Some(0),
                        utf16_offset: Some(0),
                    },
                    action_id,
                )?,
            )),
            AppCommandRequest::CancelLanguageOperation { operation_id } => {
                let event_context = self.next_event_context();
                self.language_tooling
                    .cancel_operation(operation_id, event_context);
                Ok(AppCommandOutcome::LanguageToolingUpdated(
                    self.language_tooling.projection(),
                ))
            }
            AppCommandRequest::RefreshDebugConfigurations => {
                self.restore_debug_breakpoints_from_storage()?;
                let context = self.active_documents.require_workspace_context()?;
                let Some(root_path) = self.active_documents.workspace_root_path.as_deref() else {
                    return Err(AppCompositionError::WorkspaceNotOpen);
                };
                let projection = self
                    .debug_workflow
                    .refresh_configurations(context, Path::new(root_path))?;
                Ok(AppCommandOutcome::DebugProjectionUpdated(projection))
            }
            AppCommandRequest::ToggleDebugBreakpoint {
                buffer_id,
                line,
                condition,
                hit_condition,
                log_message,
            } => {
                self.active_documents.ensure_active_buffer(buffer_id)?;
                let context = self.active_documents.require_workspace_context()?;
                let metadata = self
                    .active_documents
                    .active_file_metadata
                    .clone()
                    .ok_or(AppCompositionError::ActiveFileMissing)?;
                let event_context = self.next_event_context();
                let projection =
                    self.debug_workflow
                        .toggle_breakpoint(DebugBreakpointToggleInput {
                            context,
                            metadata,
                            line,
                            condition,
                            hit_condition,
                            log_message,
                            event_context,
                        });
                self.persist_debug_breakpoints()?;
                Ok(AppCommandOutcome::DebugProjectionUpdated(projection))
            }
            AppCommandRequest::LaunchDebugSession { configuration_id } => {
                let context = self.active_documents.require_workspace_context()?;
                let event_context = self.next_event_context();
                let projection =
                    self.debug_workflow
                        .launch(context, configuration_id, event_context);
                self.persist_debug_breakpoints()?;
                self.persist_latest_debug_audit()?;
                Ok(AppCommandOutcome::DebugProjectionUpdated(projection))
            }
            AppCommandRequest::DebugStep { session_id, kind } => {
                let projection = self.debug_workflow.step(session_id, kind);
                self.persist_latest_debug_audit()?;
                Ok(AppCommandOutcome::DebugProjectionUpdated(projection))
            }
            AppCommandRequest::DebugRunToCursor {
                session_id,
                buffer_id,
                position,
            } => {
                self.active_documents.ensure_active_buffer(buffer_id)?;
                Ok(AppCommandOutcome::DebugProjectionUpdated(
                    self.debug_workflow
                        .run_to_cursor(session_id, buffer_id, position),
                ))
            }
            AppCommandRequest::DebugEvaluateSelection {
                session_id,
                expression_label,
            } => Ok(AppCommandOutcome::DebugProjectionUpdated(
                self.debug_workflow
                    .evaluate_selection(session_id, expression_label),
            )),
            AppCommandRequest::DebugAddWatch {
                session_id,
                expression_label,
            } => Ok(AppCommandOutcome::DebugProjectionUpdated(
                self.debug_workflow.add_watch(session_id, expression_label),
            )),
            AppCommandRequest::ActivateLanguageCodeLens { buffer_id, lens_id } => {
                let projection = self.language_tooling_projection();
                if projection.buffer_id != Some(buffer_id) {
                    return Err(AppCompositionError::BufferMismatch {
                        target: buffer_id,
                        active: projection.buffer_id,
                    });
                }
                let lens = projection
                    .code_lenses
                    .into_iter()
                    .find(|lens| lens.lens_id == lens_id)
                    .ok_or_else(|| {
                        AppCompositionError::LanguageTooling(format!(
                            "code lens {lens_id} not found for buffer {buffer_id:?}"
                        ))
                    })?;
                if !lens.kind_label.contains("runnable") {
                    return Err(AppCompositionError::LanguageTooling(format!(
                        "code lens {lens_id} is not runnable"
                    )));
                }
                let context = self.active_documents.require_workspace_context()?;
                let event_context = self.next_event_context();
                let projection =
                    self.terminal_workflow
                        .launch(context, lens.command_label, event_context);
                self.persist_latest_terminal_audit()?;
                Ok(AppCommandOutcome::TerminalPanelUpdated(projection))
            }
            AppCommandRequest::TerminalLaunch { command_label } => {
                let context = self.active_documents.require_workspace_context()?;
                let event_context = self.next_event_context();
                let projection =
                    self.terminal_workflow
                        .launch(context, command_label, event_context);
                self.persist_latest_terminal_audit()?;
                Ok(AppCommandOutcome::TerminalPanelUpdated(projection))
            }
            AppCommandRequest::TerminalInput {
                session_id,
                payload,
            } => {
                let context = self.active_documents.require_workspace_context()?;
                let event_context = self.next_event_context();
                let projection =
                    self.terminal_workflow
                        .input(context, session_id, payload, event_context);
                self.persist_latest_terminal_audit()?;
                Ok(AppCommandOutcome::TerminalPanelUpdated(projection))
            }
            AppCommandRequest::TerminalResize {
                session_id,
                cols,
                rows,
            } => {
                let context = self.active_documents.require_workspace_context()?;
                let event_context = self.next_event_context();
                let projection =
                    self.terminal_workflow
                        .resize(context, session_id, cols, rows, event_context);
                self.persist_latest_terminal_audit()?;
                Ok(AppCommandOutcome::TerminalPanelUpdated(projection))
            }
            AppCommandRequest::TerminalKill { session_id } => {
                let context = self.active_documents.require_workspace_context()?;
                let event_context = self.next_event_context();
                let projection =
                    self.terminal_workflow
                        .close_or_kill(context, session_id, true, event_context);
                self.persist_latest_terminal_audit()?;
                Ok(AppCommandOutcome::TerminalPanelUpdated(projection))
            }
            AppCommandRequest::TerminalClose { session_id } => {
                let context = self.active_documents.require_workspace_context()?;
                let event_context = self.next_event_context();
                let projection =
                    self.terminal_workflow
                        .close_or_kill(context, session_id, false, event_context);
                self.persist_latest_terminal_audit()?;
                Ok(AppCommandOutcome::TerminalPanelUpdated(projection))
            }
            AppCommandRequest::TerminalOutputPoll { session_id } => {
                let event_context = self.next_event_context();
                let projection = self.terminal_workflow.poll(session_id, event_context);
                self.persist_latest_terminal_audit()?;
                Ok(AppCommandOutcome::TerminalPanelUpdated(projection))
            }
            AppCommandRequest::TerminalSearch { session_id, query } => {
                let event_context = self.next_event_context();
                let projection = self
                    .terminal_workflow
                    .search(session_id, query, event_context);
                self.persist_latest_terminal_audit()?;
                Ok(AppCommandOutcome::TerminalPanelUpdated(projection))
            }
            AppCommandRequest::OpenPath { path } => {
                Ok(AppCommandOutcome::Opened(self.open_file(path)?))
            }
            AppCommandRequest::OpenPathAtPosition { path, position } => {
                let outcome = self.open_file(path)?;
                if let Some(buffer_id) = self.active_documents.active_buffer_id {
                    self.set_buffer_cursor(buffer_id, position)?;
                }
                Ok(AppCommandOutcome::Opened(outcome))
            }
            AppCommandRequest::StartAiRun { instruction_label } => Ok(
                AppCommandOutcome::AiRunStarted(Box::new(self.start_ai_run(instruction_label)?)),
            ),
            AppCommandRequest::StartAiExplain { instruction_label } => {
                Ok(AppCommandOutcome::AiRunStarted(Box::new(
                    self.start_ai_explain(instruction_label)?,
                )))
            }
            AppCommandRequest::StartAiProposal { instruction_label } => {
                Ok(AppCommandOutcome::AiRunStarted(Box::new(
                    self.start_ai_proposal(instruction_label)?,
                )))
            }
            AppCommandRequest::SendDelegateChat { prompt_label } => {
                Ok(AppCommandOutcome::DelegateChatCompleted(Box::new(
                    self.send_delegate_chat(prompt_label)?,
                )))
            }
            AppCommandRequest::ReviewDelegateProposalHunk {
                proposal_id,
                hunk_id,
                disposition,
            } => Ok(AppCommandOutcome::DelegateProposalHunkReviewed(
                self.review_delegate_proposal_hunk(proposal_id, hunk_id, disposition)?,
            )),
            AppCommandRequest::RecordDelegateToolPermission {
                request_id,
                decision,
            } => Ok(AppCommandOutcome::DelegateToolPermissionRecorded(
                self.record_delegate_tool_permission_decision(request_id, decision)?,
            )),
            AppCommandRequest::RecordLegionWorkflowToolPermission {
                session_id,
                server_id,
                tool_name,
                decision,
            } => Ok(AppCommandOutcome::LegionWorkflowUpdated(
                self.record_legion_workflow_tool_permission_decision(
                    &session_id,
                    &server_id,
                    &tool_name,
                    decision,
                )?,
            )),
            AppCommandRequest::TriggerLegionWorkflowKillSwitch {
                session_id,
                reason_label,
            } => Ok(AppCommandOutcome::LegionWorkflowUpdated(
                self.trigger_legion_workflow_kill_switch(
                    &session_id,
                    PrincipalId("user:local".to_string()),
                    reason_label,
                )?,
            )),
            AppCommandRequest::CancelAiRun { run_id } => {
                self.cancel_ai_run(run_id.clone())?;
                Ok(AppCommandOutcome::AiRunCancelled(run_id))
            }
            AppCommandRequest::ReplayAiRun { run_id } => Ok(AppCommandOutcome::AiRunReplayed(
                Box::new(self.replay_ai_run(run_id)?),
            )),
            AppCommandRequest::InspectAiRun { run_id } => Ok(AppCommandOutcome::AiRunInspected(
                Box::new(self.inspect_ai_run(run_id)?),
            )),
            AppCommandRequest::InvokePluginCommand {
                plugin_id,
                command_id,
                metadata_label,
            } => Ok(AppCommandOutcome::PluginCommandInvoked(Box::new(
                self.invoke_plugin_command(plugin_id, command_id, metadata_label)?,
            ))),
            AppCommandRequest::JoinCollaborationSession { session_id } => {
                self.join_collaboration_session(session_id)?;
                Ok(AppCommandOutcome::CollaborationSessionJoined(session_id))
            }
            AppCommandRequest::LeaveCollaborationSession { session_id } => {
                self.leave_collaboration_session(session_id)?;
                Ok(AppCommandOutcome::CollaborationSessionLeft(session_id))
            }
            AppCommandRequest::PublishCollaborationPresence {
                session_id,
                participant_id,
            } => {
                self.publish_collaboration_presence(session_id, participant_id)?;
                Ok(AppCommandOutcome::CollaborationPresencePublished(
                    session_id,
                ))
            }
            _ => unreachable!("command execution service handled non-workflow command"),
        }
    }

    /// Load a Phase 5 plugin manifest after app-level trust and manifest validation.
    pub fn load_plugin_manifest(
        &mut self,
        manifest: PluginManifest,
    ) -> Result<PluginId, AppCompositionError> {
        let projection = PluginContributionProjection {
            plugin_id: manifest.plugin_id,
            contributions: manifest.contributions.clone(),
            permission_review_rows: manifest
                .requested_capabilities
                .iter()
                .enumerate()
                .map(|(index, capability)| {
                    format!(
                        "permission review {}: capability={}",
                        index + 1,
                        capability.0
                    )
                })
                .collect(),
            status_label: "loaded".to_string(),
        };
        let plugin_id = self
            .plugin_runtime
            .load_manifest(manifest.clone())
            .map_err(AppCompositionError::Protocol)?;
        register_plugin_tree_sitter_grammars(plugin_id, &manifest.contributions);
        self.plugin_contribution_projections.push(projection);
        Ok(plugin_id)
    }

    /// Invoke a Phase 5 plugin command through protocol host-call envelopes only.
    pub fn invoke_plugin_command(
        &mut self,
        plugin_id: PluginId,
        command_id: impl Into<String>,
        metadata_label: impl Into<String>,
    ) -> Result<PluginHostCallResponse, AppCompositionError> {
        let command_id = command_id.into();
        let event_context = self.next_event_context();
        let sequence = self.event_sequence_generator.next();
        let response = self
            .plugin_runtime
            .dispatch_host_call(PluginHostCallRequest {
                plugin_id,
                kind: PluginHostCallKind::ReadOnlyContext,
                host_call_name: format!("command:{command_id}"),
                declared_capability: CapabilityId("plugin.command".to_string()),
                correlation_id: event_context.correlation_id,
                causality_id: event_context.causality_id,
                sequence,
                metadata_label: metadata_label.into(),
            })
            .map_err(AppCompositionError::Protocol)?;
        let envelope = plugin_event_envelope(
            legion_protocol::EventId(uuid::Uuid::now_v7()),
            plugin_id,
            "plugin.command_invoked",
            event_context.correlation_id,
            event_context.causality_id,
            sequence,
            TimestampMillis::now(),
        )
        .map_err(|err| {
            AppCompositionError::Protocol(ProtocolError {
                code: "plugin_event_invalid".to_string(),
                message: err.to_string(),
            })
        })?;
        self.emit_event(envelope);
        Ok(response)
    }

    /// Enable local deterministic collaboration runtime for trusted app-owned sessions.
    pub fn enable_local_collaboration_runtime(&mut self) {
        self.collaboration.runtime_sessions_enabled = true;
        self.collaboration.presence_enabled = true;
    }

    /// Create or join a local collaboration session bound to the active editor buffer.
    pub fn join_collaboration_session(
        &mut self,
        session_id: CollaborationSessionId,
    ) -> Result<(), AppCompositionError> {
        if !self.collaboration.runtime_sessions_enabled {
            return Err(AppCompositionError::Collaboration(
                "collaboration runtime sessions are disabled by policy".to_string(),
            ));
        }
        let context = self.active_documents.require_active_save_context()?;
        if context.trust != WorkspaceTrustState::Trusted {
            return Err(AppCompositionError::Collaboration(
                "untrusted workspaces cannot join collaboration sessions".to_string(),
            ));
        }
        if self.collaboration.sessions.contains_key(&session_id) {
            return Ok(());
        }
        let snapshot = self.editor.current_snapshot(context.buffer_id)?.clone();
        let descriptor = CollaborationSessionDescriptor {
            session_id,
            workspace_id: context.workspace_id,
            state: CollaborationSessionState::Active,
            created_by: context.principal.clone(),
            created_at: TimestampMillis::now(),
            document_bindings: vec![CollaborationDocumentBinding {
                workspace_id: context.workspace_id,
                file_id: context.metadata.identity.file_id,
                buffer_id: context.buffer_id,
                snapshot_id: snapshot.snapshot_id,
                buffer_version: snapshot.buffer_version,
                document_epoch: CollaborationDocumentEpoch(1),
                content_fingerprint: Some(FileFingerprint {
                    algorithm: "legion-text-snapshot".to_string(),
                    value: snapshot.content_hash,
                }),
                schema_version: 1,
            }],
            redaction_hints: vec![RedactionHint::MetadataOnly],
            schema_version: 1,
        };
        let participant = CollaborationParticipant {
            session_id,
            participant_id: CollaborationParticipantId(1),
            principal_id: context.principal,
            role: CollaborationParticipantRole::Owner,
            permissions: vec![
                CollaborationPermission::CreateSession,
                CollaborationPermission::JoinSession,
                CollaborationPermission::PublishOperation,
                CollaborationPermission::PublishPresence,
                CollaborationPermission::ApproveSharedProposal,
                CollaborationPermission::ReplayMetadata,
                CollaborationPermission::ExportAudit,
            ],
            display_label: "local participant".to_string(),
            schema_version: 1,
        };
        let runtime = CollaborationSessionRuntime::new(
            descriptor,
            vec![participant],
            "",
            CollaborationRuntimeConfig::enabled(),
        )
        .map_err(|error| AppCompositionError::Collaboration(error.to_string()))?;
        self.collaboration.sessions.insert(session_id, runtime);
        Ok(())
    }

    /// Leave a local collaboration session without mutating editor text.
    pub fn leave_collaboration_session(
        &mut self,
        session_id: CollaborationSessionId,
    ) -> Result<(), AppCompositionError> {
        if let Some(runtime) = self.collaboration.sessions.get_mut(&session_id) {
            runtime.begin_shutdown();
            runtime.finish_shutdown();
        }
        self.collaboration.sessions.remove(&session_id);
        Ok(())
    }

    /// Publish metadata-only collaboration presence through app-owned runtime state.
    pub fn publish_collaboration_presence(
        &mut self,
        session_id: CollaborationSessionId,
        participant_id: CollaborationParticipantId,
    ) -> Result<(), AppCompositionError> {
        if !self.collaboration.presence_enabled {
            return Err(AppCompositionError::Collaboration(
                "collaboration presence is disabled by policy".to_string(),
            ));
        }
        let runtime = self
            .collaboration
            .sessions
            .get_mut(&session_id)
            .ok_or_else(|| {
                AppCompositionError::Collaboration("collaboration session is missing".to_string())
            })?;
        runtime
            .publish_presence(CollaborationPresenceProjection {
                session_id,
                participant_id,
                cursor: None,
                selections: Vec::new(),
                activity_label: Some("active".to_string()),
                reconnecting: false,
                schema_version: 1,
            })
            .map_err(|error| AppCompositionError::Collaboration(error.to_string()))?;
        Ok(())
    }

    /// Receive a deterministic local transport envelope and apply accepted operations through editor authority.
    pub fn receive_collaboration_transport_envelope(
        &mut self,
        envelope: CollaborationTransportEnvelope,
    ) -> Result<Option<AppCommandOutcome>, AppCompositionError> {
        let operation = match &envelope.payload {
            CollaborationTransportPayload::Operation(operation) => Some((**operation).clone()),
            _ => None,
        };
        let runtime = self
            .collaboration
            .sessions
            .get_mut(&envelope.session_id)
            .ok_or_else(|| {
                AppCompositionError::Collaboration("collaboration session is missing".to_string())
            })?;
        let outcome = runtime
            .handle_transport_envelope(envelope)
            .map_err(|error| AppCompositionError::Collaboration(error.to_string()))?;

        let Some(operation) = operation else {
            return Ok(None);
        };
        let Some(outcome) = outcome else {
            return Ok(None);
        };
        if outcome.acknowledgement.status
            != legion_protocol::CollaborationAcknowledgementStatus::Accepted
        {
            return Ok(None);
        }
        let descriptor = self.apply_collaboration_operation_through_editor(operation)?;
        self.emit_transaction_event(&descriptor);
        let audit = self.collaboration_audit_record(Some(descriptor.correlation_id), None, None)?;
        self.persist_collaboration_audit(audit)?;
        Ok(Some(AppCommandOutcome::CollaborationOperationApplied(
            descriptor,
        )))
    }

    fn apply_collaboration_operation_through_editor(
        &mut self,
        operation: CollaborationDocumentOperation,
    ) -> Result<TextTransactionDescriptor, AppCompositionError> {
        let replacement = match operation.kind {
            CollaborationDocumentOperationKind::Insert { text }
            | CollaborationDocumentOperationKind::Replace { text } => text,
            CollaborationDocumentOperationKind::Delete => String::new(),
            _ => {
                return Err(AppCompositionError::Collaboration(
                    "operation has no text mutation".to_string(),
                ));
            }
        };
        let range = operation.range.ok_or_else(|| {
            AppCompositionError::Collaboration("text operation requires a range".to_string())
        })?;
        let record = self
            .editor
            .apply_protocol_edits(EditorApplyTransactionRequest {
                workspace_id: operation.preconditions.workspace_id,
                buffer_id: operation.preconditions.buffer_id,
                file_id: operation.preconditions.file_id,
                edits: legion_protocol::EditBatch {
                    edits: vec![legion_protocol::TextEdit { range, replacement }],
                },
                source: TransactionSource::CollaborationParticipant {
                    session_id: operation.session_id,
                    participant_id: operation.author_participant_id,
                    operation_id: operation.operation_id,
                },
                undo_group_id: operation.undo_group.map(|group| group.group_id),
                correlation_id: operation.preconditions.correlation_id,
            })?;
        Ok(record.to_protocol_descriptor())
    }

    fn collaboration_audit_record(
        &mut self,
        correlation_id: Option<CorrelationId>,
        operation_id: Option<legion_protocol::CollaborationOperationId>,
        proposal_id: Option<ProposalId>,
    ) -> Result<CollaborationAuditRecord, AppCompositionError> {
        let session = self.collaboration.sessions.values().next().ok_or_else(|| {
            AppCompositionError::Collaboration("collaboration session is missing".to_string())
        })?;
        Ok(session.audit_record(
            operation_id,
            proposal_id,
            self.event_sequence_generator.next(),
            correlation_id.unwrap_or_else(|| self.correlation_generator.next()),
        ))
    }

    fn persist_collaboration_audit(
        &self,
        record: CollaborationAuditRecord,
    ) -> Result<(), AppCompositionError> {
        self.storage
            .handle(StorageRepositoryRequest::SaveCollaborationAuditRecord(
                record.clone(),
            ))
            .map_err(AppCompositionError::Protocol)?;
        let envelope = collaboration_audit_recorded_event(&record)
            .map_err(|error| AppCompositionError::Collaboration(error.to_string()))?;
        self.emit_event(envelope);
        Ok(())
    }

    /// Enable deterministic Phase 7 remote development runtime for app-owned sessions.
    pub fn enable_remote_development_runtime(&mut self) {
        self.remote.enable();
    }

    /// Connect a remote workspace session through app-owned composition.
    pub fn connect_remote_workspace_session(
        &mut self,
        session_id: RemoteWorkspaceSessionId,
        authority_label: impl Into<String>,
    ) -> Result<RemoteWorkspaceSessionDescriptor, AppCompositionError> {
        if !self.remote.runtime_sessions_enabled {
            return Err(AppCompositionError::Remote(
                "remote runtime sessions are disabled by policy".to_string(),
            ));
        }
        let context = self.active_documents.require_workspace_context()?;
        if context.trust != WorkspaceTrustState::Trusted {
            return Err(AppCompositionError::Remote(
                "untrusted workspaces cannot connect remote sessions".to_string(),
            ));
        }

        let spec = self.remote_connection_spec(
            session_id,
            authority_label.into(),
            "legion-remote-ssh-agent/1".to_string(),
        )?;
        let plan = plan_ssh_session(spec).map_err(remote_error)?;
        let descriptor = plan.descriptor;
        self.remote
            .runtime
            .create_session(descriptor.clone(), context.workspace_generation)
            .map_err(|error| AppCompositionError::Remote(error.to_string()))?;
        Ok(descriptor)
    }

    /// Connect a devcontainer remote workspace session through app-owned composition.
    pub fn connect_devcontainer_workspace_session_from_json(
        &mut self,
        session_id: RemoteWorkspaceSessionId,
        authority_label: impl Into<String>,
        devcontainer_json: &str,
    ) -> Result<RemoteWorkspaceSessionDescriptor, AppCompositionError> {
        if !self.remote.runtime_sessions_enabled {
            return Err(AppCompositionError::Remote(
                "remote runtime sessions are disabled by policy".to_string(),
            ));
        }
        let context = self.active_documents.require_workspace_context()?;
        if context.trust != WorkspaceTrustState::Trusted {
            return Err(AppCompositionError::Remote(
                "untrusted workspaces cannot connect remote sessions".to_string(),
            ));
        }
        let spec = self.remote_connection_spec(
            session_id,
            authority_label.into(),
            "legion-remote-devcontainer-agent/1".to_string(),
        )?;
        let plan =
            plan_devcontainer_session_from_json(spec, devcontainer_json).map_err(remote_error)?;
        let descriptor = plan.descriptor;
        self.remote
            .runtime
            .create_session(descriptor.clone(), context.workspace_generation)
            .map_err(|error| AppCompositionError::Remote(error.to_string()))?;
        Ok(descriptor)
    }

    fn remote_connection_spec(
        &self,
        session_id: RemoteWorkspaceSessionId,
        authority_label: String,
        agent_version: String,
    ) -> Result<RemoteConnectionSpec, AppCompositionError> {
        let context = self.active_documents.require_workspace_context()?;
        let authority_id = legion_protocol::RemoteAuthorityId(session_id.0.saturating_add(100));
        let credential_reference_label = format!(
            "credential-ref:{}",
            metadata_fingerprint("remote-authority", &authority_label).value
        );
        Ok(RemoteConnectionSpec {
            session_id,
            authority_id,
            agent_id: legion_protocol::RemoteAgentId(session_id.0.saturating_add(200)),
            workspace_id: context.workspace_id,
            principal_id: context.principal,
            authority_label,
            workspace_root_label: self
                .active_documents
                .workspace_root_path
                .clone()
                .unwrap_or_else(|| "workspace".to_string()),
            credential_reference_label,
            agent_version,
            trust_state: context.trust,
            granted_capabilities: default_remote_capabilities(),
        })
    }

    /// Return projection-safe remote session descriptors.
    pub fn remote_session_projections(&self) -> Vec<RemoteWorkspaceSessionDescriptor> {
        self.remote.session_descriptors()
    }

    /// Enable the app-owned deterministic Legion Cloud Lane runtime envelope.
    pub fn enable_legion_cloud_lane_runtime(
        &mut self,
        endpoint: &str,
        max_cost_cents: u32,
        max_upload_bytes: u64,
    ) -> Result<(), AppCompositionError> {
        self.require_automate_mode()?;
        self.legion_cloud_lane
            .enable(endpoint, max_cost_cents, max_upload_bytes)
    }

    /// Submit a metadata-only Legion Cloud Lane task and project its status.
    pub fn submit_legion_cloud_lane_task(
        &mut self,
        request: LegionCloudLaneTaskRequest,
    ) -> Result<LegionCloudLaneTaskStatus, AppCompositionError> {
        self.require_automate_mode()?;
        let context = self.active_documents.require_workspace_context()?;
        if request.task_packet.workspace_id != context.workspace_id {
            return Err(AppCompositionError::Remote(
                "cloud lane task workspace does not match active workspace".to_string(),
            ));
        }
        let event_sequence = self.event_sequence_generator.next();
        self.legion_cloud_lane
            .submit_task(request, &context, event_sequence)
    }

    /// Return the current metadata-only Legion Cloud Lane projection.
    pub fn legion_cloud_lane_projection(&self) -> LegionCloudLaneProjection {
        let projection = self.legion_cloud_lane.projection(TimestampMillis::now());
        let validation = validate_legion_cloud_lane_projection(&projection);
        debug_assert!(validation.is_ok());
        projection
    }

    /// Replace delegated-task plan contracts used for projection-only command-center surfaces.
    pub fn seed_delegated_task_plan_contracts(&mut self, plans: Vec<DelegatedTaskPlanContract>) {
        self.delegated_task_plan_contracts = plans
            .into_iter()
            .filter(|plan| !plan.plan_id.0.trim().is_empty())
            .collect();
    }

    /// Executes a delegated task plan contract, running it in an isolated sandbox,
    /// enforcing security policies, and emitting mutation-safe edit proposals.
    pub fn execute_delegated_task(
        &mut self,
        plan_id: &legion_protocol::DelegatedTaskPlanId,
    ) -> Result<AppDelegatedTaskExecutionOutcome, AppCompositionError> {
        self.require_delegate_mode()?;
        let Some(contract) = self
            .delegated_task_plan_contracts
            .iter()
            .find(|plan| plan.plan_id == *plan_id)
            .cloned()
        else {
            return Ok(AppDelegatedTaskExecutionOutcome::PlanMissing {
                plan_id: plan_id.clone(),
            });
        };

        let request_id = delegated_runtime_permission_request_id(plan_id);
        let permission = self
            .delegate_workflow
            .tool_permission(&request_id)
            .cloned()
            .unwrap_or_else(|| {
                self.delegate_workflow.record_tool_permission_decision(
                    DelegatedTaskToolPermissionRequestInput {
                        request_id,
                        profile: DelegatedTaskToolPermissionProfile::Write,
                        action_class: PermissionBudgetActionClass::AccessWorkspaceFiles,
                        capability: Some(CapabilityId("delegated.runtime.allocate".to_string())),
                        target_id: Some(plan_id.0.clone()),
                        decision: DelegatedTaskToolPermissionDecision::Confirm,
                        labels: delegated_runtime_permission_labels(plan_id),
                        schema_version: 1,
                    },
                )
            });
        if permission.deny_overrides {
            self.delegate_workflow
                .set_runtime_activation(DelegatedTaskRuntimeActivationState::Blocked);
            return Ok(AppDelegatedTaskExecutionOutcome::Denied {
                request: permission,
            });
        }
        if !permission.runtime_allowed {
            self.delegate_workflow
                .set_runtime_activation(DelegatedTaskRuntimeActivationState::Planned);
            return Ok(AppDelegatedTaskExecutionOutcome::WaitingForToolPermission {
                request: permission,
            });
        }

        let event_context = self.next_event_context();
        let correlation_id = event_context.correlation_id;
        let causality_id = event_context.causality_id;
        let event_sequence = self.event_sequence_generator.next();

        if correlation_id.0 == 0 {
            return Err(AppCompositionError::AiRuntime(
                "Assisted AI requires non-zero correlation id".to_string(),
            ));
        }
        if causality_id.0.is_nil() {
            return Err(AppCompositionError::AiRuntime(
                "Assisted AI requires non-nil causality id".to_string(),
            ));
        }

        // 1. Initialize Agent Runtime and transition state
        let run_id = legion_protocol::AgentRunId(format!("run-{}", plan_id.0));
        let mut agent_runtime = AgentRuntime::new(run_id);

        // Observing -> Planning
        agent_runtime
            .transition(
                legion_protocol::AgentRunState::Planning,
                "task.start",
                correlation_id,
                causality_id,
                event_sequence,
            )
            .map_err(|e| AppCompositionError::AiRuntime(e.to_string()))?;

        // Planning -> Proposing
        agent_runtime
            .transition(
                legion_protocol::AgentRunState::Proposing,
                "task.propose",
                correlation_id,
                causality_id,
                self.event_sequence_generator.next(),
            )
            .map_err(|e| AppCompositionError::AiRuntime(e.to_string()))?;

        // 2. Setup isolated sandbox orchestrator
        let mut orchestrator = DelegatedTaskSandboxOrchestrator::new(&plan_id.0);
        orchestrator.initialize(&permission).map_err(|e| {
            AppCompositionError::AiRuntime(format!("Failed to initialize sandbox: {e}"))
        })?;
        self.delegate_workflow
            .set_runtime_activation(DelegatedTaskRuntimeActivationState::SandboxAllocated);
        let sandbox_path = orchestrator.sandbox_path().to_path_buf();

        let target_file = sandbox_path.join(delegated_task_proposal_relative_path(&contract));
        let target_file_absolute = std::env::current_dir().unwrap().join(&target_file);
        let mut proposal_content = delegated_task_proposal_content(&contract, &permission);
        let proposal_id = self.proposal_coordinator.next_id();
        let proposal_event_sequence = self.event_sequence_generator.next();
        let principal = self
            .active_documents
            .active_principal_id
            .clone()
            .unwrap_or_else(|| PrincipalId(format!("delegate-plan:{}", contract.plan_id.0)));
        let capability = permission
            .capability
            .clone()
            .unwrap_or_else(|| CapabilityId("delegated.runtime.allocate".to_string()));
        let context_manifest = contract.context_manifest.clone().unwrap_or_else(|| {
            trust_reference(
                &format!("delegate:plan-context:{}", contract.plan_id.0),
                legion_protocol::AssistedAiTrustProjectionKind::ContextManifest,
            )
        });
        let approval_checklist = contract.approval_checklist.clone().unwrap_or_else(|| {
            trust_reference(
                &format!("delegate:plan-approval:{}", contract.plan_id.0),
                legion_protocol::AssistedAiTrustProjectionKind::ProposalApprovalChecklist,
            )
        });

        if let Some(acp_host_command) = self.acp_host_command.as_ref() {
            let _connect_message_id = self.delegate_workflow.record_system_message(
                format!(
                    "acp.host.connect program={}",
                    acp_host_command.program.display()
                ),
                Some(contract.plan_id.clone()),
                None,
                correlation_id,
                causality_id,
            );
            let host_output = match acp_host_command.run(
                &sandbox_path,
                &target_file_absolute,
                &contract.plan_id.0,
            ) {
                Ok(output) => output,
                Err(e) => {
                    // The sandbox was already allocated; clean it up before the
                    // early return and surface any cleanup failure alongside the
                    // original error.
                    let message = match orchestrator.cleanup(&permission) {
                        Ok(()) => format!("ACP host command failed to start: {e}"),
                        Err(cleanup_err) => format!(
                            "ACP host command failed to start: {e}; additionally sandbox cleanup failed: {cleanup_err}"
                        ),
                    };
                    return Err(AppCompositionError::AiRuntime(message));
                }
            };
            let stdout_label = String::from_utf8_lossy(&host_output.stdout);
            let stderr_label = String::from_utf8_lossy(&host_output.stderr);
            let _spawn_message_id = self.delegate_workflow.record_system_message(
                format!(
                    "acp.host.spawn status={} stdout_bytes={} stderr_bytes={}",
                    host_output.status,
                    host_output.stdout.len(),
                    host_output.stderr.len()
                ),
                Some(contract.plan_id.clone()),
                None,
                correlation_id,
                causality_id,
            );
            if !host_output.status.success() {
                let _terminate_message_id = self.delegate_workflow.record_system_message(
                    format!(
                        "acp.host.terminate failure stdout={} stderr={}",
                        stdout_label.trim(),
                        stderr_label.trim()
                    ),
                    Some(contract.plan_id.clone()),
                    None,
                    correlation_id,
                    causality_id,
                );
                let cleanup_res = orchestrator.cleanup(&permission);
                cleanup_res.map_err(|e| {
                    AppCompositionError::AiRuntime(format!("Sandbox cleanup failed: {e}"))
                })?;
                return Err(AppCompositionError::AiRuntime(format!(
                    "ACP host command exited unsuccessfully: {}",
                    stderr_label.trim()
                )));
            }
            proposal_content = match std::fs::read_to_string(&target_file_absolute) {
                Ok(content) => content,
                Err(e) => {
                    // Clean up the allocated sandbox before the early return and
                    // surface any cleanup failure alongside the original error.
                    let message = match orchestrator.cleanup(&permission) {
                        Ok(()) => format!("Failed to read ACP host proposal: {e}"),
                        Err(cleanup_err) => format!(
                            "Failed to read ACP host proposal: {e}; additionally sandbox cleanup failed: {cleanup_err}"
                        ),
                    };
                    return Err(AppCompositionError::AiRuntime(message));
                }
            };
        }

        let generator = DelegatedTaskProposalGenerator::new(sandbox_path.clone());
        let proposal_result = generator.generate_proposal(DelegatedTaskProposalInput {
            target_path: &target_file,
            modified_content: &proposal_content,
            output_id: format!(
                "delegate-output:{}:{}",
                contract.plan_id.0, proposal_event_sequence.0
            ),
            request_id: permission.request_id.clone(),
            provider_id: DETERMINISTIC_LOCAL_PROVIDER_ID.to_string(),
            proposal_id,
            principal,
            capability,
            correlation_id,
            causality_id,
            created_at: TimestampMillis::now(),
            context_manifest,
            approval_checklist,
        });

        // Cleanup orchestrator immediately (fail-closed resource safety)
        let cleanup_res = orchestrator.cleanup(&permission);

        let proposal = proposal_result.map_err(|e| {
            AppCompositionError::AiRuntime(format!("Proposal generation failed: {e}"))
        })?;
        cleanup_res
            .map_err(|e| AppCompositionError::AiRuntime(format!("Sandbox cleanup failed: {e}")))?;

        if self.acp_host_command.is_some() {
            self.delegate_workflow.record_system_message(
                format!(
                    "acp.host.terminate success proposal={} sandbox={}",
                    proposal.proposal_id.0,
                    sandbox_path.display()
                ),
                Some(contract.plan_id.clone()),
                Some(proposal.proposal_id),
                correlation_id,
                causality_id,
            );
        }

        // Proposing -> WaitingForApproval
        agent_runtime
            .transition(
                legion_protocol::AgentRunState::WaitingForApproval,
                "task.waiting_for_approval",
                correlation_id,
                causality_id,
                self.event_sequence_generator.next(),
            )
            .map_err(|e| AppCompositionError::AiRuntime(e.to_string()))?;
        self.delegate_workflow
            .set_runtime_activation(DelegatedTaskRuntimeActivationState::WaitingForApproval);

        Ok(AppDelegatedTaskExecutionOutcome::ProposalReady(Box::new(
            proposal,
        )))
    }

    /// Replace app-owned Legion workflow session metadata for tests and smoke harnesses.
    pub fn seed_legion_workflow_sessions(
        &mut self,
        sessions: Vec<LegionWorkflowSession>,
    ) -> Result<(), AppCompositionError> {
        let mut seen = HashSet::new();
        let mut valid_sessions = Vec::new();
        for session in sessions {
            if session.session_id.0.trim().is_empty()
                || session.schema_version == 0
                || session.correlation_id.0 == 0
                || session.causality_id.0.is_nil()
                || legion_protocol::validate_legion_workflow_session(&session).is_err()
            {
                continue;
            }
            if !seen.insert(session.session_id.0.clone()) {
                return Err(AppCompositionError::LegionWorkflow(format!(
                    "duplicate workflow session {}",
                    session.session_id.0
                )));
            }
            valid_sessions.push(session);
        }
        self.legion_workflow_sessions = valid_sessions;
        Ok(())
    }

    /// Returns a metadata-only Legion workflow projection owned by the app layer.
    pub fn legion_workflow_projection(
        &self,
        generated_at: TimestampMillis,
    ) -> LegionWorkflowProjection {
        let mut projection = legion_protocol::legion_workflow_projection_from_sessions(
            "legion-workflow:app-command-center",
            &self.legion_workflow_sessions,
            generated_at,
            64,
            1,
        );
        self.automate_workflow.apply_to_projection(&mut projection);
        projection
    }

    /// Seed app-owned MCP registry metadata for Automate command centers and tool gating.
    pub fn seed_legion_workflow_mcp_registry(
        &mut self,
        registry: McpRegistrySnapshot,
    ) -> Result<LegionWorkflowProjection, AppCompositionError> {
        self.require_automate_mode()?;
        validate_mcp_registry_snapshot(&registry)
            .map_err(|error| AppCompositionError::LegionWorkflow(error.message))?;
        self.automate_workflow.seed_mcp_registry(registry);
        Ok(self.legion_workflow_projection(TimestampMillis::now()))
    }

    /// Register an app-owned MCP runtime used by Automate fleet workers.
    pub fn register_legion_workflow_mcp_tool_runtime(
        &mut self,
        server_id: McpServerId,
        runtime: Arc<dyn AppAutomateMcpToolRuntime>,
    ) -> Result<(), AppCompositionError> {
        if server_id.0.trim().is_empty() {
            return Err(AppCompositionError::LegionWorkflow(
                "MCP server id must be non-empty".to_string(),
            ));
        }
        self.automate_mcp_tool_runtimes.insert(server_id.0, runtime);
        Ok(())
    }

    /// Apply an MCP list-changed notification and surface a decision-feed entry.
    pub fn apply_legion_workflow_mcp_list_changed(
        &mut self,
        session_id: &LegionWorkflowSessionId,
        server_id: &McpServerId,
        kind: McpListChangedKind,
    ) -> Result<LegionWorkflowProjection, AppCompositionError> {
        self.require_automate_mode()?;
        self.legion_workflow_session(session_id).ok_or_else(|| {
            AppCompositionError::LegionWorkflow(format!(
                "workflow session {} not found",
                session_id.0
            ))
        })?;
        if !self
            .automate_workflow
            .apply_mcp_list_changed(server_id, kind, TimestampMillis::now())
        {
            return Err(AppCompositionError::LegionWorkflow(format!(
                "MCP server {} not found",
                server_id.0
            )));
        }
        let event_context = self.next_event_context();
        self.automate_workflow
            .record_decision(AutomateDecisionInput {
                session_id: session_id.clone(),
                worker_id: None,
                kind: LegionWorkflowDecisionKind::McpRegistryReloaded,
                summary_label: format!("MCP registry list changed: {}", kind.method()),
                risk_label: ProposalRiskLabel::Medium,
                mcp_server_id: Some(server_id.clone()),
                mcp_primitive_kind: None,
                tool_permission_request_id: None,
                event_context,
                event_sequence: self.event_sequence_generator.next(),
            })?;
        self.automate_workflow.risk_monitor(session_id, None)?;
        Ok(self.legion_workflow_projection(TimestampMillis::now()))
    }

    /// Record an Automate MCP tool permission decision.
    pub fn record_legion_workflow_tool_permission_decision(
        &mut self,
        session_id: &LegionWorkflowSessionId,
        server_id: &McpServerId,
        tool_name: &McpToolName,
        decision: DelegatedTaskToolPermissionDecision,
    ) -> Result<LegionWorkflowProjection, AppCompositionError> {
        self.require_automate_mode()?;
        self.legion_workflow_session(session_id).ok_or_else(|| {
            AppCompositionError::LegionWorkflow(format!(
                "workflow session {} not found",
                session_id.0
            ))
        })?;
        let tool = self
            .automate_workflow
            .mcp_tool(server_id, tool_name)
            .cloned()
            .ok_or_else(|| {
                AppCompositionError::LegionWorkflow(format!(
                    "MCP tool {} not found on server {}",
                    tool_name.0, server_id.0
                ))
            })?;
        let request_id = automate_tool_permission_request_id(session_id, server_id, tool_name);
        if self
            .automate_workflow
            .tool_permission(&request_id)
            .is_none()
        {
            return Err(AppCompositionError::LegionWorkflow(format!(
                "MCP tool permission request {request_id} has not been projected"
            )));
        }
        let request = self
            .automate_workflow
            .record_tool_permission_decision(session_id, request_id, &tool, decision);
        if request.deny_overrides {
            *self
                .automate_workflow
                .denied_tool_count
                .entry(session_id.0.clone())
                .or_insert(0) += 1;
        }
        let event_context = self.next_event_context();
        self.automate_workflow
            .record_decision(AutomateDecisionInput {
                session_id: session_id.clone(),
                worker_id: None,
                kind: if request.deny_overrides {
                    LegionWorkflowDecisionKind::ToolCallDenied
                } else {
                    LegionWorkflowDecisionKind::ToolApprovalRequested
                },
                summary_label: format!(
                    "MCP tool permission {:?}: {}",
                    request.decision, request.request_id
                ),
                risk_label: if request.deny_overrides {
                    ProposalRiskLabel::High
                } else {
                    ProposalRiskLabel::Medium
                },
                mcp_server_id: Some(server_id.clone()),
                mcp_primitive_kind: Some(McpPrimitiveKind::Tool),
                tool_permission_request_id: Some(request.request_id.clone()),
                event_context,
                event_sequence: self.event_sequence_generator.next(),
            })?;
        self.automate_workflow.risk_monitor(session_id, None)?;
        Ok(self.legion_workflow_projection(TimestampMillis::now()))
    }

    /// Prepare an Automate MCP tool call without invoking it until permission and risk checks pass.
    pub fn prepare_legion_workflow_mcp_tool_call(
        &mut self,
        session_id: &LegionWorkflowSessionId,
        server_id: &McpServerId,
        tool_name: &McpToolName,
    ) -> Result<AppAutomateToolCallOutcome, AppCompositionError> {
        self.require_automate_mode()?;
        self.legion_workflow_session(session_id).ok_or_else(|| {
            AppCompositionError::LegionWorkflow(format!(
                "workflow session {} not found",
                session_id.0
            ))
        })?;
        let tool = self
            .automate_workflow
            .mcp_tool(server_id, tool_name)
            .cloned()
            .ok_or_else(|| {
                AppCompositionError::LegionWorkflow(format!(
                    "MCP tool {} not found on server {}",
                    tool_name.0, server_id.0
                ))
            })?;
        let risk = tool.risk_label;
        let request_id = automate_tool_permission_request_id(session_id, server_id, tool_name);
        if matches!(risk, ProposalRiskLabel::High | ProposalRiskLabel::Unknown)
            && self
                .automate_workflow
                .counted_high_risk_tool_requests
                .insert(request_id.clone())
        {
            *self
                .automate_workflow
                .high_risk_tool_count
                .entry(session_id.0.clone())
                .or_insert(0) += 1;
        }
        let monitor = self.automate_workflow.risk_monitor(session_id, None)?;
        if monitor.state == LegionWorkflowRiskMonitorState::Halted
            || self.automate_workflow.kill_switch_triggered(session_id)
        {
            let event_context = self.next_event_context();
            self.automate_workflow
                .record_decision(AutomateDecisionInput {
                    session_id: session_id.clone(),
                    worker_id: None,
                    kind: LegionWorkflowDecisionKind::RiskMonitorHalted,
                    summary_label: "MCP tool call halted by Automate risk monitor".to_string(),
                    risk_label: ProposalRiskLabel::High,
                    mcp_server_id: Some(server_id.clone()),
                    mcp_primitive_kind: Some(McpPrimitiveKind::Tool),
                    tool_permission_request_id: None,
                    event_context,
                    event_sequence: self.event_sequence_generator.next(),
                })?;
            return Ok(AppAutomateToolCallOutcome::Halted { monitor });
        }
        let request = self
            .automate_workflow
            .tool_permission(&request_id)
            .cloned()
            .unwrap_or_else(|| {
                self.automate_workflow.record_tool_permission_decision(
                    session_id,
                    request_id,
                    &tool,
                    DelegatedTaskToolPermissionDecision::Confirm,
                )
            });
        let event_context = self.next_event_context();
        if request.deny_overrides {
            self.automate_workflow
                .record_decision(AutomateDecisionInput {
                    session_id: session_id.clone(),
                    worker_id: None,
                    kind: LegionWorkflowDecisionKind::ToolCallDenied,
                    summary_label: format!("MCP tool call denied: {}", request.request_id),
                    risk_label: ProposalRiskLabel::High,
                    mcp_server_id: Some(server_id.clone()),
                    mcp_primitive_kind: Some(McpPrimitiveKind::Tool),
                    tool_permission_request_id: Some(request.request_id.clone()),
                    event_context,
                    event_sequence: self.event_sequence_generator.next(),
                })?;
            return Ok(AppAutomateToolCallOutcome::Denied { request });
        }
        if !request.runtime_allowed {
            self.automate_workflow
                .record_decision(AutomateDecisionInput {
                    session_id: session_id.clone(),
                    worker_id: None,
                    kind: LegionWorkflowDecisionKind::ToolApprovalRequested,
                    summary_label: format!(
                        "MCP tool call waiting for permission: {}",
                        request.request_id
                    ),
                    risk_label: risk,
                    mcp_server_id: Some(server_id.clone()),
                    mcp_primitive_kind: Some(McpPrimitiveKind::Tool),
                    tool_permission_request_id: Some(request.request_id.clone()),
                    event_context,
                    event_sequence: self.event_sequence_generator.next(),
                })?;
            return Ok(AppAutomateToolCallOutcome::WaitingForToolPermission { request });
        }
        self.automate_workflow
            .record_decision(AutomateDecisionInput {
                session_id: session_id.clone(),
                worker_id: None,
                kind: LegionWorkflowDecisionKind::ToolCallReady,
                summary_label: format!("MCP tool call ready: {}", request.request_id),
                risk_label: risk,
                mcp_server_id: Some(server_id.clone()),
                mcp_primitive_kind: Some(McpPrimitiveKind::Tool),
                tool_permission_request_id: Some(request.request_id.clone()),
                event_context,
                event_sequence: self.event_sequence_generator.next(),
            })?;
        let monitor = self.automate_workflow.risk_monitor(session_id, None)?;
        Ok(AppAutomateToolCallOutcome::Ready { request, monitor })
    }

    fn invoke_legion_workflow_mcp_tool(
        &mut self,
        session_id: &LegionWorkflowSessionId,
        worker_id: &LegionWorkflowWorkerId,
        server_id: &McpServerId,
        tool_name: &McpToolName,
        request: &DelegatedTaskToolPermissionRequest,
    ) -> Result<AppAutomateMcpToolInvocationReceipt, AppCompositionError> {
        let runtime = self
            .automate_mcp_tool_runtimes
            .get(&server_id.0)
            .cloned()
            .ok_or_else(|| {
                AppCompositionError::LegionWorkflow(format!(
                    "MCP runtime {} is not registered",
                    server_id.0
                ))
            })?;
        let event_context = self.next_event_context();
        let event_sequence = self.event_sequence_generator.next();
        let invocation = AppAutomateMcpToolInvocation {
            session_id: session_id.clone(),
            worker_id: worker_id.clone(),
            server_id: server_id.clone(),
            tool_name: tool_name.clone(),
            permission: request.clone(),
            arguments: json!({}),
            correlation_id: event_context.correlation_id,
            causality_id: event_context.causality_id,
            event_sequence,
        };
        let receipt = runtime
            .call_tool(&invocation)
            .map_err(|error| AppCompositionError::LegionWorkflow(error.to_string()))?;
        if receipt.session_id != *session_id
            || receipt.worker_id != *worker_id
            || receipt.server_id != *server_id
            || receipt.tool_name != *tool_name
            || receipt.permission_request_id != request.request_id
        {
            return Err(AppCompositionError::LegionWorkflow(
                "MCP runtime returned mismatched invocation receipt".to_string(),
            ));
        }
        self.automate_workflow
            .record_decision(AutomateDecisionInput {
                session_id: session_id.clone(),
                worker_id: Some(worker_id.clone()),
                kind: LegionWorkflowDecisionKind::ToolCallExecuted,
                summary_label: format!("MCP tool call executed: {}", receipt.result_label),
                risk_label: ProposalRiskLabel::Medium,
                mcp_server_id: Some(server_id.clone()),
                mcp_primitive_kind: Some(McpPrimitiveKind::Tool),
                tool_permission_request_id: Some(request.request_id.clone()),
                event_context,
                event_sequence: self.event_sequence_generator.next(),
            })?;
        Ok(receipt)
    }

    /// Trigger the Automate hard kill switch for a workflow session.
    pub fn trigger_legion_workflow_kill_switch(
        &mut self,
        session_id: &LegionWorkflowSessionId,
        principal_id: PrincipalId,
        reason_label: String,
    ) -> Result<LegionWorkflowProjection, AppCompositionError> {
        self.require_automate_mode()?;
        {
            let session = self.legion_workflow_session_mut(session_id)?;
            session.lifecycle_state = LegionWorkflowState::Cancelled;
        }
        let event_context = self.next_event_context();
        self.automate_workflow.trigger_kill_switch(
            session_id,
            principal_id,
            reason_label,
            event_context.correlation_id,
            event_context.causality_id,
        )?;
        self.automate_workflow
            .record_decision(AutomateDecisionInput {
                session_id: session_id.clone(),
                worker_id: None,
                kind: LegionWorkflowDecisionKind::KillSwitchTriggered,
                summary_label: "Automate kill switch triggered".to_string(),
                risk_label: ProposalRiskLabel::High,
                mcp_server_id: None,
                mcp_primitive_kind: None,
                tool_permission_request_id: None,
                event_context,
                event_sequence: self.event_sequence_generator.next(),
            })?;
        Ok(self.legion_workflow_projection(TimestampMillis::now()))
    }

    /// Returns app-owned tracker metadata records for Legion workflows.
    pub fn legion_workflow_tracker_records(&self) -> &[LegionWorkflowTrackerRecord] {
        self.legion_workflow_tracker_ledger.records()
    }

    /// Returns one app-owned Legion workflow session by id.
    pub fn legion_workflow_session(
        &self,
        session_id: &LegionWorkflowSessionId,
    ) -> Option<&LegionWorkflowSession> {
        self.legion_workflow_sessions
            .iter()
            .find(|session| &session.session_id == session_id)
    }

    /// Executes one metadata-only Legion workflow coordination pass.
    pub fn execute_legion_workflow(
        &mut self,
        session_id: &LegionWorkflowSessionId,
    ) -> Result<AppLegionWorkflowExecution, AppCompositionError> {
        self.require_automate_mode()?;
        let session_index = self
            .legion_workflow_sessions
            .iter()
            .position(|session| &session.session_id == session_id)
            .ok_or_else(|| {
                AppCompositionError::LegionWorkflow(format!(
                    "workflow session {} not found",
                    session_id.0
                ))
            })?;
        let mut session = self.legion_workflow_sessions[session_index].clone();
        let event_context = self.next_event_context();
        self.automate_workflow.armed_kill_switch(
            &session.session_id,
            event_context.correlation_id,
            event_context.causality_id,
        )?;
        let risk_monitor = self.automate_workflow.risk_monitor(
            &session.session_id,
            self.automate_workflow
                .kill_switch_triggered(&session.session_id)
                .then_some(LegionWorkflowRiskHaltReason::KillSwitch),
        )?;
        if risk_monitor.state == LegionWorkflowRiskMonitorState::Halted {
            session.lifecycle_state = LegionWorkflowState::Blocked;
            self.automate_workflow
                .record_decision(AutomateDecisionInput {
                    session_id: session.session_id.clone(),
                    worker_id: None,
                    kind: LegionWorkflowDecisionKind::RiskMonitorHalted,
                    summary_label: "Legion workflow halted before worker scheduling".to_string(),
                    risk_label: ProposalRiskLabel::High,
                    mcp_server_id: None,
                    mcp_primitive_kind: None,
                    tool_permission_request_id: None,
                    event_context,
                    event_sequence: self.event_sequence_generator.next(),
                })?;
            let merge_readiness =
                legion_protocol::evaluate_legion_workflow_merge_readiness(&session);
            self.append_legion_workflow_tracker_record(&session, &merge_readiness, event_context)?;
            self.legion_workflow_sessions[session_index] = session.clone();
            return Ok(AppLegionWorkflowExecution {
                session_id: session.session_id.clone(),
                outputs: vec![LegionWorkflowCoordinatorOutput::MergeReadiness(
                    merge_readiness.clone(),
                )],
                merge_readiness,
                projection: self.legion_workflow_projection(TimestampMillis::now()),
                tracker_record_count: self.legion_workflow_tracker_ledger.records().len(),
                memory_candidate_proposed: false,
            });
        }
        let mut coordinator = LegionWorkflowCoordinator::new(session.clone())
            .map_err(|error| AppCompositionError::LegionWorkflow(error.to_string()))?;
        let mut outputs = Vec::new();
        for conflict in coordinator.conflicts() {
            if !session
                .conflict_summaries
                .iter()
                .any(|existing| existing.conflict_id == conflict.conflict_id)
            {
                session.conflict_summaries.push(conflict.clone());
            }
            outputs.push(LegionWorkflowCoordinatorOutput::Conflict(Box::new(
                conflict.clone(),
            )));
        }

        for worker in coordinator.next_ready_workers() {
            self.automate_workflow
                .record_decision(AutomateDecisionInput {
                    session_id: session.session_id.clone(),
                    worker_id: Some(worker.worker_id.clone()),
                    kind: LegionWorkflowDecisionKind::WorkerScheduled,
                    summary_label: format!(
                        "Legion workflow worker scheduled: {}",
                        worker.worker_id.0
                    ),
                    risk_label: if worker.risk_labels.iter().any(|risk| {
                        matches!(
                            risk,
                            CommandRiskLabel::Privileged | CommandRiskLabel::Destructive
                        )
                    }) {
                        ProposalRiskLabel::High
                    } else {
                        ProposalRiskLabel::Medium
                    },
                    mcp_server_id: None,
                    mcp_primitive_kind: None,
                    tool_permission_request_id: None,
                    event_context,
                    event_sequence: self.event_sequence_generator.next(),
                })?;
            if let Some((server_id, tool_name)) = legion_workflow_worker_mcp_tool(&worker) {
                match self.prepare_legion_workflow_mcp_tool_call(
                    &session.session_id,
                    &server_id,
                    &tool_name,
                )? {
                    AppAutomateToolCallOutcome::WaitingForToolPermission { request } => {
                        let output = coordinator
                            .mark_worker_blocked(
                                &worker.worker_id,
                                vec![format!(
                                    "legion_workflow.mcp_worker_waiting_for_tool_permission:{}",
                                    request.request_id
                                )],
                            )
                            .map_err(|error| {
                                AppCompositionError::LegionWorkflow(error.to_string())
                            })?;
                        self.set_legion_workflow_worker_state(
                            &mut session,
                            &worker.worker_id,
                            LegionWorkflowWorkerState::ProviderRouteRequired,
                        );
                        outputs.push(output);
                        continue;
                    }
                    AppAutomateToolCallOutcome::Denied { request } => {
                        let output = coordinator
                            .mark_worker_blocked(
                                &worker.worker_id,
                                vec![format!(
                                    "legion_workflow.mcp_worker_tool_permission_denied:{}",
                                    request.request_id
                                )],
                            )
                            .map_err(|error| {
                                AppCompositionError::LegionWorkflow(error.to_string())
                            })?;
                        self.set_legion_workflow_worker_state(
                            &mut session,
                            &worker.worker_id,
                            LegionWorkflowWorkerState::Blocked,
                        );
                        outputs.push(output);
                        continue;
                    }
                    AppAutomateToolCallOutcome::Halted { monitor } => {
                        let output = coordinator
                            .mark_worker_blocked(
                                &worker.worker_id,
                                vec![format!(
                                    "legion_workflow.mcp_worker_halted:{:?}",
                                    monitor.halt_reason
                                )],
                            )
                            .map_err(|error| {
                                AppCompositionError::LegionWorkflow(error.to_string())
                            })?;
                        self.set_legion_workflow_worker_state(
                            &mut session,
                            &worker.worker_id,
                            LegionWorkflowWorkerState::Blocked,
                        );
                        outputs.push(output);
                        continue;
                    }
                    AppAutomateToolCallOutcome::Ready { request, .. } => {
                        match self.invoke_legion_workflow_mcp_tool(
                            &session.session_id,
                            &worker.worker_id,
                            &server_id,
                            &tool_name,
                            &request,
                        ) {
                            Ok(_receipt) => {
                                coordinator
                                    .mark_worker_completed(&worker.worker_id)
                                    .map_err(|error| {
                                        AppCompositionError::LegionWorkflow(error.to_string())
                                    })?;
                                self.set_legion_workflow_worker_state(
                                    &mut session,
                                    &worker.worker_id,
                                    LegionWorkflowWorkerState::Completed,
                                );
                                self.satisfy_legion_workflow_dependencies(
                                    &mut session,
                                    &worker.worker_id,
                                );
                                continue;
                            }
                            Err(error) => {
                                let reason = error.to_string();
                                let event_context = self.next_event_context();
                                self.automate_workflow
                                    .record_decision(AutomateDecisionInput {
                                        session_id: session.session_id.clone(),
                                        worker_id: Some(worker.worker_id.clone()),
                                        kind: LegionWorkflowDecisionKind::ToolCallFailed,
                                        summary_label: format!("MCP tool call failed: {reason}"),
                                        risk_label: ProposalRiskLabel::High,
                                        mcp_server_id: Some(server_id.clone()),
                                        mcp_primitive_kind: Some(McpPrimitiveKind::Tool),
                                        tool_permission_request_id: Some(
                                            request.request_id.clone(),
                                        ),
                                        event_context,
                                        event_sequence: self.event_sequence_generator.next(),
                                    })?;
                                let output = coordinator
                                    .mark_worker_blocked(
                                        &worker.worker_id,
                                        vec![format!(
                                            "legion_workflow.mcp_worker_tool_call_failed:{reason}"
                                        )],
                                    )
                                    .map_err(|error| {
                                        AppCompositionError::LegionWorkflow(error.to_string())
                                    })?;
                                self.set_legion_workflow_worker_state(
                                    &mut session,
                                    &worker.worker_id,
                                    LegionWorkflowWorkerState::Blocked,
                                );
                                outputs.push(output);
                                continue;
                            }
                        }
                    }
                }
            }
            let task_packet_output = coordinator
                .task_packet_for_worker(&worker.worker_id)
                .map_err(|error| AppCompositionError::LegionWorkflow(error.to_string()))?;
            outputs.push(task_packet_output);
            match worker.model_backend {
                legion_protocol::LegionWorkflowModelBackend::ProviderBacked => {
                    let output = coordinator
                        .provider_route_for_worker(&worker.worker_id)
                        .map_err(|error| AppCompositionError::LegionWorkflow(error.to_string()))?;
                    let metadata_output = coordinator
                        .provider_route_metadata_for_worker(&worker.worker_id)
                        .map_err(|error| AppCompositionError::LegionWorkflow(error.to_string()))?;
                    self.set_legion_workflow_worker_state(
                        &mut session,
                        &worker.worker_id,
                        LegionWorkflowWorkerState::ProviderRouteRequired,
                    );
                    outputs.push(output);
                    outputs.push(metadata_output);
                }
                legion_protocol::LegionWorkflowModelBackend::Local => {
                    let Some(plan_id) = worker.linked_delegated_plan_id.clone() else {
                        let output = coordinator
                            .mark_worker_blocked(
                                &worker.worker_id,
                                vec!["legion_workflow.local_worker_missing_plan".to_string()],
                            )
                            .map_err(|error| {
                                AppCompositionError::LegionWorkflow(error.to_string())
                            })?;
                        self.set_legion_workflow_worker_state(
                            &mut session,
                            &worker.worker_id,
                            LegionWorkflowWorkerState::Blocked,
                        );
                        outputs.push(output);
                        continue;
                    };
                    let mut proposal_output = match self.execute_delegated_task(&plan_id)? {
                        AppDelegatedTaskExecutionOutcome::ProposalReady(proposal_output) => {
                            *proposal_output
                        }
                        AppDelegatedTaskExecutionOutcome::PlanMissing { plan_id } => {
                            let output = coordinator
                                .mark_worker_blocked(
                                    &worker.worker_id,
                                    vec![format!(
                                        "legion_workflow.local_worker_plan_missing:{}",
                                        plan_id.0
                                    )],
                                )
                                .map_err(|error| {
                                    AppCompositionError::LegionWorkflow(error.to_string())
                                })?;
                            self.set_legion_workflow_worker_state(
                                &mut session,
                                &worker.worker_id,
                                LegionWorkflowWorkerState::Blocked,
                            );
                            outputs.push(output);
                            continue;
                        }
                        AppDelegatedTaskExecutionOutcome::WaitingForToolPermission { request } => {
                            let output = coordinator
                                .mark_worker_blocked(
                                    &worker.worker_id,
                                    vec![format!(
                                        "legion_workflow.local_worker_waiting_for_delegate_permission:{}",
                                        request.request_id
                                    )],
                                )
                                .map_err(|error| {
                                    AppCompositionError::LegionWorkflow(error.to_string())
                                })?;
                            self.set_legion_workflow_worker_state(
                                &mut session,
                                &worker.worker_id,
                                LegionWorkflowWorkerState::Blocked,
                            );
                            outputs.push(output);
                            continue;
                        }
                        AppDelegatedTaskExecutionOutcome::Denied { request } => {
                            let output = coordinator
                                .mark_worker_blocked(
                                    &worker.worker_id,
                                    vec![format!(
                                        "legion_workflow.local_worker_delegate_permission_denied:{}",
                                        request.request_id
                                    )],
                                )
                                .map_err(|error| {
                                    AppCompositionError::LegionWorkflow(error.to_string())
                                })?;
                            self.set_legion_workflow_worker_state(
                                &mut session,
                                &worker.worker_id,
                                LegionWorkflowWorkerState::Blocked,
                            );
                            outputs.push(output);
                            continue;
                        }
                    };
                    proposal_output.proposal_id = self.proposal_coordinator.next_id();
                    proposal_output.output_id = format!(
                        "legion-output:{}:{}",
                        session.session_id.0, worker.worker_id.0
                    );
                    proposal_output.request_id = format!(
                        "legion-request:{}:{}",
                        session.session_id.0, worker.worker_id.0
                    );
                    proposal_output.provider_id = worker.display_safe_model_label.clone();
                    proposal_output.correlation_id = worker.correlation_id;
                    proposal_output.causality_id = worker.causality_id;
                    proposal_output.created_at = TimestampMillis::now();
                    let output = coordinator
                        .record_proposal_output(&worker.worker_id, proposal_output.clone())
                        .map_err(|error| AppCompositionError::LegionWorkflow(error.to_string()))?;
                    coordinator
                        .mark_worker_completed(&worker.worker_id)
                        .map_err(|error| AppCompositionError::LegionWorkflow(error.to_string()))?;
                    self.set_legion_workflow_worker_state(
                        &mut session,
                        &worker.worker_id,
                        LegionWorkflowWorkerState::Completed,
                    );
                    self.satisfy_legion_workflow_dependencies(&mut session, &worker.worker_id);
                    if !session.proposal_ids.contains(&proposal_output.proposal_id) {
                        session.proposal_ids.push(proposal_output.proposal_id);
                    }
                    outputs.push(output);
                    if let Some(result) = coordinator.worker_result_for_worker(&worker.worker_id) {
                        outputs.push(LegionWorkflowCoordinatorOutput::WorkerResultReady(
                            Box::new(result.clone()),
                        ));
                    }
                    for evidence in coordinator.evidence_records_for_worker(&worker.worker_id) {
                        outputs.push(LegionWorkflowCoordinatorOutput::EvidenceReady(Box::new(
                            evidence.clone(),
                        )));
                    }
                }
                legion_protocol::LegionWorkflowModelBackend::Unavailable => {
                    let output = coordinator
                        .mark_worker_blocked(
                            &worker.worker_id,
                            vec!["legion_workflow.worker_backend_unavailable".to_string()],
                        )
                        .map_err(|error| AppCompositionError::LegionWorkflow(error.to_string()))?;
                    self.set_legion_workflow_worker_state(
                        &mut session,
                        &worker.worker_id,
                        LegionWorkflowWorkerState::Blocked,
                    );
                    outputs.push(output);
                }
            }
        }

        self.apply_legion_workflow_dirty_workspace_gate(&mut session);
        let merge_readiness = legion_protocol::evaluate_legion_workflow_merge_readiness(&session);
        session.lifecycle_state = match merge_readiness.state {
            LegionWorkflowMergeReadinessState::Ready => LegionWorkflowState::Completed,
            LegionWorkflowMergeReadinessState::WaitingForApproval => {
                LegionWorkflowState::WaitingForApproval
            }
            LegionWorkflowMergeReadinessState::Blocked => LegionWorkflowState::Blocked,
        };
        self.append_legion_workflow_tracker_record(&session, &merge_readiness, event_context)?;
        let memory_candidate_proposed = self
            .propose_legion_workflow_memory_candidate(&session, MemoryConsentState::NotGranted)?;
        self.automate_workflow
            .record_decision(AutomateDecisionInput {
                session_id: session.session_id.clone(),
                worker_id: None,
                kind: LegionWorkflowDecisionKind::MergeReadinessEvaluated,
                summary_label: format!(
                    "Legion workflow merge readiness evaluated: {:?}",
                    merge_readiness.state
                ),
                risk_label: if merge_readiness.state == LegionWorkflowMergeReadinessState::Ready {
                    ProposalRiskLabel::Medium
                } else {
                    ProposalRiskLabel::High
                },
                mcp_server_id: None,
                mcp_primitive_kind: None,
                tool_permission_request_id: None,
                event_context,
                event_sequence: self.event_sequence_generator.next(),
            })?;
        self.legion_workflow_sessions[session_index] = session.clone();
        outputs.push(LegionWorkflowCoordinatorOutput::MergeReadiness(
            merge_readiness.clone(),
        ));
        Ok(AppLegionWorkflowExecution {
            session_id: session.session_id.clone(),
            outputs,
            merge_readiness,
            projection: self.legion_workflow_projection(TimestampMillis::now()),
            tracker_record_count: self.legion_workflow_tracker_ledger.records().len(),
            memory_candidate_proposed,
        })
    }

    /// Records app-owned verification evidence metadata for a Legion workflow gate.
    pub fn record_legion_workflow_verification(
        &mut self,
        session_id: &LegionWorkflowSessionId,
        gate_id: &LegionWorkflowVerificationGateId,
        state: LegionWorkflowVerificationGateState,
        evidence_artifact_id: Option<String>,
    ) -> Result<LegionWorkflowMergeReadiness, AppCompositionError> {
        let session = self.legion_workflow_session_mut(session_id)?;
        let gate = session
            .verification_gates
            .iter_mut()
            .find(|gate| &gate.gate_id == gate_id)
            .ok_or_else(|| {
                AppCompositionError::LegionWorkflow(format!(
                    "verification gate {} not found",
                    gate_id.0
                ))
            })?;
        gate.state = state;
        gate.evidence_artifact_id = evidence_artifact_id;
        session.lifecycle_state = LegionWorkflowState::Verifying;
        Ok(legion_protocol::evaluate_legion_workflow_merge_readiness(
            session,
        ))
    }

    /// Records reviewer sign-off metadata for a Legion workflow.
    pub fn record_legion_workflow_sign_off(
        &mut self,
        session_id: &LegionWorkflowSessionId,
        sign_off_id: &LegionWorkflowSignOffId,
        state: LegionWorkflowSignOffState,
        reviewer_principal_id: Option<PrincipalId>,
    ) -> Result<LegionWorkflowMergeReadiness, AppCompositionError> {
        let session = self.legion_workflow_session_mut(session_id)?;
        let signoff = session
            .sign_off_records
            .iter_mut()
            .find(|signoff| &signoff.sign_off_id == sign_off_id)
            .ok_or_else(|| {
                AppCompositionError::LegionWorkflow(format!("sign-off {} not found", sign_off_id.0))
            })?;
        signoff.state = if reviewer_principal_id
            .as_ref()
            .is_some_and(|principal| principal.0.trim().is_empty())
        {
            LegionWorkflowSignOffState::Rejected
        } else {
            state
        };
        signoff.reviewer_principal_id = reviewer_principal_id;
        Ok(legion_protocol::evaluate_legion_workflow_merge_readiness(
            session,
        ))
    }

    /// Records merge approval metadata without applying or merging the workflow proposal.
    pub fn record_legion_workflow_merge_approval(
        &mut self,
        session_id: &LegionWorkflowSessionId,
        approval_granted: bool,
        rollback_available: bool,
        audit_persisted_before_success: bool,
        proposal_preconditions_stale: bool,
    ) -> Result<LegionWorkflowMergeReadiness, AppCompositionError> {
        let dirty = self.has_dirty_open_buffers();
        let session = self.legion_workflow_session_mut(session_id)?;
        session.merge_approval = Some(LegionWorkflowMergeApproval {
            approval_artifact_id: Some(format!("legion-approval:{}", session.session_id.0)),
            approval_granted,
            rollback_available,
            audit_persisted_before_success,
            main_workspace_dirty_conflict: dirty,
            proposal_preconditions_stale,
            labels: vec!["legion_workflow.app_merge_approval".to_string()],
            redaction_hints: vec![RedactionHint::MetadataOnly],
            schema_version: 1,
        });
        Ok(legion_protocol::evaluate_legion_workflow_merge_readiness(
            session,
        ))
    }

    /// Resolves a Legion workflow conflict by metadata id.
    pub fn resolve_legion_workflow_conflict(
        &mut self,
        session_id: &LegionWorkflowSessionId,
        conflict_id: &LegionWorkflowConflictId,
    ) -> Result<LegionWorkflowMergeReadiness, AppCompositionError> {
        let session = self.legion_workflow_session_mut(session_id)?;
        let conflict = session
            .conflict_summaries
            .iter_mut()
            .find(|conflict| &conflict.conflict_id == conflict_id)
            .ok_or_else(|| {
                AppCompositionError::LegionWorkflow(format!("conflict {} not found", conflict_id.0))
            })?;
        conflict.state = LegionWorkflowConflictState::Resolved;
        Ok(legion_protocol::evaluate_legion_workflow_merge_readiness(
            session,
        ))
    }

    fn legion_workflow_session_mut(
        &mut self,
        session_id: &LegionWorkflowSessionId,
    ) -> Result<&mut LegionWorkflowSession, AppCompositionError> {
        self.legion_workflow_sessions
            .iter_mut()
            .find(|session| &session.session_id == session_id)
            .ok_or_else(|| {
                AppCompositionError::LegionWorkflow(format!(
                    "workflow session {} not found",
                    session_id.0
                ))
            })
    }

    fn set_legion_workflow_worker_state(
        &self,
        session: &mut LegionWorkflowSession,
        worker_id: &LegionWorkflowWorkerId,
        state: LegionWorkflowWorkerState,
    ) {
        if let Some(worker) = session
            .worker_assignments
            .iter_mut()
            .find(|worker| &worker.worker_id == worker_id)
        {
            worker.state = state;
        }
    }

    fn satisfy_legion_workflow_dependencies(
        &self,
        session: &mut LegionWorkflowSession,
        worker_id: &LegionWorkflowWorkerId,
    ) {
        for dependency in session
            .dependency_edges
            .iter_mut()
            .filter(|dependency| &dependency.predecessor_worker_id == worker_id)
        {
            dependency.state = LegionWorkflowDependencyState::Satisfied;
        }
    }

    fn has_dirty_open_buffers(&self) -> bool {
        self.active_documents
            .open_tabs
            .iter()
            .any(|buffer_id| self.editor.is_dirty(*buffer_id).unwrap_or(true))
    }

    fn apply_legion_workflow_dirty_workspace_gate(&self, session: &mut LegionWorkflowSession) {
        if !self.has_dirty_open_buffers() {
            return;
        }
        if let Some(approval) = session.merge_approval.as_mut() {
            approval.main_workspace_dirty_conflict = true;
            if !approval
                .labels
                .iter()
                .any(|label| label == "legion_workflow.dirty_workspace")
            {
                approval
                    .labels
                    .push("legion_workflow.dirty_workspace".to_string());
            }
            return;
        }
        session.merge_approval = Some(LegionWorkflowMergeApproval {
            approval_artifact_id: None,
            approval_granted: false,
            rollback_available: true,
            audit_persisted_before_success: true,
            main_workspace_dirty_conflict: true,
            proposal_preconditions_stale: false,
            labels: vec!["legion_workflow.dirty_workspace".to_string()],
            redaction_hints: vec![RedactionHint::MetadataOnly],
            schema_version: 1,
        });
    }

    fn append_legion_workflow_tracker_record(
        &mut self,
        session: &LegionWorkflowSession,
        readiness: &LegionWorkflowMergeReadiness,
        event_context: EventContext,
    ) -> Result<(), AppCompositionError> {
        let unresolved_conflict_count = session
            .conflict_summaries
            .iter()
            .filter(|conflict| conflict.state == LegionWorkflowConflictState::Unresolved)
            .count() as u32;
        let failed_verification_count = session
            .verification_gates
            .iter()
            .filter(|gate| {
                gate.state == LegionWorkflowVerificationGateState::Failed
                    || gate.state == LegionWorkflowVerificationGateState::Blocked
            })
            .count() as u32;
        let signed_off_count = session
            .sign_off_records
            .iter()
            .filter(|signoff| signoff.state == LegionWorkflowSignOffState::SignedOff)
            .count() as u32;
        self.legion_workflow_tracker_ledger
            .append(LegionWorkflowTrackerRecord {
                record_id: format!(
                    "legion-tracker:{}:{}",
                    session.session_id.0, event_context.correlation_id.0
                ),
                workflow_session_id: session.session_id.clone(),
                worker_id: None,
                linked_proposal_ids: session.proposal_ids.clone(),
                verification_gate_ids: session
                    .verification_gates
                    .iter()
                    .map(|gate| gate.gate_id.clone())
                    .collect(),
                conflict_ids: session
                    .conflict_summaries
                    .iter()
                    .map(|conflict| conflict.conflict_id.clone())
                    .collect(),
                unresolved_conflict_count,
                failed_verification_count,
                required_sign_off_count: session.sign_off_records.len() as u32,
                signed_off_count,
                merge_readiness_state: readiness.state,
                risk_labels: session
                    .worker_assignments
                    .iter()
                    .flat_map(|worker| {
                        worker
                            .risk_labels
                            .iter()
                            .map(|risk| format!("worker_risk:{risk:?}"))
                    })
                    .collect(),
                privacy_labels: vec![legion_protocol::PrivacyClassification::Metadata],
                summary_hash: metadata_fingerprint(
                    "legion-workflow-session",
                    &format!(
                        "{}:{}:{}:{}",
                        session.session_id.0,
                        session.worker_assignments.len(),
                        session.proposal_ids.len(),
                        readiness.labels.join("|")
                    ),
                ),
                correlation_id: event_context.correlation_id,
                causality_id: event_context.causality_id,
                event_sequence: self.event_sequence_generator.next(),
                labels: readiness.labels.clone(),
                redaction_hints: vec![RedactionHint::MetadataOnly],
                schema_version: session.schema_version.max(1),
            })
            .map_err(|error| AppCompositionError::LegionWorkflow(error.to_string()))
    }

    fn propose_legion_workflow_memory_candidate(
        &mut self,
        session: &LegionWorkflowSession,
        consent: MemoryConsentState,
    ) -> Result<bool, AppCompositionError> {
        let candidate = LegionWorkflowOutcomeCandidate::from_session_metadata(
            session,
            consent,
            metadata_fingerprint(
                "legion-workflow-outcome",
                &format!(
                    "{}:{}:{}",
                    session.session_id.0,
                    session.proposal_ids.len(),
                    session.conflict_summaries.len()
                ),
            ),
        )
        .map_err(|error| AppCompositionError::LegionWorkflow(error.to_string()))?;
        self.memory_service
            .propose_legion_workflow_candidate(candidate)
            .map(|_| true)
            .map_err(|error| AppCompositionError::LegionWorkflow(error.to_string()))
    }

    fn current_delegated_task_projection(
        &self,
        generated_at: TimestampMillis,
    ) -> DelegatedTaskProjection {
        let proposal_ledger = self
            .proposal_coordinator
            .proposal_ledger_projection(generated_at);
        self.delegated_task_projection(generated_at, &proposal_ledger)
    }

    fn delegated_task_projection(
        &self,
        generated_at: TimestampMillis,
        proposal_ledger_projection: &ProposalLedgerProjection,
    ) -> DelegatedTaskProjection {
        let mut projection = legion_protocol::delegated_task_projection_from_plan_contracts(
            "delegated-task:app-command-center",
            self.delegated_task_plan_contracts.clone(),
            generated_at,
            1,
        );
        self.delegate_workflow
            .apply_to_projection(&mut projection, proposal_ledger_projection);
        projection
    }

    fn command_registry_projection(
        &self,
        proposal_ledger_projection: &ProposalLedgerProjection,
        delegated_task_projection: &DelegatedTaskProjection,
        generated_at: TimestampMillis,
    ) -> legion_protocol::CommandRegistryProjection {
        let active_buffer = self.active_documents.active_buffer_id;
        let active_file_metadata = active_buffer
            .and_then(|buffer_id| self.active_documents.metadata_for_buffer(buffer_id));
        let selected_proposal = proposal_ledger_projection.selected_proposal_id;
        let delegated_plans_available = delegated_task_projection.plan_count > 0;
        legion_protocol::CommandRegistryProjection {
            projection_id: "command-registry:app-shell".to_string(),
            commands: vec![
                command_descriptor(AppCommandDescriptorInput {
                    command_id: "file.save",
                    title: "Save Active Buffer",
                    scope: "editor",
                    enabled: active_buffer.is_some(),
                    disabled_reason: active_buffer
                        .is_none()
                        .then(|| "no active buffer".to_string()),
                    shortcut: Some(":w"),
                    risk_label: legion_protocol::CommandRiskLabel::Review,
                    required_permission: Some(CapabilityId("workspace.save".to_string())),
                    target: active_buffer.map(|buffer| format!("buffer:{}", buffer.0)),
                }),
                command_descriptor(AppCommandDescriptorInput {
                    command_id: "file.save.active",
                    title: "Save Active Buffer",
                    scope: "editor",
                    enabled: active_buffer.is_some(),
                    disabled_reason: active_buffer
                        .is_none()
                        .then(|| "no active buffer".to_string()),
                    shortcut: Some("⌘S"),
                    risk_label: legion_protocol::CommandRiskLabel::Review,
                    required_permission: Some(CapabilityId("workspace.save".to_string())),
                    target: active_buffer.map(|buffer| format!("buffer:{}", buffer.0)),
                }),
                command_descriptor(AppCommandDescriptorInput {
                    command_id: "file.close.active",
                    title: "Close Active Tab",
                    scope: "editor",
                    enabled: active_buffer.is_some(),
                    disabled_reason: active_buffer
                        .is_none()
                        .then(|| "no active buffer".to_string()),
                    shortcut: Some("⌘W"),
                    risk_label: legion_protocol::CommandRiskLabel::Destructive,
                    required_permission: None,
                    target: active_buffer.map(|buffer| format!("buffer:{}", buffer.0)),
                }),
                command_descriptor(AppCommandDescriptorInput {
                    command_id: "explorer.reveal.active",
                    title: "Reveal Active File in Explorer",
                    scope: "explorer",
                    enabled: active_file_metadata.is_some(),
                    disabled_reason: active_file_metadata
                        .is_none()
                        .then(|| "no active file metadata".to_string()),
                    shortcut: Some("⇧⌘E"),
                    risk_label: legion_protocol::CommandRiskLabel::Safe,
                    required_permission: None,
                    target: active_file_metadata
                        .map(|metadata| format!("file:{}", metadata.identity.file_id.0)),
                }),
                command_descriptor(AppCommandDescriptorInput {
                    command_id: "proposal.preview",
                    title: "Preview Proposal",
                    scope: "review",
                    enabled: selected_proposal.is_some(),
                    disabled_reason: selected_proposal
                        .is_none()
                        .then(|| "no selected proposal".to_string()),
                    shortcut: None,
                    risk_label: legion_protocol::CommandRiskLabel::Safe,
                    required_permission: Some(CapabilityId("proposal.preview".to_string())),
                    target: selected_proposal.map(|proposal| format!("proposal:{}", proposal.0)),
                }),
                command_descriptor(AppCommandDescriptorInput {
                    command_id: "proposal.approve",
                    title: "Approve Proposal",
                    scope: "review",
                    enabled: selected_proposal.is_some(),
                    disabled_reason: selected_proposal
                        .is_none()
                        .then(|| "no selected proposal".to_string()),
                    shortcut: None,
                    risk_label: legion_protocol::CommandRiskLabel::Review,
                    required_permission: Some(CapabilityId("proposal.approve".to_string())),
                    target: selected_proposal.map(|proposal| format!("proposal:{}", proposal.0)),
                }),
                command_descriptor(AppCommandDescriptorInput {
                    command_id: "proposal.apply.approved",
                    title: "Apply Approved Proposal",
                    scope: "review",
                    enabled: false,
                    disabled_reason: Some(
                        "requires explicit approved proposal dispatch".to_string(),
                    ),
                    shortcut: None,
                    risk_label: legion_protocol::CommandRiskLabel::Destructive,
                    required_permission: Some(CapabilityId("proposal.apply".to_string())),
                    target: selected_proposal.map(|proposal| format!("proposal:{}", proposal.0)),
                }),
                command_descriptor(AppCommandDescriptorInput {
                    command_id: "delegated.inspect_plan",
                    title: "Inspect Delegated Plan",
                    scope: "agents",
                    enabled: delegated_plans_available,
                    disabled_reason: (!delegated_plans_available)
                        .then(|| "no delegated plan projected".to_string()),
                    shortcut: None,
                    risk_label: legion_protocol::CommandRiskLabel::Safe,
                    required_permission: Some(CapabilityId("delegated.plan.inspect".to_string())),
                    target: delegated_plans_available.then(|| "delegated-task".to_string()),
                }),
                command_descriptor(AppCommandDescriptorInput {
                    command_id: "delegated.allocate_sandbox",
                    title: "Allocate Delegated Sandbox",
                    scope: "agents",
                    enabled: false,
                    disabled_reason: Some(
                        "post-GA runtime activation requires policy and approval gates".to_string(),
                    ),
                    shortcut: None,
                    risk_label: legion_protocol::CommandRiskLabel::Privileged,
                    required_permission: Some(CapabilityId(
                        "delegated.runtime.allocate".to_string(),
                    )),
                    target: delegated_plans_available.then(|| "isolated-worktree".to_string()),
                }),
                command_descriptor(AppCommandDescriptorInput {
                    command_id: "verification.run_required",
                    title: "Run Required Verification",
                    scope: "verification",
                    enabled: false,
                    disabled_reason: Some(
                        "verification runs are projected until runtime gate is accepted"
                            .to_string(),
                    ),
                    shortcut: None,
                    risk_label: legion_protocol::CommandRiskLabel::Privileged,
                    required_permission: Some(CapabilityId("verification.run".to_string())),
                    target: Some("workspace-gates".to_string()),
                }),
            ],
            selected_command_id: None,
            omitted_command_count: 0,
            generated_at,
            redaction_hints: vec![RedactionHint::MetadataOnly],
            schema_version: 1,
        }
    }

    fn artifact_ledger_projection(
        &self,
        proposal_ledger_projection: &ProposalLedgerProjection,
        delegated_task_projection: &DelegatedTaskProjection,
        generated_at: TimestampMillis,
    ) -> legion_protocol::ArtifactLedgerProjection {
        let mut rows = delegated_task_projection
            .plan_rows
            .iter()
            .map(|plan| legion_protocol::ArtifactLedgerRow {
                artifact_id: format!("artifact:directive:{}", plan.plan_id.0),
                kind: legion_protocol::ArtifactKind::Directive,
                title: "Delegated directive".to_string(),
                state_label: format!("{:?}", plan.plan_state),
                linked_proposal_id: None,
                linked_session_id: None,
                raw_payload_retained: false,
                risk_label: plan.risk_label,
                privacy_label: plan.privacy_label,
                redaction_hints: vec![RedactionHint::MetadataOnly],
                schema_version: 1,
            })
            .collect::<Vec<_>>();
        rows.extend(proposal_ledger_projection.rows.iter().map(|proposal| {
            legion_protocol::ArtifactLedgerRow {
                artifact_id: format!("artifact:approval:{}", proposal.proposal_id.0),
                kind: legion_protocol::ArtifactKind::Approval,
                title: proposal.title.clone(),
                state_label: proposal.lifecycle.label.clone(),
                linked_proposal_id: Some(proposal.proposal_id),
                linked_session_id: None,
                raw_payload_retained: false,
                risk_label: proposal.risk_label,
                privacy_label: proposal.privacy_label,
                redaction_hints: vec![RedactionHint::MetadataOnly],
                schema_version: 1,
            }
        }));
        legion_protocol::ArtifactLedgerProjection {
            projection_id: "artifact-ledger:app-shell".to_string(),
            rows,
            omitted_row_count: 0,
            generated_at,
            redaction_hints: vec![RedactionHint::MetadataOnly],
            schema_version: 1,
        }
    }

    fn verification_run_projection(
        &self,
        delegated_task_projection: &DelegatedTaskProjection,
        generated_at: TimestampMillis,
    ) -> legion_protocol::VerificationRunProjection {
        let rows = delegated_task_projection
            .plan_rows
            .iter()
            .map(|plan| legion_protocol::VerificationRunRow {
                run_id: format!("verification:{}", plan.plan_id.0),
                label: "Required delegated-task verification".to_string(),
                state: if plan.readiness
                    == legion_protocol::DelegatedTaskPlanReadinessStatus::Refused
                    || plan.readiness == legion_protocol::DelegatedTaskPlanReadinessStatus::Blocked
                {
                    legion_protocol::VerificationRunState::Blocked
                } else {
                    legion_protocol::VerificationRunState::Planned
                },
                command_class_label: "workspace-gates".to_string(),
                command_body_redacted: true,
                exit_code: None,
                target_labels: plan.labels.clone(),
                evidence_artifact_id: None,
                started_at: None,
                completed_at: None,
                risk_label: plan.risk_label,
                privacy_label: plan.privacy_label,
                redaction_hints: vec![RedactionHint::MetadataOnly],
                schema_version: 1,
            })
            .collect::<Vec<_>>();
        legion_protocol::VerificationRunProjection {
            projection_id: "verification-runs:app-shell".to_string(),
            rows,
            omitted_row_count: 0,
            generated_at,
            redaction_hints: vec![RedactionHint::MetadataOnly],
            schema_version: 1,
        }
    }

    fn system_graph_projection(
        &self,
        proposal_ledger_projection: &ProposalLedgerProjection,
        delegated_task_projection: &DelegatedTaskProjection,
        generated_at: TimestampMillis,
    ) -> legion_protocol::SystemGraphProjection {
        let mut nodes = vec![legion_protocol::SystemGraphNode {
            node_id: "system:workspace".to_string(),
            kind_label: "workspace".to_string(),
            display_label: "Active workspace".to_string(),
            target_count: self.active_documents.workspace_id().map_or(0, |_| 1),
            risk_label: legion_protocol::ProposalRiskLabel::Low,
            privacy_label: legion_protocol::ProposalPrivacyLabel::WorkspaceMetadata,
            redaction_hints: vec![RedactionHint::MetadataOnly],
            schema_version: 1,
        }];
        if self.active_documents.active_file_id.is_some() {
            nodes.push(legion_protocol::SystemGraphNode {
                node_id: "system:active-file".to_string(),
                kind_label: "file".to_string(),
                display_label: "Active file".to_string(),
                target_count: 1,
                risk_label: legion_protocol::ProposalRiskLabel::Low,
                privacy_label: legion_protocol::ProposalPrivacyLabel::WorkspaceMetadata,
                redaction_hints: vec![RedactionHint::MetadataOnly],
                schema_version: 1,
            });
        }
        if !proposal_ledger_projection.rows.is_empty() {
            nodes.push(legion_protocol::SystemGraphNode {
                node_id: "system:proposal-ledger".to_string(),
                kind_label: "proposal-ledger".to_string(),
                display_label: "Proposal ledger".to_string(),
                target_count: proposal_ledger_projection.rows.len() as u32,
                risk_label: legion_protocol::ProposalRiskLabel::Medium,
                privacy_label: legion_protocol::ProposalPrivacyLabel::WorkspaceMetadata,
                redaction_hints: vec![RedactionHint::MetadataOnly],
                schema_version: 1,
            });
        }
        if delegated_task_projection.plan_count > 0 {
            nodes.push(legion_protocol::SystemGraphNode {
                node_id: "system:delegated-task-manager".to_string(),
                kind_label: "delegated-task-manager".to_string(),
                display_label: "Delegated task manager".to_string(),
                target_count: delegated_task_projection.plan_count,
                risk_label: legion_protocol::ProposalRiskLabel::Medium,
                privacy_label: legion_protocol::ProposalPrivacyLabel::WorkspaceMetadata,
                redaction_hints: vec![RedactionHint::MetadataOnly],
                schema_version: 1,
            });
        }
        let edges = nodes
            .iter()
            .filter(|node| node.node_id != "system:workspace")
            .map(|node| legion_protocol::SystemGraphEdge {
                from_node_id: "system:workspace".to_string(),
                to_node_id: node.node_id.clone(),
                relation_label: "contains".to_string(),
                redaction_hints: vec![RedactionHint::MetadataOnly],
                schema_version: 1,
            })
            .collect::<Vec<_>>();
        legion_protocol::SystemGraphProjection {
            projection_id: "system-graph:app-shell".to_string(),
            nodes,
            edges,
            omitted_node_count: 0,
            omitted_edge_count: 0,
            generated_at,
            redaction_hints: vec![RedactionHint::MetadataOnly],
            schema_version: 1,
        }
    }

    /// Seed an ephemeral deterministic remote fixture file for Phase 7 validation.
    pub fn seed_remote_fixture_file(
        &mut self,
        session_id: RemoteWorkspaceSessionId,
        path: CanonicalPath,
        file_id: FileId,
        content: impl Into<String>,
    ) -> Result<legion_protocol::RemoteFilesystemSnapshot, AppCompositionError> {
        self.remote
            .runtime
            .session_mut(session_id)
            .map_err(remote_error)?
            .seed_file(path, file_id, content)
            .map_err(remote_error)
    }

    /// Receive a remote transport envelope and persist metadata-only app-owned audit.
    pub fn receive_remote_transport_envelope(
        &mut self,
        envelope: RemoteTransportEnvelope,
    ) -> Result<RemoteOperationOutcome, AppCompositionError> {
        let session_id = envelope.session_id;
        let operation_id = envelope.operation_id;
        let correlation_id = envelope.correlation_id;
        let causality_id = envelope.causality_id;
        let proposal_id = match &envelope.payload {
            RemoteTransportPayload::FilesystemOperation(operation) => operation.proposal_id,
            RemoteTransportPayload::Audit(record) => record.proposal_id,
            _ => None,
        };

        let outcome = self
            .remote
            .runtime
            .handle_transport_envelope(envelope)
            .map_err(remote_error)?;
        let audit = self
            .remote
            .runtime
            .session(session_id)
            .map_err(remote_error)?
            .audit_record(
                Some(operation_id),
                proposal_id,
                self.event_sequence_generator.next(),
                correlation_id,
                causality_id,
            );
        self.persist_remote_audit(audit)?;
        Ok(outcome)
    }

    fn persist_remote_audit(&self, record: RemoteAuditRecord) -> Result<(), AppCompositionError> {
        self.storage
            .handle(StorageRepositoryRequest::SaveRemoteAuditRecord(
                record.clone(),
            ))
            .map_err(AppCompositionError::Protocol)?;
        let envelope = remote_audit_recorded_event(&record)
            .map_err(|error| AppCompositionError::Remote(error.to_string()))?;
        self.emit_event(envelope);
        Ok(())
    }

    /// Start a Phase 4 local-provider AI run and register its generated edit as a proposal.
    pub fn start_ai_run(
        &mut self,
        instruction_label: impl Into<String>,
    ) -> Result<AppAiRunOutcome, AppCompositionError> {
        self.start_ai_proposal(instruction_label)
    }

    /// Start a metadata-only assisted-AI explain run.
    pub fn start_ai_explain(
        &mut self,
        instruction_label: impl Into<String>,
    ) -> Result<AppAiRunOutcome, AppCompositionError> {
        self.run_assisted_ai_operation(
            legion_protocol::AssistedAiOperationClass::Explain,
            instruction_label,
            legion_protocol::AssistedAiProviderClass::LocalLoopback,
        )
    }

    /// Start a proposal-only assisted-AI edit run.
    pub fn start_ai_proposal(
        &mut self,
        instruction_label: impl Into<String>,
    ) -> Result<AppAiRunOutcome, AppCompositionError> {
        self.run_assisted_ai_operation(
            legion_protocol::AssistedAiOperationClass::ProposeEdit,
            instruction_label,
            legion_protocol::AssistedAiProviderClass::LocalLoopback,
        )
    }

    fn run_assisted_ai_operation(
        &mut self,
        operation_class: legion_protocol::AssistedAiOperationClass,
        instruction_label: impl Into<String>,
        provider_class: legion_protocol::AssistedAiProviderClass,
    ) -> Result<AppAiRunOutcome, AppCompositionError> {
        self.require_assist_mode()?;
        let instruction_label = instruction_label.into();
        let context = self.active_documents.require_active_save_context()?;
        let event_context = self.next_event_context();
        let generated_at = TimestampMillis::now();
        let snapshot = self.editor.current_snapshot(context.buffer_id)?.clone();
        let run_id =
            legion_protocol::AgentRunId(format!("phase4-run-{}", event_context.correlation_id.0));
        let route_id = format!("phase4-route-{}", event_context.correlation_id.0);
        let snapshot_hash = FileFingerprint {
            algorithm: "legion-text-snapshot".to_string(),
            value: snapshot.content_hash.clone(),
        };
        let instruction_bundle = instruction_prefix_bundle(
            context.workspace_id,
            generated_at,
            self.active_documents
                .workspace_root_path
                .as_ref()
                .map(|path| std::path::Path::new(path.as_str())),
            std::env::var_os("HOME")
                .as_deref()
                .map(std::path::Path::new),
        );
        let context_manifest_projection = Phase4ContextAssemblyService::assemble_context_manifest(
            &context,
            &run_id,
            &route_id,
            snapshot.snapshot_id,
            snapshot.buffer_version,
            snapshot_hash,
            snapshot.byte_len as u64,
            snapshot.line_count.min(u32::MAX as usize) as u32,
            generated_at,
            instruction_bundle.manifest_items,
        );
        let privacy_inspector_projection =
            legion_protocol::privacy_inspector_from_context_manifest_projection(
                &context_manifest_projection,
                format!("phase4:privacy:{}", run_id.0),
                generated_at,
                1,
            );
        let permission_budget_projection = phase4_permission_budget_projection(
            &context_manifest_projection,
            &run_id,
            generated_at,
        );

        let mut agent = AgentRuntime::new(run_id.clone());
        agent
            .transition(
                legion_protocol::AgentRunState::Planning,
                "agent.planning.context_ready",
                event_context.correlation_id,
                event_context.causality_id,
                self.event_sequence_generator.next(),
            )
            .map_err(|error| AppCompositionError::AiRuntime(error.to_string()))?;

        let provider_route_request = legion_protocol::AssistedAiProviderRouteRequest {
            route_id: route_id.clone(),
            provider_id: DETERMINISTIC_LOCAL_PROVIDER_ID.to_string(),
            model_label: "deterministic-local".to_string(),
            provider_class,
            operation_class,
            context_manifest: trust_reference(
                &context_manifest_projection.manifest.manifest_id,
                legion_protocol::AssistedAiTrustProjectionKind::ContextManifest,
            ),
            privacy_inspector: trust_reference(
                &privacy_inspector_projection.inspector_id,
                legion_protocol::AssistedAiTrustProjectionKind::PrivacyInspector,
            ),
            permission_budget: trust_reference(
                &permission_budget_projection.projection_id,
                legion_protocol::AssistedAiTrustProjectionKind::PermissionBudget,
            ),
            prompt_prefix: instruction_bundle.prompt_prefix,
            proposal_intent: legion_protocol::AssistedAiProposalTargetIntent {
                payload_kind: legion_protocol::ProposalPayloadKind::TextEdit,
                target_coverage: ProposalTargetCoverage {
                    coverage_kind: ProposalTargetCoverageKind::Complete,
                    targets: vec![ProposalAffectedTarget {
                        target_id: format!("file:{}", context.metadata.identity.file_id.0),
                        kind: ProposalTargetKind::OpenBuffer,
                        workspace_id: Some(context.workspace_id),
                        file_id: Some(context.metadata.identity.file_id),
                        buffer_id: Some(context.buffer_id),
                        path: Some(context.metadata.identity.canonical_path.clone()),
                        terminal_session_id: None,
                        plugin_id: None,
                        remote_authority: None,
                        collaboration_session_id: None,
                        byte_ranges: vec![legion_protocol::ByteRange::new(0, 0)],
                        redaction_hints: vec![RedactionHint::MetadataOnly],
                    }],
                    omitted_target_count: 0,
                    redaction_hints: vec![RedactionHint::MetadataOnly],
                },
                required_capability: CapabilityId("editor.write".to_string()),
                risk_label: legion_protocol::ProposalRiskLabel::Low,
                privacy_label: legion_protocol::ProposalPrivacyLabel::WorkspaceMetadata,
                labels: vec![instruction_label.clone()],
                redaction_hints: vec![RedactionHint::MetadataOnly],
                schema_version: 1,
            },
            policy_decision_id: None,
            required_capability: CapabilityId("ai.provider.invoke".to_string()),
            network_target: Some(legion_protocol::NetworkTarget {
                scheme: "http".to_string(),
                host: "localhost".to_string(),
                port: Some(11434),
            }),
            cancellation_token: legion_protocol::CancellationTokenId(uuid::Uuid::now_v7()),
            health_labels: vec!["local.deterministic".to_string()],
            cost_labels: vec!["local.free".to_string()],
            principal_id: context.principal.clone(),
            workspace_trust_state: context.trust.clone(),
            correlation_id: event_context.correlation_id,
            causality_id: event_context.causality_id,
            event_sequence: self.event_sequence_generator.next(),
            redaction_hints: vec![RedactionHint::MetadataOnly],
            schema_version: 1,
        };
        let broker = DenyByDefaultBroker::new(
            SecurityPolicy::default(),
            CapabilityNamespace("app.ai".to_string()),
        );
        let route_response = ProviderRouter::new(&self.ai_registry, &broker)
            .route_completion(provider_route_request.clone())
            .map_err(|error| AppCompositionError::AiRuntime(error.to_string()))?;
        if route_response.invocation_state
            != legion_protocol::AssistedAiProviderInvocationState::Completed
            || operation_class == legion_protocol::AssistedAiOperationClass::Explain
        {
            return self.finish_assisted_ai_metadata_only_run(
                run_id,
                route_id,
                operation_class,
                provider_class,
                provider_route_request,
                route_response,
                context_manifest_projection,
                privacy_inspector_projection,
                permission_budget_projection,
                generated_at,
                event_context,
                &mut agent,
            );
        }

        agent
            .transition(
                legion_protocol::AgentRunState::Proposing,
                "agent.proposing.provider_completed",
                event_context.correlation_id,
                event_context.causality_id,
                self.event_sequence_generator.next(),
            )
            .map_err(|error| AppCompositionError::AiRuntime(error.to_string()))?;

        let proposal_id = self.proposal_coordinator.next_id();
        let preconditions = ProposalVersionPreconditions {
            file_version: Some(context.metadata.file_content_version),
            buffer_version: Some(snapshot.buffer_version),
            snapshot_id: Some(snapshot.snapshot_id),
            generation: Some(context.metadata.workspace_generation),
            file_content_version: Some(context.metadata.file_content_version),
            workspace_generation: Some(context.metadata.workspace_generation),
            expected_fingerprint: Some(context.metadata.fingerprint.clone()),
            expected_file_length: context.metadata.file_length,
            expected_modified_at: context.metadata.modified_at,
        };
        let output = legion_protocol::AssistedAiEditProposalOutput {
            output_id: format!("phase4-output-{}", event_context.correlation_id.0),
            request_id: format!("phase4-request-{}", event_context.correlation_id.0),
            provider_id: DETERMINISTIC_LOCAL_PROVIDER_ID.to_string(),
            proposal_id,
            principal: context.principal.clone(),
            capability: CapabilityId("editor.write".to_string()),
            correlation_id: event_context.correlation_id,
            causality_id: event_context.causality_id,
            payload: ProposalPayload::TextEdit(legion_protocol::TextEditProposal {
                file_id: context.metadata.identity.file_id,
                edits: legion_protocol::EditBatch {
                    edits: vec![legion_protocol::TextEdit {
                        range: legion_protocol::TextRange::byte(0, 0),
                        replacement: "/* phase4 local AI proposal */\n".to_string(),
                    }],
                },
            }),
            preconditions,
            preview: PreviewSummary {
                summary: "Phase 4 local AI edit proposal".to_string(),
                details: vec![
                    "Generated by deterministic local provider".to_string(),
                    "Proposal is registered only; app/editor/workspace own apply".to_string(),
                ],
            },
            expires_at: None,
            created_at: generated_at,
            context_manifest: trust_reference(
                &context_manifest_projection.manifest.manifest_id,
                legion_protocol::AssistedAiTrustProjectionKind::ContextManifest,
            ),
            approval_checklist: trust_reference(
                &format!("phase4:approval:{}", run_id.0),
                legion_protocol::AssistedAiTrustProjectionKind::ProposalApprovalChecklist,
            ),
            redaction_hints: vec![RedactionHint::MetadataOnly],
            schema_version: 1,
        };
        let proposal = output
            .to_workspace_proposal()
            .map_err(|error| AppCompositionError::AiRuntime(error.to_string()))?;
        let proposal_created = self.register_proposal_lifecycle(&proposal)?;
        let ledger_projection = self
            .proposal_coordinator
            .proposal_ledger_projection(generated_at);
        let checkpoint_rollback_projection =
            legion_protocol::checkpoint_rollback_projection_from_proposal(
                format!("phase4:checkpoint:{}", run_id.0),
                &proposal,
                ProposalLifecycleState::Created,
                Some(&ledger_projection),
                legion_protocol::CheckpointRollbackAuditStatus::Available,
                Some(event_context.causality_id),
                generated_at,
                1,
            );
        let approval_checklist_projection =
            legion_protocol::approval_checklist_from_trust_projections(
                format!("phase4:approval:{}", run_id.0),
                &proposal,
                ProposalLifecycleState::Created,
                Some(&ledger_projection),
                Some(&context_manifest_projection),
                Some(&privacy_inspector_projection),
                Some(&permission_budget_projection),
                Some(&checkpoint_rollback_projection),
                true,
                Some(event_context.causality_id),
                generated_at,
                1,
            );
        let provider_capability = phase4_provider_capability(provider_class, None);
        let request_contract = assisted_ai_request_contract_from_metadata(
            output.request_id.clone(),
            &provider_capability,
            operation_class,
            &context_manifest_projection,
            &privacy_inspector_projection,
            &permission_budget_projection,
            &approval_checklist_projection,
            Some(&checkpoint_rollback_projection),
            event_context,
            provider_route_request.proposal_intent.clone(),
            route_response.route_decision.clone(),
            generated_at,
        );
        let assisted_ai_projection = legion_protocol::assisted_ai_projection_from_metadata(
            format!("phase4:assisted:{}", run_id.0),
            vec![provider_capability],
            vec![request_contract],
            vec![output.clone()],
            Some(&ledger_projection),
            Some(&context_manifest_projection),
            Some(&privacy_inspector_projection),
            Some(&permission_budget_projection),
            Some(&approval_checklist_projection),
            Some(&checkpoint_rollback_projection),
            generated_at,
            1,
        );

        agent
            .transition(
                legion_protocol::AgentRunState::WaitingForApproval,
                "agent.waiting_for_approval.proposal_registered",
                event_context.correlation_id,
                event_context.causality_id,
                self.event_sequence_generator.next(),
            )
            .map_err(|error| AppCompositionError::AiRuntime(error.to_string()))?;
        let replay_manifest = legion_protocol::AgentReplayManifest {
            run_id: run_id.clone(),
            transitions: agent.transitions().to_vec(),
            context_manifests: vec![trust_reference(
                &context_manifest_projection.manifest.manifest_id,
                legion_protocol::AssistedAiTrustProjectionKind::ContextManifest,
            )],
            provider_route_ids: vec![route_id.clone()],
            proposal_ids: vec![proposal_id],
            correlation_id: event_context.correlation_id,
            causality_id: event_context.causality_id,
            event_sequence: self.event_sequence_generator.next(),
            redaction_hints: vec![RedactionHint::MetadataOnly],
            schema_version: 1,
        };
        self.persist_phase4_runtime_records(
            &run_id,
            &route_id,
            route_response.invocation_state,
            "phase4.provider.route.completed",
            event_context,
            &replay_manifest,
        )?;
        self.tracker_ledger
            .append(TrackerRunLedgerRecord {
                run_id: run_id.clone(),
                state: legion_protocol::AgentRunState::WaitingForApproval,
                proposal_id: Some(proposal_id),
                transitions: replay_manifest.transitions.clone(),
                correlation_id: event_context.correlation_id,
                causality_id: event_context.causality_id,
                event_sequence: self.event_sequence_generator.next(),
                labels: vec!["tracker.phase4.run.waiting_for_approval".to_string()],
            })
            .map_err(|error| AppCompositionError::AiRuntime(error.to_string()))?;
        let _ = self
            .memory_service
            .propose_candidate(MemoryCandidateRecord {
                candidate_id: format!("phase4-memory-candidate-{}", run_id.0),
                run_id: Some(run_id.clone()),
                consent: MemoryConsentState::NotGranted,
                labels: vec!["memory.candidate.review_required".to_string()],
                correlation_id: event_context.correlation_id,
                causality_id: event_context.causality_id,
                event_sequence: self.event_sequence_generator.next(),
            })
            .map_err(|error| AppCompositionError::AiRuntime(error.to_string()))?;

        self.phase4_projection_state.context_manifest_projection =
            Some(context_manifest_projection.clone());
        self.phase4_projection_state.privacy_inspector_projection =
            Some(privacy_inspector_projection.clone());
        self.phase4_projection_state.permission_budget_projection =
            Some(permission_budget_projection.clone());
        self.phase4_projection_state.approval_checklist_projection =
            Some(approval_checklist_projection);
        self.phase4_projection_state.checkpoint_rollback_projection =
            Some(checkpoint_rollback_projection);
        self.phase4_projection_state.assisted_ai_projection = Some(assisted_ai_projection.clone());
        self.phase4_projection_state
            .replay_manifests
            .insert(run_id.clone(), replay_manifest.clone());
        self.phase4_projection_state.inspection_snapshots.insert(
            run_id.clone(),
            AppAiInspectionSnapshot {
                run_id: run_id.clone(),
                context_manifest_projection: context_manifest_projection.clone(),
                privacy_inspector_projection: privacy_inspector_projection.clone(),
                permission_budget_projection: permission_budget_projection.clone(),
                assisted_ai_projection: assisted_ai_projection.clone(),
            },
        );

        Ok(AppAiRunOutcome {
            run_id,
            proposal_id: Some(proposal_id),
            proposal_created: Some(proposal_created),
            route_response,
            context_manifest_projection,
            privacy_inspector_projection,
            permission_budget_projection,
            refusal: None,
            replay_manifest,
        })
    }

    #[allow(clippy::too_many_arguments)]
    fn finish_assisted_ai_metadata_only_run(
        &mut self,
        run_id: legion_protocol::AgentRunId,
        route_id: String,
        operation_class: legion_protocol::AssistedAiOperationClass,
        provider_class: legion_protocol::AssistedAiProviderClass,
        provider_route_request: legion_protocol::AssistedAiProviderRouteRequest,
        route_response: legion_protocol::AssistedAiProviderRouteResponse,
        context_manifest_projection: legion_protocol::ContextManifestProjection,
        privacy_inspector_projection: legion_protocol::PrivacyInspectorProjection,
        permission_budget_projection: legion_protocol::PermissionBudgetProjection,
        generated_at: TimestampMillis,
        event_context: EventContext,
        agent: &mut AgentRuntime,
    ) -> Result<AppAiRunOutcome, AppCompositionError> {
        let refused = route_response.invocation_state
            != legion_protocol::AssistedAiProviderInvocationState::Completed;
        let agent_state = if refused {
            legion_protocol::AgentRunState::Blocked
        } else {
            legion_protocol::AgentRunState::Proposing
        };
        let outcome_label = if refused {
            "phase5.provider.route.refused"
        } else {
            "phase5.explain.metadata_ready"
        };
        agent
            .transition(
                agent_state,
                outcome_label,
                event_context.correlation_id,
                event_context.causality_id,
                self.event_sequence_generator.next(),
            )
            .map_err(|error| AppCompositionError::AiRuntime(error.to_string()))?;

        let provider_capability =
            phase4_provider_capability(provider_class, route_response.refusal.clone());
        let approval_checklist_projection = empty_approval_checklist_projection();
        let checkpoint_rollback_projection = empty_checkpoint_rollback_projection();
        let request_contract = assisted_ai_request_contract_from_metadata(
            format!("phase5-request-{}", event_context.correlation_id.0),
            &provider_capability,
            operation_class,
            &context_manifest_projection,
            &privacy_inspector_projection,
            &permission_budget_projection,
            &approval_checklist_projection,
            Some(&checkpoint_rollback_projection),
            event_context,
            provider_route_request.proposal_intent.clone(),
            route_response.route_decision.clone(),
            generated_at,
        );
        let assisted_ai_projection = legion_protocol::assisted_ai_projection_from_metadata(
            format!("phase5:assisted:{}", run_id.0),
            vec![provider_capability],
            vec![request_contract],
            Vec::new(),
            None,
            Some(&context_manifest_projection),
            Some(&privacy_inspector_projection),
            Some(&permission_budget_projection),
            Some(&approval_checklist_projection),
            Some(&checkpoint_rollback_projection),
            generated_at,
            1,
        );
        let replay_manifest = legion_protocol::AgentReplayManifest {
            run_id: run_id.clone(),
            transitions: agent.transitions().to_vec(),
            context_manifests: vec![trust_reference(
                &context_manifest_projection.manifest.manifest_id,
                legion_protocol::AssistedAiTrustProjectionKind::ContextManifest,
            )],
            provider_route_ids: vec![route_id.clone()],
            proposal_ids: Vec::new(),
            correlation_id: event_context.correlation_id,
            causality_id: event_context.causality_id,
            event_sequence: self.event_sequence_generator.next(),
            redaction_hints: vec![RedactionHint::MetadataOnly],
            schema_version: 1,
        };
        self.persist_phase4_runtime_records(
            &run_id,
            &route_id,
            route_response.invocation_state,
            outcome_label,
            event_context,
            &replay_manifest,
        )?;
        self.tracker_ledger
            .append(TrackerRunLedgerRecord {
                run_id: run_id.clone(),
                state: agent_state,
                proposal_id: None,
                transitions: replay_manifest.transitions.clone(),
                correlation_id: event_context.correlation_id,
                causality_id: event_context.causality_id,
                event_sequence: self.event_sequence_generator.next(),
                labels: vec![outcome_label.to_string()],
            })
            .map_err(|error| AppCompositionError::AiRuntime(error.to_string()))?;

        self.phase4_projection_state.context_manifest_projection =
            Some(context_manifest_projection.clone());
        self.phase4_projection_state.privacy_inspector_projection =
            Some(privacy_inspector_projection.clone());
        self.phase4_projection_state.permission_budget_projection =
            Some(permission_budget_projection.clone());
        self.phase4_projection_state.approval_checklist_projection =
            Some(approval_checklist_projection);
        self.phase4_projection_state.checkpoint_rollback_projection =
            Some(checkpoint_rollback_projection);
        self.phase4_projection_state.assisted_ai_projection = Some(assisted_ai_projection.clone());
        self.phase4_projection_state
            .replay_manifests
            .insert(run_id.clone(), replay_manifest.clone());
        self.phase4_projection_state.inspection_snapshots.insert(
            run_id.clone(),
            AppAiInspectionSnapshot {
                run_id: run_id.clone(),
                context_manifest_projection: context_manifest_projection.clone(),
                privacy_inspector_projection: privacy_inspector_projection.clone(),
                permission_budget_projection: permission_budget_projection.clone(),
                assisted_ai_projection: assisted_ai_projection.clone(),
            },
        );

        Ok(AppAiRunOutcome {
            run_id,
            proposal_id: None,
            proposal_created: None,
            refusal: route_response.refusal.clone(),
            route_response,
            context_manifest_projection,
            privacy_inspector_projection,
            permission_budget_projection,
            replay_manifest,
        })
    }

    /// Cancel a Phase 4 run by writing metadata-only cancellation audit.
    pub fn cancel_ai_run(
        &mut self,
        run_id: legion_protocol::AgentRunId,
    ) -> Result<(), AppCompositionError> {
        if !self
            .phase4_projection_state
            .replay_manifests
            .contains_key(&run_id)
        {
            return Err(AppCompositionError::AiRunMissing { run_id: run_id.0 });
        }
        let event_context = self.next_event_context();
        let record = legion_protocol::Phase4RuntimeAuditRecord {
            audit_id: format!("phase4-cancel:{}", run_id.0),
            run_id: Some(run_id),
            step_id: None,
            provider_route_id: None,
            invocation_state: legion_protocol::AssistedAiProviderInvocationState::Cancelled,
            outcome_label: "phase4.agent.cancelled".to_string(),
            labels: vec!["agent.cancelled.metadata_only".to_string()],
            correlation_id: event_context.correlation_id,
            causality_id: event_context.causality_id,
            event_sequence: self.event_sequence_generator.next(),
            redaction_hints: vec![RedactionHint::MetadataOnly],
            schema_version: 1,
        };
        self.storage
            .handle(StorageRepositoryRequest::SavePhase4RuntimeAuditRecord(
                record.clone(),
            ))
            .map_err(AppCompositionError::Protocol)?;
        let envelope = phase4_runtime_audit_recorded_event(&record)
            .map_err(|error| AppCompositionError::AiRuntime(error.to_string()))?;
        self.emit_event(envelope);
        Ok(())
    }

    /// Replay a Phase 4 run from metadata-only storage.
    pub fn replay_ai_run(
        &self,
        run_id: legion_protocol::AgentRunId,
    ) -> Result<legion_protocol::AgentReplayManifest, AppCompositionError> {
        match self
            .storage
            .handle(StorageRepositoryRequest::ReadAgentReplayManifest(
                run_id.clone(),
            ))
            .map_err(AppCompositionError::Protocol)?
        {
            StorageRepositoryResponse::AgentReplayManifest(manifest) => manifest
                .as_ref()
                .clone()
                .ok_or(AppCompositionError::AiRunMissing { run_id: run_id.0 }),
            other => Err(AppCompositionError::Protocol(ProtocolError {
                code: "phase4_replay_unexpected_response".to_string(),
                message: format!("expected agent replay manifest, got {other:?}"),
            })),
        }
    }

    /// Inspect Phase 4 projections for a specific run's metadata.
    pub fn inspect_ai_run(
        &self,
        run_id: legion_protocol::AgentRunId,
    ) -> Result<AppAiInspectionSnapshot, AppCompositionError> {
        self.phase4_projection_state
            .inspection_snapshots
            .get(&run_id)
            .cloned()
            .ok_or(AppCompositionError::AiRunMissing { run_id: run_id.0 })
    }

    fn persist_phase4_runtime_records(
        &self,
        run_id: &legion_protocol::AgentRunId,
        route_id: &str,
        invocation_state: legion_protocol::AssistedAiProviderInvocationState,
        outcome_label: &str,
        event_context: EventContext,
        replay_manifest: &legion_protocol::AgentReplayManifest,
    ) -> Result<(), AppCompositionError> {
        let record = legion_protocol::Phase4RuntimeAuditRecord {
            audit_id: format!("phase4-runtime:{}:{}", run_id.0, route_id),
            run_id: Some(run_id.clone()),
            step_id: None,
            provider_route_id: Some(route_id.to_string()),
            invocation_state,
            outcome_label: outcome_label.to_string(),
            labels: vec!["phase4.runtime.metadata_only".to_string()],
            correlation_id: event_context.correlation_id,
            causality_id: event_context.causality_id,
            event_sequence: replay_manifest.event_sequence,
            redaction_hints: vec![RedactionHint::MetadataOnly],
            schema_version: 1,
        };
        self.storage
            .handle(StorageRepositoryRequest::SavePhase4RuntimeAuditRecord(
                record.clone(),
            ))
            .map_err(AppCompositionError::Protocol)?;
        self.storage
            .handle(StorageRepositoryRequest::SaveAgentReplayManifest(
                replay_manifest.clone(),
            ))
            .map_err(AppCompositionError::Protocol)?;
        let runtime_event = phase4_runtime_audit_recorded_event(&record)
            .map_err(|error| AppCompositionError::AiRuntime(error.to_string()))?;
        self.emit_event(runtime_event);
        let replay_event = agent_replay_manifest_recorded_event(replay_manifest)
            .map_err(|error| AppCompositionError::AiRuntime(error.to_string()))?;
        self.emit_event(replay_event);
        Ok(())
    }

    /// Save currently active buffer through editor save request and workspace write authority.
    pub fn save_active_buffer(&mut self) -> Result<AppSaveOutcome, AppCompositionError> {
        let buffer_id = self.active_documents.require_active_buffer()?;
        self.save_buffer(buffer_id)
    }

    fn save_buffer(&mut self, buffer_id: BufferId) -> Result<AppSaveOutcome, AppCompositionError> {
        let context = self.active_documents.save_context_for_buffer(buffer_id)?;
        let event_context = self.next_event_context();
        match SaveWorkflowService::save_active_buffer(
            &mut self.editor,
            &self.workspace,
            &mut self.proposal_coordinator,
            &self.storage,
            context,
            event_context,
        ) {
            Ok(output) => {
                self.editor
                    .acknowledge_save_outcome(output.save.request_id, SaveAcknowledgement::Saved);
                self.active_documents
                    .bind_saved_buffer(output.save.buffer_id, output.applied);
                self.active_documents
                    .clear_dirty_prompt_for(output.save.buffer_id);
                Ok(AppSaveOutcome::Saved(output.save))
            }
            Err(failure) => {
                if let Some(committed) = failure.committed {
                    // The on-disk write already committed before the post-commit
                    // audit failed. Reconcile editor state with disk (mark the
                    // buffer saved) so we never leave a dirty buffer over content
                    // that is already persisted, then surface the audit failure.
                    self.editor.acknowledge_save_outcome(
                        committed.save.request_id,
                        SaveAcknowledgement::Saved,
                    );
                    self.active_documents
                        .bind_saved_buffer(committed.save.buffer_id, committed.applied);
                    self.active_documents
                        .clear_dirty_prompt_for(committed.save.buffer_id);
                } else if failure.request_id != uuid::Uuid::nil() {
                    self.editor.acknowledge_save_outcome(
                        failure.request_id,
                        acknowledgement_for_response(&failure.response),
                    );
                }
                Ok(AppSaveOutcome::Rejected(Box::new(failure.response)))
            }
        }
    }

    /// Save all open tabs sequentially through the existing proposal-mediated save workflow.
    pub fn save_all(&mut self) -> Result<AppSaveAllOutcome, AppCompositionError> {
        let buffers = self.active_documents.open_tabs.clone();
        let mut results = Vec::new();
        let mut saved_count = 0;
        let mut rejected_count = 0;
        for buffer_id in buffers {
            let Some(metadata) = self
                .active_documents
                .metadata_for_buffer(buffer_id)
                .cloned()
            else {
                rejected_count += 1;
                results.push(AppSaveAllItemOutcome {
                    buffer_id,
                    file_id: None,
                    file_path: None,
                    status: AppSaveAllItemStatus::MetadataMissing,
                    outcome: None,
                    rejection_metadata: Some(save_all_missing_metadata(buffer_id)),
                    final_dirty: self.editor.is_dirty(buffer_id).unwrap_or(true),
                });
                continue;
            };
            if !self.active_documents.open_tabs.contains(&buffer_id) {
                rejected_count += 1;
                results.push(AppSaveAllItemOutcome {
                    buffer_id,
                    file_id: Some(metadata.identity.file_id),
                    file_path: Some(metadata.identity.canonical_path),
                    status: AppSaveAllItemStatus::MetadataMissing,
                    outcome: None,
                    rejection_metadata: Some(save_all_missing_metadata(buffer_id)),
                    final_dirty: self.editor.is_dirty(buffer_id).unwrap_or(true),
                });
                continue;
            }
            let file_id = Some(metadata.identity.file_id);
            let file_path = Some(metadata.identity.canonical_path);
            let outcome = self.save_buffer(buffer_id)?;
            let status = match &outcome {
                AppSaveOutcome::Saved(_) => AppSaveAllItemStatus::Saved,
                AppSaveOutcome::Rejected(_) => AppSaveAllItemStatus::Rejected,
            };
            let rejection_metadata = match &outcome {
                AppSaveOutcome::Saved(_) => None,
                AppSaveOutcome::Rejected(response) => Some(save_all_rejection_metadata(response)),
            };
            match &outcome {
                AppSaveOutcome::Saved(_) => saved_count += 1,
                AppSaveOutcome::Rejected(_) => rejected_count += 1,
            }
            results.push(AppSaveAllItemOutcome {
                buffer_id,
                file_id,
                file_path,
                status,
                outcome: Some(outcome),
                rejection_metadata,
                final_dirty: self.editor.is_dirty(buffer_id)?,
            });
        }

        let status = match (saved_count, rejected_count, results.is_empty()) {
            (_, _, true) => AppSaveAllStatus::Noop,
            (_, 0, false) => AppSaveAllStatus::Saved,
            (0, _, false) => AppSaveAllStatus::Rejected,
            _ => AppSaveAllStatus::Partial,
        };

        Ok(AppSaveAllOutcome {
            status,
            results,
            saved_count,
            rejected_count,
        })
    }

    /// Cancel the active dirty-close prompt without changing buffer text or tab state.
    pub fn cancel_dirty_close(&mut self, buffer_id: BufferId) -> Result<(), AppCompositionError> {
        self.active_documents.cancel_dirty_close(buffer_id)
    }

    /// Switch the active tab to an already-open buffer.
    pub fn switch_tab(&mut self, buffer_id: BufferId) -> Result<(), AppCompositionError> {
        self.active_documents.switch_to_buffer(buffer_id)
    }

    /// Close a tab when clean; dirty tabs produce a prompt projection and remain open.
    pub fn close_tab(
        &mut self,
        buffer_id: BufferId,
    ) -> Result<AppCloseTabOutcome, AppCompositionError> {
        self.active_documents.require_open_buffer(buffer_id)?;
        if self.editor.is_dirty(buffer_id)? {
            self.active_documents.prompt_dirty_close(buffer_id)?;
            let prompt = self
                .active_documents
                .close_dirty_prompt
                .as_ref()
                .ok_or(AppCompositionError::BufferNotOpen(buffer_id))?;
            return Ok(AppCloseTabOutcome::CloseDirtyPrompt {
                buffer_id,
                file_id: prompt.file_id,
                path: prompt.path.clone(),
            });
        }

        self.editor.close_buffer(buffer_id)?;
        self.active_documents.remove_open_tab(buffer_id);
        self.assist_inline_prediction_state
            .clear_for_buffer(buffer_id);
        self.active_documents.activate_first_available_tab();
        Ok(AppCloseTabOutcome::Closed { buffer_id })
    }

    /// Set the active cursor for an open buffer through editor authority.
    pub fn set_buffer_cursor(
        &mut self,
        buffer_id: BufferId,
        cursor: TextCoordinate,
    ) -> Result<(), AppCompositionError> {
        self.active_documents.require_open_buffer(buffer_id)?;
        self.editor.set_cursors(
            buffer_id,
            vec![Cursor {
                position: CommandDispatcher::editor_position(cursor),
            }],
        )?;
        Ok(())
    }

    /// Set the active selection for an open buffer through editor authority.
    pub fn set_buffer_selection(
        &mut self,
        buffer_id: BufferId,
        range: legion_protocol::ProtocolTextRange,
    ) -> Result<(), AppCompositionError> {
        self.active_documents.require_open_buffer(buffer_id)?;
        self.editor.set_selections(
            buffer_id,
            vec![Selection {
                range: CommandDispatcher::editor_range(range),
            }],
        )?;
        Ok(())
    }

    fn collapse_selection_to_cursor(
        &mut self,
        buffer_id: BufferId,
        cursor: TextCoordinate,
    ) -> Result<(), AppCompositionError> {
        self.set_buffer_cursor(buffer_id, cursor)?;
        self.editor.set_selections(buffer_id, Vec::new())?;
        Ok(())
    }

    fn select_all_buffer(&mut self, buffer_id: BufferId) -> Result<(), AppCompositionError> {
        self.active_documents.ensure_active_buffer(buffer_id)?;
        let end = text_end_coordinate(self.editor.text(buffer_id)?);
        self.set_buffer_selection(
            buffer_id,
            ProtocolTextRange {
                start: text_coordinate_with_offsets(0, 0, 0, 0),
                end,
            },
        )
    }

    fn clipboard_metadata_for_selection(
        &self,
        buffer_id: BufferId,
        cut: bool,
    ) -> Result<(AppClipboardUpdate, Option<ProtocolTextRange>), AppCompositionError> {
        self.active_documents.ensure_active_buffer(buffer_id)?;
        let Some(selection) = self.primary_selection(buffer_id)? else {
            return Ok((
                AppClipboardUpdate {
                    buffer_id,
                    byte_len: 0,
                    line_count: 0,
                    cut,
                },
                None,
            ));
        };

        let text = self.editor.text(buffer_id)?;
        let Some((start, end)) = byte_bounds_for_protocol_range(text, selection) else {
            return Err(EditorError::InvalidEdit(
                "clipboard selection requires valid byte-coordinate bounds",
            )
            .into());
        };
        if start == end {
            return Ok((
                AppClipboardUpdate {
                    buffer_id,
                    byte_len: 0,
                    line_count: 0,
                    cut,
                },
                None,
            ));
        }
        let selected = &text[start..end];
        Ok((
            AppClipboardUpdate {
                buffer_id,
                byte_len: selected.len(),
                line_count: selected_line_count(selected),
                cut,
            },
            Some(selection),
        ))
    }

    fn primary_selection(
        &self,
        buffer_id: BufferId,
    ) -> Result<Option<ProtocolTextRange>, AppCompositionError> {
        self.active_documents.ensure_active_buffer(buffer_id)?;
        Ok(self
            .editor
            .viewport_projection(legion_protocol::EditorViewportRequest {
                buffer_id,
                scroll: self.active_documents.viewport_scroll_for(buffer_id),
                dimensions: legion_protocol::ViewportDimensions {
                    width_px: 800,
                    height_px: 384,
                },
            })?
            .selections
            .into_iter()
            .next())
    }

    fn set_cursor_after_edit(
        &mut self,
        buffer_id: BufferId,
        edit: &TextEdit,
    ) -> Result<(), AppCompositionError> {
        self.set_buffer_cursor(
            buffer_id,
            text_coordinate_after_replacement(edit.range.start, &edit.new_text),
        )
    }

    /// Store viewport scroll for an open buffer.
    pub fn set_viewport_scroll(
        &mut self,
        buffer_id: BufferId,
        scroll: ViewportScroll,
    ) -> Result<(), AppCompositionError> {
        self.active_documents.set_viewport_scroll(buffer_id, scroll)
    }

    /// Run bounded lexical search through app-owned editor/workspace authority.
    pub fn run_search(
        &mut self,
        query_id: String,
        scope: SearchScopeProjection,
        query: String,
        limit: usize,
    ) -> Result<SearchProjection, AppCompositionError> {
        let result_limit = normalize_search_limit(limit);
        let query_label = query.trim().to_string();
        if query_label.is_empty() {
            self.search_projection = build_search_projection(
                Some(query_id),
                scope,
                query_label,
                result_limit,
                SearchStatusProjection {
                    kind: SearchStatusKindProjection::ValidationError,
                    message: "Search query is empty".to_string(),
                },
                SearchBuildResult::default(),
            );
            return Ok(self.search_projection.clone());
        }

        let result = match scope {
            SearchScopeProjection::ActiveFile => {
                self.run_active_file_search(&query_id, &query_label, result_limit)?
            }
            SearchScopeProjection::Workspace => {
                self.run_workspace_search(&query_id, &query_label, result_limit)?
            }
        };

        let status = search_status_for_result(scope, &result);
        self.search_projection = build_search_projection(
            Some(query_id),
            scope,
            query_label,
            result_limit,
            status,
            result,
        );
        Ok(self.search_projection.clone())
    }

    /// Run deterministic structural search and optionally create a rewrite proposal preview.
    pub fn run_structural_search(
        &mut self,
        query_id: String,
        scope: SearchScopeProjection,
        pattern: String,
        rewrite: Option<String>,
        limit: usize,
    ) -> Result<StructuralSearchProjection, AppCompositionError> {
        let result_limit = normalize_search_limit(limit);
        let pattern_label = pattern.trim().to_string();
        let rewrite_label = rewrite
            .as_ref()
            .map(|value| value.trim().to_string())
            .filter(|value| !value.is_empty());
        if pattern_label.is_empty() {
            let result = StructuralBuildResult::default();
            self.structural_search_projection =
                build_structural_search_projection(StructuralSearchProjectionInput {
                    query_id: Some(query_id),
                    scope,
                    pattern_label,
                    rewrite_label,
                    result_limit,
                    status: SearchStatusProjection {
                        kind: SearchStatusKindProjection::ValidationError,
                        message: "Structural search pattern is empty".to_string(),
                    },
                    result: &result,
                    proposal_id: None,
                });
            return Ok(self.structural_search_projection.clone());
        }

        let query = StructuralSearchQuery {
            pattern: pattern_label.clone(),
            rewrite: rewrite_label.clone(),
            result_limit,
        };
        let mut result = match scope {
            SearchScopeProjection::ActiveFile => {
                self.run_active_file_structural_search(&query_id, &query, result_limit)?
            }
            SearchScopeProjection::Workspace => {
                self.run_workspace_structural_search(&query_id, &query, result_limit)?
            }
        };

        let proposal_id = if rewrite_label.is_some() && !result.matches.is_empty() {
            self.create_structural_rewrite_proposal(&pattern_label, &mut result)?
        } else {
            None
        };
        let status = structural_search_status_for_result(&result);
        self.structural_search_projection =
            build_structural_search_projection(StructuralSearchProjectionInput {
                query_id: Some(query_id),
                scope,
                pattern_label,
                rewrite_label,
                result_limit,
                status,
                result: &result,
                proposal_id,
            });
        Ok(self.structural_search_projection.clone())
    }

    /// Cancel the projected search by query id.
    pub fn cancel_search(&mut self, query_id: String) -> SearchProjection {
        if self.search_projection.query_id.as_deref() == Some(query_id.as_str()) {
            self.search_projection.status = SearchStatusProjection {
                kind: SearchStatusKindProjection::Cancelled,
                message: "Search cancelled".to_string(),
            };
            self.search_projection.generated_at = TimestampMillis::now();
        }
        self.search_projection.clone()
    }

    /// Refresh app-owned git projection data for the active workspace.
    pub fn refresh_git_projection(&mut self) -> GitProjection {
        let Some(root_path) = self.active_documents.workspace_root_path.as_deref() else {
            self.git_hunk_cache.clear();
            self.git_projection = GitProjection {
                diagnostics: vec!["git.workspace_not_open".to_string()],
                generated_at: TimestampMillis::now(),
                worktrees: Vec::new(),
                ..GitProjection::idle()
            };
            return self.git_projection.clone();
        };
        let active_file = self
            .active_documents
            .active_file_path
            .as_deref()
            .map(PathBuf::from);
        match collect_git_snapshot(
            Path::new(root_path),
            active_file.as_deref(),
            GitSnapshotOptions::default(),
        ) {
            Ok(snapshot) => {
                self.git_hunk_cache = snapshot
                    .hunks
                    .iter()
                    .map(|hunk| (hunk.hunk_id.clone(), hunk.clone()))
                    .collect();
                self.git_projection = git_projection_from_project(snapshot);
            }
            Err(error) => {
                self.git_hunk_cache.clear();
                self.git_projection = GitProjection {
                    root_label: Some(root_path.to_string()),
                    diagnostics: vec![format!("git.refresh_failed: {error}")],
                    generated_at: TimestampMillis::now(),
                    worktrees: Vec::new(),
                    ..GitProjection::idle()
                };
            }
        }
        self.git_projection.clone()
    }

    fn stage_or_unstage_git_hunk(
        &mut self,
        hunk_id: &str,
        expected_stage: GitHunkStage,
    ) -> Result<GitProjection, AppCompositionError> {
        let Some(root_path) = self.active_documents.workspace_root_path.as_deref() else {
            return Err(AppCompositionError::WorkspaceNotOpen);
        };
        let hunk = self.git_hunk_cache.get(hunk_id).cloned().ok_or_else(|| {
            git_protocol_error(
                "git_hunk_missing",
                format!("git hunk `{hunk_id}` is not present in the current projection"),
            )
        })?;
        if hunk.stage != expected_stage {
            return Err(git_protocol_error(
                "git_hunk_stage_mismatch",
                format!(
                    "git hunk `{hunk_id}` stage is {:?}, expected {:?}",
                    hunk.stage, expected_stage
                ),
            ));
        }
        match expected_stage {
            GitHunkStage::Unstaged => stage_git_hunk(Path::new(root_path), &hunk)
                .map_err(git_inspection_protocol_error)?,
            GitHunkStage::Staged => unstage_git_hunk(Path::new(root_path), &hunk)
                .map_err(git_inspection_protocol_error)?,
        }
        Ok(self.refresh_git_projection())
    }

